    @property
    def agents(self) -> List[AgentInfo]:
        """Lazy load agents list."""
        if self._agents is None:
            self._agents = self._load_agents()
        return self._agents

    @property
    def opencode_models(self) -> List[Dict]:
        """Lazy load OpenCode models."""
        if self._opencode_models is None:
            self._opencode_models = self._get_opencode_models()
        return self._opencode_models

    def _load_agents(self) -> List[AgentInfo]:
        """Load agents list (called lazily)."""
        try:
            try:
                asyncio.get_running_loop()
                return self._fallback_agents()
            except RuntimeError:
                pass
            from superqode.agents.discovery import read_agents

            agents_data = asyncio.run(read_agents())
            return [
                AgentInfo(
                    identity=short_name,
                    name=agent.get("name", short_name),
                    short_name=short_name,
                    description=agent.get("description", ""),
                    author=agent.get("author", "SuperQode"),
                    status=AgentStatus.AVAILABLE,
                )
                for short_name, agent in agents_data.items()
            ]
        except Exception as e:
            # Fallback to basic agents if discovery fails
            return self._fallback_agents()

    def _fallback_agents(self) -> List[AgentInfo]:
        """Basic agents used when async discovery cannot run synchronously."""
        return [
            AgentInfo(
                identity="opencode",
                name="OpenCode",
                short_name="opencode",
                description="AI coding assistant",
                author="OpenCode",
                status=AgentStatus.AVAILABLE,
            ),
            AgentInfo(
                identity="gemini",
                name="Gemini",
                short_name="gemini",
                description="Google AI assistant",
                author="Google",
                status=AgentStatus.AVAILABLE,
            ),
            AgentInfo(
                identity="claude",
                name="Claude",
                short_name="claude",
                description="Anthropic AI assistant",
                author="Anthropic",
                status=AgentStatus.AVAILABLE,
            ),
        ]

    def _get_opencode_models(self) -> List[Dict]:
        """Get OpenCode models from the live CLI catalog."""
        try:
            from superqode.providers.opencode_models import get_opencode_models_sync

            models = get_opencode_models_sync()

            # Convert to our format. Show all discovered OpenCode models, not
            # only free ones, because the catalog and free-tier markers change.
            return [
                {
                    "id": m["id"],
                    "name": m.get("name", m["id"].split("/")[-1]),
                    "context": m.get("context", 128000),
                    "free": bool(m.get("is_free", False)),
                    "recommended": bool(m.get("recommended", False)),
                    "desc": m.get("description") or m.get("source", "OpenCode"),
                    "catalog_unavailable": bool(m.get("catalog_unavailable", False)),
                }
                for m in models
            ]
        except Exception:
            return []

        return []

