    def action_refresh_opencode_models(self):
        """Refresh OpenCode models from CLI."""
        if not getattr(self, "_awaiting_model_selection", False):
            return

        if self.current_agent != "opencode":
            return

        # Clear cache and refresh models
        try:
            from superqode.providers.opencode_models import clear_cache

            clear_cache()
            # Re-fetch models
            self._opencode_models = None
            models = self.opencode_models

            # Show updated list
            log = self.query_one("#log", ConversationLog)
            agent = getattr(self, "_opencode_agent_data", None)
            if not agent:
                agent_list = getattr(self, "_acp_agent_list", [])
                for agent_id, agent_data in agent_list:
                    if agent_id == "opencode":
                        agent = agent_data
                        break
            if not agent:
                agent = {"name": "OpenCode", "short_name": "opencode"}

            # Reset highlight index to 0
            self._opencode_highlighted_model_index = 0

            # Show message
            t = Text()
            t.append("\n  🔄 ", style=THEME["success"])
            t.append("Refreshing models from OpenCode...", style=THEME["text"])
            log.write(t)

            # Then show the model list
            self.set_timer(0.5, lambda: self._show_opencode_models_selection(agent, log))

        except Exception as e:
            log = self.query_one("#log", ConversationLog)
            t = Text()
            t.append(f"\n  ⚠️  Error refreshing: {str(e)}", style=THEME["error"])
            log.write(t)

    def action_refresh_byok_models(self):
        """Refresh BYOK providers/models from models.dev API."""
        if not (
            getattr(self, "_awaiting_byok_provider", False)
            or getattr(self, "_awaiting_byok_model", False)
        ):
            return

        try:
            from superqode.providers.models_dev import get_models_dev

            client = get_models_dev()

            t = Text()
            t.append("\n  🔄 ", style=THEME["success"])
            t.append("Refreshing models from models.dev...", style=THEME["text"])

            log = self.query_one("#log", ConversationLog)
            log.write(t)

            def on_refresh_complete(success: bool):
                log = self.query_one("#log", ConversationLog)
                if success:
                    t = Text()
                    t.append("  ✓ ", style=THEME["success"])
                    t.append("Models refreshed successfully!", style=THEME["text"])
                    log.write(t)
                else:
                    t = Text()
                    t.append("  ⚠️ ", style=THEME["error"])
                    t.append("Failed to refresh. Using cached models.", style=THEME["muted"])
                    log.write(t)

                # Re-show the provider picker
                self.set_timer(0.3, lambda: self._show_connect_picker(log, clear_log=True))

            # Trigger async refresh - it will call on_refresh_complete when done
            import asyncio

            async def do_refresh():
                success = await client.refresh(force=True)
                if success:
                    self._apply_live_models(client)
                self.call_later(lambda: on_refresh_complete(success))

            asyncio.create_task(do_refresh())

        except Exception as e:
            log = self.query_one("#log", ConversationLog)
            t = Text()
            t.append(f"\n  ⚠️  Error refreshing: {str(e)}", style=THEME["error"])
            log.write(t)

    def _scroll_to_highlighted_item(
        self, log: ConversationLog, highlighted_idx: int, total_items: int
    ):
        """Scroll the log to keep the highlighted item visible.

        Prefer the actual rendered selection row so wrapped descriptions and a
        short terminal viewport cannot hide the item. The geometry fallback is
        retained for pickers that do not render a ``SELECTED`` marker.
        """
        if self._scroll_to_rendered_selected_row(log):
            return

        try:
            log.auto_scroll = False
            visible_height = max(
                6,
                int(
                    getattr(getattr(log, "scrollable_content_region", None), "height", 0)
                    or getattr(getattr(log, "size", None), "height", 18)
                    or 18
                ),
            )
            lines_per_item = 3
            header_lines = 5
            highlighted_y = header_lines + highlighted_idx * lines_per_item
            target_y = max(0, highlighted_y - max(1, visible_height // 2))
            log.scroll_to(y=target_y, animate=False)
        except Exception:
            pass  # If scrolling fails, just continue

    @staticmethod
    def _scroll_to_rendered_selected_row(log: ConversationLog) -> bool:
        """Bring the RichLog row containing the current picker marker into view."""
        try:
            selected_y = next(
                index
                for index, line in enumerate(log.lines)
                if "SELECTED" in line.text
            )
        except (AttributeError, StopIteration):
            return False

        try:
            # A picker owns the viewport while it is active. Re-enabling
            # RichLog's follow mode here would immediately jump back to the
            # footer after this row-level scroll.
            log.auto_scroll = False

            from textual.geometry import Region

            log.scroll_to_region(
                Region(0, selected_y, 1, 1),
                animate=False,
                x_axis=False,
                y_axis=True,
            )
            return True
        except Exception:
            return False

    def _scroll_to_highlighted_local_model(self, log: ConversationLog, highlighted_idx: int):
        """Scroll the local-model picker so the highlighted multi-line row is visible."""
        try:
            log.auto_scroll = False
            visible_height = max(6, int(getattr(getattr(log, "size", None), "height", 18) or 18))
            header_lines = 5
            # Local model rows render as: title, id, details, optional capabilities,
            # blank line. Use a conservative row height so row 6+ scrolls into view.
            lines_per_item = 5
            highlighted_y = header_lines + highlighted_idx * lines_per_item
            target_y = max(0, highlighted_y - max(2, visible_height // 2))
            log.scroll_to(y=target_y, animate=False)
        except Exception:
            pass

    def _scroll_down_to_item(self, log: ConversationLog, target_offset: int, lines_per_item: int):
        """Helper to scroll down to show the highlighted item."""
        try:
            # Scroll down by the calculated amount
            scroll_steps = max(0, target_offset // 3)  # Approximate scroll steps
            for _ in range(min(scroll_steps, 30)):  # Limit to prevent excessive scrolling
                log.scroll_down(animate=False)
        except Exception:
            pass

    def _adjust_scroll_for_item(self, log: ConversationLog, highlighted_idx: int, total_items: int):
        """Adjust scroll position to show highlighted item (legacy, kept for compatibility)."""
        try:
            # Use the new simpler approach
            self._scroll_to_highlighted_item(log, highlighted_idx, total_items)
        except Exception:
            pass

