    def _sync_attachment_prefill(self) -> None:
        if not getattr(self, "_attached_refs", None):
            self._set_prompt_prefill("")
            return
        prefill = " ".join(dict.fromkeys(self._attached_refs)) + " "
        self._set_prompt_prefill(prefill)

    def _render_attachments(self) -> Text:
        t = Text()
        t.append("\n  📎 ", style=f"bold {THEME['cyan']}")
        t.append("Prompt Attachments\n\n", style=f"bold {THEME['text']}")
        refs = getattr(self, "_attached_refs", [])
        if not refs:
            t.append("  No staged references.\n", style=THEME["muted"])
            t.append("  Add one with ", style=THEME["muted"])
            t.append(":attach <file|url>\n", style=THEME["cyan"])
            return t
        for index, ref in enumerate(refs, 1):
            t.append(f"  [{index}] ", style=THEME["dim"])
            ref_style = (
                THEME["purple"]
                if ref.startswith("mcp://")
                else THEME["cyan"]
                if ref.startswith("@")
                else THEME["text"]
            )
            t.append(ref, style=ref_style)
            t.append("\n")
        t.append("\n  Commands: ", style=THEME["muted"])
        t.append(":attach remove <n>", style=THEME["cyan"])
        t.append(", ", style=THEME["muted"])
        t.append(":attach clear\n", style=THEME["cyan"])
        return t

    def _attach_cmd(self, args: str, log: ConversationLog):
        """Insert file or URL references into the next prompt."""
        value = args.strip()
        if not value:
            self._show_command_output(log, self._render_attachments())
            return
        try:
            raw_refs = shlex.split(value)
        except ValueError as exc:
            log.add_error(f"Could not parse :attach arguments: {exc}")
            return
        action = raw_refs[0].lower() if raw_refs else ""
        if action in {"list", "ls", "show"}:
            self._show_command_output(log, self._render_attachments())
            return
        if action in {"clear", "reset"}:
            self._attached_refs = []
            self._set_prompt_prefill("")
            log.add_info("Cleared staged prompt references.")
            return
        if action in {"remove", "rm", "delete"}:
            if len(raw_refs) < 2:
                log.add_error("Usage: :attach remove <index|reference>")
                return
            target = raw_refs[1]
            refs = list(getattr(self, "_attached_refs", []))
            removed = None
            if target.isdigit():
                index = int(target) - 1
                if 0 <= index < len(refs):
                    removed = refs.pop(index)
            elif target in refs:
                refs.remove(target)
                removed = target
            if removed is None:
                log.add_error(f"Attachment not found: {target}")
                return
            self._attached_refs = refs
            self._sync_attachment_prefill()
            log.add_info(f"Removed staged reference: {removed}")
            return
        refs: list[str] = []
        for raw in raw_refs:
            if raw.startswith(("http://", "https://")):
                refs.append(raw)
                continue
            path = Path(raw).expanduser()
            if not path.is_absolute():
                path = Path.cwd() / path
            if not path.exists():
                log.add_error(f"Cannot attach missing path: {raw}")
                continue
            try:
                refs.append("@" + str(path.relative_to(Path.cwd())))
            except ValueError:
                refs.append("@" + str(path))
        if not refs:
            return
        self._attached_refs.extend(refs)
        self._attached_refs = list(dict.fromkeys(self._attached_refs))
        self._sync_attachment_prefill()
        log.add_info(f"Attached {len(refs)} reference(s) to the next prompt.")

    _IMAGE_EXTENSIONS = {".png", ".jpg", ".jpeg", ".gif", ".webp", ".bmp", ".tiff"}

    def _is_image_path(self, value: str) -> bool:
        """True if value looks like a path to a readable image file."""
        try:
            path = Path(value.strip().strip("'\"")).expanduser()
            return path.suffix.lower() in self._IMAGE_EXTENSIONS and path.is_file()
        except Exception:
            return False

    def _grab_clipboard_image(self) -> Optional[Path]:
        """Best-effort capture of an image on the system clipboard to a temp PNG.

        Tries macOS ``pngpaste`` first, then an AppleScript fallback, then
        Pillow's ImageGrab (cross-platform). Returns the saved path or None.
        """
        import shutil
        import subprocess
        import sys
        import tempfile

        target_dir = Path.cwd() / ".superqode" / "pasted"
        try:
            target_dir.mkdir(parents=True, exist_ok=True)
        except Exception:
            target_dir = Path(tempfile.gettempdir())
        out = target_dir / f"clipboard-{int(time.time())}.png"

        if shutil.which("pngpaste"):
            try:
                result = subprocess.run(["pngpaste", str(out)], capture_output=True, timeout=10)
                if result.returncode == 0 and out.exists() and out.stat().st_size > 0:
                    return out
            except Exception:
                pass

        if sys.platform == "darwin":
            script = (
                "set theData to the clipboard as «class PNGf»\n"
                f'set theFile to open for access POSIX file "{out}" with write permission\n'
                "write theData to theFile\nclose access theFile"
            )
            try:
                result = subprocess.run(
                    ["osascript", "-e", script], capture_output=True, timeout=10
                )
                if result.returncode == 0 and out.exists() and out.stat().st_size > 0:
                    return out
            except Exception:
                pass

        try:
            from PIL import ImageGrab  # type: ignore

            image = ImageGrab.grabclipboard()
            if image is not None and hasattr(image, "save"):
                image.save(out, "PNG")
                if out.exists() and out.stat().st_size > 0:
                    return out
        except Exception:
            pass
        return None

    def _stage_image_attachment(
        self, path: Path, log: ConversationLog, *, source: str = ""
    ) -> bool:
        """Stage an image file for the next prompt and inform the user."""
        try:
            ref = "@" + str(path.relative_to(Path.cwd()))
        except ValueError:
            ref = "@" + str(path)
        if not hasattr(self, "_attached_refs"):
            self._attached_refs = []
        self._attached_refs.append(ref)
        self._attached_refs = list(dict.fromkeys(self._attached_refs))
        self._sync_attachment_prefill()
        label = f" ({source})" if source else ""
        log.add_success(f"🖼  Attached image{label}: {path.name}")
        model = getattr(self, "current_model", "") or ""
        if model and not self._model_supports_vision(model):
            log.add_info(
                "Note: the active model may not support images. Connect a vision model to use it."
            )
        return True

    def _model_supports_vision(self, model: str) -> bool:
        """Best-effort check whether the active model accepts images."""
        try:
            from superqode.providers.models import get_model_info

            info = get_model_info(getattr(self, "current_provider", "") or "", model)
            if info is not None:
                return bool(getattr(info, "supports_vision", False))
        except Exception:
            pass
        # Unknown: don't discourage; assume capable.
        return True

    def _handle_paste_image(self, args: str, log: ConversationLog):
        """`:paste` — attach an image from a path or the system clipboard."""
        value = (args or "").strip().strip("'\"")
        if value:
            path = Path(value).expanduser()
            if not path.is_absolute():
                path = Path.cwd() / path
            if self._is_image_path(str(path)):
                self._stage_image_attachment(path, log, source="path")
            else:
                log.add_error(f"Not a readable image: {value}")
            return
        image_path = self._grab_clipboard_image()
        if image_path is not None:
            self._stage_image_attachment(image_path, log, source="clipboard")
        else:
            log.add_info(
                "No image found on the clipboard. Copy an image, then run :paste — "
                "or use :paste <path-to-image>."
            )

    def on_paste(self, event) -> None:
        """Auto-attach when an image file path is pasted into the terminal."""
        text = (getattr(event, "text", "") or "").strip().strip("'\"")
        if text and "\n" not in text and self._is_image_path(text):
            try:
                log = self.query_one("#log", ConversationLog)
            except Exception:
                return
            path = Path(text).expanduser()
            if not path.is_absolute():
                path = Path.cwd() / path
            self._stage_image_attachment(path, log, source="pasted path")
            try:
                event.stop()
                event.prevent_default()
            except Exception:
                pass

    def _prompt_file_cmd(self, args: str, log: ConversationLog):
        """Load a prompt file into the input buffer."""
        value = args.strip()
        if not value:
            log.add_info("Usage: :prompt <file>")
            return
        try:
            parts = shlex.split(value)
        except ValueError as exc:
            log.add_error(f"Could not parse :prompt arguments: {exc}")
            return
        if not parts:
            log.add_info("Usage: :prompt <file>")
            return
        path = Path(parts[0]).expanduser()
        if not path.is_absolute():
            path = Path.cwd() / path
        if not path.exists() or not path.is_file():
            log.add_error(f"Prompt file not found: {path}")
            return
        try:
            content = path.read_text(encoding="utf-8")
        except Exception as exc:
            log.add_error(f"Could not read prompt file: {exc}")
            return
        self._set_prompt_prefill(content)
        log.add_info(f"Loaded prompt file into input: {path}")

    @staticmethod
    def _mcp_server_config_from_target(server_id: str, target: str):
        """Build an MCPServerConfig from a URL or stdio command string."""
        from superqode.mcp.config import MCPHttpConfig, MCPServerConfig, MCPStdioConfig

        target = target.strip()
        if target.startswith(("http://", "https://")):
            return MCPServerConfig(
                id=server_id,
                name=server_id,
                enabled=True,
                auto_connect=True,
                config=MCPHttpConfig(url=target),
            )
        argv = shlex.split(target)
        if not argv:
            raise ValueError("MCP target cannot be empty")
        command = argv[0]
        args = argv[1:]
        if command.startswith("@"):
            args = [command, *args]
            command = "npx"
        return MCPServerConfig(
            id=server_id,
            name=server_id,
            enabled=True,
            auto_connect=True,
            config=MCPStdioConfig(command=command, args=args),
        )

    @staticmethod
    def _mcp_id_from_target(target: str) -> str:
        """Generate a stable-ish MCP server id for direct connect targets."""
        target = target.strip()
        if target.startswith(("http://", "https://")):
            parsed = urlparse(target)
            base = parsed.netloc or parsed.path
        else:
            try:
                parts = shlex.split(target)
            except ValueError:
                parts = target.split()
            base = parts[0] if parts else "mcp"
            if base.startswith("@"):
                base = base.split("/")[-1]
        safe = "".join(ch if ch.isalnum() else "-" for ch in base.lower()).strip("-")
        return safe or "mcp-server"

    async def _add_mcp_server_config(
        self,
        manager,
        server_id: str,
        target: str,
    ) -> tuple[bool, str]:
        """Persist and register an MCP server config."""
        from superqode.mcp.config import load_mcp_config, save_mcp_config

        config = self._mcp_server_config_from_target(server_id, target)
        servers = load_mcp_config()
        if server_id in servers:
            return False, f"MCP server already exists: {server_id}"
        servers[server_id] = config
        save_mcp_config(servers)
        manager.add_server(config)
        return True, f"Saved MCP server {server_id}."

    @staticmethod
    def _resolve_mcp_resource_ref(manager, target: str):
        """Resolve a user-facing MCP resource reference to a resource object."""
        target = target.strip()
        resources = list(manager.list_all_resources())
        if not target:
            return None
        if target.isdigit():
            index = int(target) - 1
            return resources[index] if 0 <= index < len(resources) else None
        if target.startswith("mcp://"):
            target = target[len("mcp://") :]
        server_hint = ""
        resource_hint = target
        if "/" in target:
            server_hint, resource_hint = target.split("/", 1)

        matches = []
        lowered = resource_hint.lower()
        for resource in resources:
            if server_hint and resource.server_id.lower() != server_hint.lower():
                continue
            candidates = [
                resource.uri,
                resource.name,
                f"{resource.server_id}/{resource.uri}",
                f"{resource.server_id}/{resource.name}",
            ]
            if any(candidate and candidate.lower() == lowered for candidate in candidates):
                matches.append(resource)
                continue
            if any(candidate and candidate.lower().startswith(lowered) for candidate in candidates):
                matches.append(resource)
        return matches[0] if len(matches) == 1 else None

    async def _mcp_attach_resource(self, manager, target: str, log: ConversationLog) -> None:
        """Stage an MCP resource reference for the next prompt."""
        resource = self._resolve_mcp_resource_ref(manager, target)
        if resource is None:
            log.add_error(f"MCP resource not found or ambiguous: {target}")
            log.add_info("Use :mcp resources, then :mcp attach <index|server/uri>.")
            return
        ref = self._mcp_resource_ref(resource.server_id, resource.uri)
        refs = list(getattr(self, "_attached_refs", []))
        if ref not in refs:
            refs.append(ref)
        self._attached_refs = refs
        self._sync_attachment_prefill()
        detail = resource.name or resource.uri
        if resource.mime_type:
            detail = f"{detail} ({resource.mime_type})"
        log.add_info(f"Attached MCP resource: {detail}")

    async def _mcp_cmd(self, args: str, log: ConversationLog):
        """Handle MCP status and inventory commands."""
        try:
            from superqode.mcp.integration import get_mcp_manager
        except ImportError as exc:
            log.add_error(f"MCP support is not installed: {exc}")
            return

        parts = args.split(maxsplit=1)
        subcommand = parts[0].lower() if parts else "status"
        subargs = parts[1].strip() if len(parts) > 1 else ""
        if subcommand == "list":
            subcommand = "status"

        manager = await get_mcp_manager()

        if subcommand in ("", "status"):
            configs = manager.get_server_configs()
            summary = manager.get_status_summary()
            t = Text()
            t.append("\n  🔗 ", style=f"bold {THEME['cyan']}")
            t.append("MCP Servers\n\n", style=f"bold {THEME['cyan']}")
            t.append("  Configured: ", style=THEME["muted"])
            t.append(f"{summary['total_servers']}  ", style=f"bold {THEME['text']}")
            t.append("Connected: ", style=THEME["muted"])
            t.append(f"{summary['connected']}  ", style=f"bold {THEME['success']}")
            t.append("Tools: ", style=THEME["muted"])
            t.append(f"{summary['total_tools']}  ", style=f"bold {THEME['text']}")
            t.append("Resources: ", style=THEME["muted"])
            t.append(f"{summary['total_resources']}  ", style=f"bold {THEME['text']}")
            t.append("Prompts: ", style=THEME["muted"])
            t.append(f"{summary['total_prompts']}\n\n", style=f"bold {THEME['text']}")

            if not configs:
                t.append("  No MCP servers configured.\n", style=THEME["muted"])
                t.append(
                    "  Add servers in .superqode/mcp.json or your MCP config file.\n",
                    style=THEME["dim"],
                )
            else:
                for server_id, config in configs.items():
                    state = manager.get_connection_state(server_id).value
                    server_summary = summary["servers"].get(server_id, {})
                    status_style = (
                        THEME["success"]
                        if state == "connected"
                        else THEME["warning"]
                        if state == "error"
                        else THEME["muted"]
                    )
                    t.append(f"  {server_id:<18}", style=f"bold {THEME['cyan']}")
                    t.append(f"{state:<13}", style=status_style)
                    t.append(f"{config.name or server_id:<22}", style=THEME["text"])
                    t.append(
                        f"{server_summary.get('tools', 0)} tools  {server_summary.get('resources', 0)} resources  {server_summary.get('prompts', 0)} prompts",
                        style=THEME["muted"],
                    )
                    error = server_summary.get("error")
                    if error:
                        t.append(f"  {error}", style=THEME["warning"])
                    t.append("\n")

            t.append("\n  Commands: ", style=THEME["muted"])
            t.append(":mcp connect [server]", style=THEME["cyan"])
            t.append(", ", style=THEME["muted"])
            t.append(":mcp disconnect [server]", style=THEME["cyan"])
            t.append(", ", style=THEME["muted"])
            t.append(":mcp tools", style=THEME["cyan"])
            t.append(", ", style=THEME["muted"])
            t.append(":mcp resources", style=THEME["cyan"])
            t.append(", ", style=THEME["muted"])
            t.append(":mcp attach <resource>", style=THEME["cyan"])
            t.append("\n", style=THEME["muted"])
            self._show_command_output(log, t)
            return

        if subcommand == "add":
            try:
                tokens = shlex.split(subargs)
            except ValueError as exc:
                log.add_error(f"Could not parse MCP add command: {exc}")
                return
            if len(tokens) < 2:
                log.add_info("Usage: :mcp add <name> <url|stdio command>")
                return
            if not self._ensure_project_trusted_for(log, "add an MCP server"):
                return
            server_id = tokens[0]
            target = " ".join(shlex.quote(token) for token in tokens[1:])
            ok, message = await self._add_mcp_server_config(manager, server_id, target)
            if ok:
                log.add_info(message)
                log.add_info(f"Connect it with :mcp connect {server_id}")
            else:
                log.add_error(message)
            return

        if subcommand == "connect":
            if subargs:
                configs = manager.get_server_configs()
                server_id = subargs
                if subargs not in configs:
                    if not self._ensure_project_trusted_for(log, "add an MCP server"):
                        return
                    server_id = self._mcp_id_from_target(subargs)
                    ok, message = await self._add_mcp_server_config(manager, server_id, subargs)
                    if not ok:
                        log.add_error(message)
                        return
                    log.add_info(message)
                ok = await manager.connect(server_id)
                log.add_info(
                    f"MCP server {server_id}: {'connected' if ok else 'failed to connect'}"
                )
            else:
                results = await manager.connect_all()
                if not results:
                    log.add_info("No enabled MCP servers configured.")
                else:
                    connected = sum(1 for ok in results.values() if ok)
                    log.add_info(f"Connected {connected}/{len(results)} MCP servers.")
            return

        if subcommand in {"reconnect", "restart"}:
            if subargs:
                ok = await manager.restart_server(subargs)
                log.add_info(
                    f"MCP server {subargs}: {'reconnected' if ok else 'failed to reconnect'}"
                )
            else:
                configs = manager.get_server_configs()
                if not configs:
                    log.add_info("No MCP servers configured.")
                    return
                results = {}
                for server_id in configs:
                    results[server_id] = await manager.restart_server(server_id)
                connected = sum(1 for ok in results.values() if ok)
                log.add_info(f"Reconnected {connected}/{len(results)} MCP servers.")
            return

        if subcommand == "disconnect":
            if subargs:
                await manager.disconnect(subargs)
                log.add_info(f"MCP server {subargs}: disconnected")
            else:
                await manager.disconnect_all()
                log.add_info("Disconnected all MCP servers.")
            return

        if subcommand in {"doctor", "diagnostics", "diag"}:
            self._show_mcp_doctor(manager, subargs, log)
            return

        if subcommand == "attach":
            if not subargs:
                log.add_info("Usage: :mcp attach <index|server/uri|mcp://server/uri>")
                log.add_info("Use :mcp resources to list attachable resources.")
                return
            await self._mcp_attach_resource(manager, subargs, log)
            return

        if subcommand == "tools":
            tools = manager.list_all_tools()
            t = Text()
            t.append("\n  🧰 ", style=f"bold {THEME['cyan']}")
            t.append("MCP Tools\n\n", style=f"bold {THEME['cyan']}")
            if not tools:
                t.append(
                    "  No MCP tools are available from connected servers.\n", style=THEME["muted"]
                )
                t.append("  Run ", style=THEME["muted"])
                t.append(":mcp connect", style=THEME["cyan"])
                t.append(" first if servers are configured.\n", style=THEME["muted"])
            for tool in tools:
                t.append(f"  {tool.server_id:<16}", style=f"bold {THEME['purple']}")
                t.append(f"{tool.name}", style=THEME["text"])
                if tool.description:
                    t.append(f" - {tool.description[:120]}", style=THEME["muted"])
                t.append("\n")
            self._show_command_output(log, t)
            return

        if subcommand == "resources":
            resources = manager.list_all_resources()
            t = Text()
            t.append("\n  📚 ", style=f"bold {THEME['cyan']}")
            t.append("MCP Resources\n\n", style=f"bold {THEME['cyan']}")
            if not resources:
                t.append(
                    "  No MCP resources are available from connected servers.\n",
                    style=THEME["muted"],
                )
            for index, resource in enumerate(resources, 1):
                t.append(f"  [{index}] ", style=THEME["dim"])
                t.append(f"{resource.server_id:<16}", style=f"bold {THEME['purple']}")
                t.append(f"{resource.name}", style=THEME["text"])
                t.append(f"  {resource.uri}", style=THEME["muted"])
                if resource.mime_type:
                    t.append(f"  {resource.mime_type}", style=THEME["dim"])
                t.append("\n")
            if resources:
                t.append("\n  Attach: ", style=THEME["muted"])
                t.append(":mcp attach <index|server/uri>", style=THEME["cyan"])
                t.append("\n", style=THEME["muted"])
            self._show_command_output(log, t)
            return

        if subcommand == "prompts":
            prompts = manager.list_all_prompts()
            t = Text()
            t.append("\n  💬 ", style=f"bold {THEME['cyan']}")
            t.append("MCP Prompts\n\n", style=f"bold {THEME['cyan']}")
            if not prompts:
                t.append(
                    "  No MCP prompts are available from connected servers.\n", style=THEME["muted"]
                )
            for prompt in prompts:
                t.append(f"  {prompt.server_id:<16}", style=f"bold {THEME['purple']}")
                t.append(prompt.name, style=THEME["text"])
                if prompt.description:
                    t.append(f" - {prompt.description[:120]}", style=THEME["muted"])
                t.append("\n")
            self._show_command_output(log, t)
            return

        log.add_info(
            "Usage: :mcp status|add|connect|reconnect|disconnect|doctor|tools|resources|attach|prompts"
        )

    def _show_mcp_doctor(self, manager, server_filter: str, log: ConversationLog) -> None:
        """Render MCP server configuration and runtime diagnostics."""
        configs = manager.get_server_configs()
        if server_filter:
            configs = {server_filter: configs[server_filter]} if server_filter in configs else {}
        t = Text()
        t.append("\n  🔗 ", style=f"bold {THEME['cyan']}")
        t.append("MCP Doctor\n\n", style=f"bold {THEME['text']}")
        if not configs:
            t.append("  No matching MCP server configured.\n", style=THEME["warning"])
            t.append("  Add one with :mcp add <name> <url|command>.\n", style=THEME["muted"])
            self._show_command_output(log, t)
            return
        summary = manager.get_status_summary()
        for server_id, config in configs.items():
            conn = manager.get_connection(server_id)
            state = manager.get_connection_state(server_id).value
            config_obj = config.config
            transport = getattr(config_obj, "transport", type(config_obj).__name__)
            if hasattr(config_obj, "url"):
                target = getattr(config_obj, "url", "")
            else:
                target = " ".join(
                    [getattr(config_obj, "command", ""), *getattr(config_obj, "args", [])]
                )
            server_summary = summary.get("servers", {}).get(server_id, {})
            style = (
                THEME["success"]
                if state == "connected"
                else THEME["warning"]
                if state == "error"
                else THEME["muted"]
            )
            t.append(f"  {server_id}\n", style=f"bold {THEME['cyan']}")
            t.append("    state      ", style=THEME["muted"])
            t.append(f"{state}\n", style=style)
            t.append("    transport  ", style=THEME["muted"])
            t.append(f"{transport}\n", style=THEME["text"])
            t.append("    target     ", style=THEME["muted"])
            t.append(f"{target or '-'}\n", style=THEME["text"])
            t.append("    enabled    ", style=THEME["muted"])
            t.append(f"{config.enabled}  auto_connect={config.auto_connect}\n", style=THEME["text"])
            t.append("    exposed    ", style=THEME["muted"])
            t.append(
                f"{server_summary.get('tools', 0)} tools, {server_summary.get('resources', 0)} resources, {server_summary.get('prompts', 0)} prompts\n",
                style=THEME["text"],
            )
            error = getattr(conn, "error_message", None) if conn else server_summary.get("error")
            if error:
                t.append("    error      ", style=THEME["muted"])
                t.append(f"{error}\n", style=THEME["error"])
            t.append("\n")
        t.append("  Commands: ", style=THEME["muted"])
        t.append(":mcp connect <server>", style=THEME["cyan"])
        t.append(", ", style=THEME["muted"])
        t.append(":mcp reconnect <server>", style=THEME["cyan"])
        t.append("\n", style=THEME["muted"])
        self._show_command_output(log, t)

    def _get_session_manager(self):
        """Get a local JSONL session manager."""
        from superqode.agent.session_manager import SessionManager

        return SessionManager(storage_dir=".superqode/sessions")

    def _current_session_id(self) -> str:
        """Resolve the active or most-recent local session id."""
        try:
            if hasattr(self, "_pure_mode") and self._pure_mode:
                sid = self._pure_mode.get_current_session_id()
                if sid:
                    return sid
        except Exception:
            pass
        try:
            sessions = self._get_session_manager().list_all_sessions()
            if sessions:
                return sessions[0].session_id
        except Exception:
            pass
        return ""

    def _handle_session(self, args: str, log: ConversationLog):
        """Session subcommands: `:session` (info) and `:session rename <name>`."""
        parts = (args or "").strip().split(maxsplit=1)
        sub = parts[0].lower() if parts else ""
        manager = self._get_session_manager()

        if sub in ("rename", "name", "title"):
            rest = parts[1].strip() if len(parts) > 1 else ""
            if not rest:
                log.add_info("Usage: :session rename [<id>] <new title>")
                return
            # Optional leading id/prefix: "<id> <title...>".
            sid = ""
            tokens = rest.split(maxsplit=1)
            if len(tokens) == 2:
                candidate = tokens[0]
                matches = [
                    s for s in manager.list_all_sessions() if s.session_id.startswith(candidate)
                ]
                if len(matches) == 1:
                    sid = matches[0].session_id
                    rest = tokens[1].strip()
            if not sid:
                sid = self._current_session_id()
            if not sid:
                log.add_error("No session to rename yet. Start a conversation first.")
                return
            metadata = manager.get_session_info(sid)
            if metadata is None:
                log.add_error(f"Session not found: {sid[:8]}")
                return
            metadata.title = rest
            try:
                manager.store._save_metadata(metadata)
            except Exception as exc:
                log.add_error(f"Could not save session title: {exc}")
                return
            log.add_success(f"Renamed session {sid[:8]} → “{rest}”")
            return

        # No/unknown subcommand: show current session info.
        sid = self._current_session_id()
        if not sid:
            log.add_info("No active session. Connect and send a message, or :sessions to list.")
            return
        metadata = manager.get_session_info(sid)
        t = Text()
        t.append("\n  📂 ", style=f"bold {THEME['purple']}")
        t.append("Current Session\n\n", style=f"bold {THEME['text']}")
        t.append("  Id      ", style=THEME["muted"])
        t.append(f"{sid[:12]}\n", style=f"bold {THEME['cyan']}")
        if metadata is not None:
            t.append("  Title   ", style=THEME["muted"])
            t.append(f"{metadata.title or '(unnamed)'}\n", style=THEME["text"])
            t.append("  Model   ", style=THEME["muted"])
            t.append(
                f"{metadata.provider or '-'} / {metadata.model or 'unknown'}\n", style=THEME["text"]
            )
            t.append("  Messages ", style=THEME["muted"])
            t.append(f"{metadata.message_count}\n", style=THEME["text"])
        t.append("\n  ", style="")
        t.append(":session rename <name>", style=f"bold {THEME['cyan']}")
        t.append(" to label it.\n", style=THEME["muted"])
        log.write(t)

    def _handle_update(self, args: str, log: ConversationLog):
        """Check whether a newer SuperQode release is available on PyPI."""
        from importlib.metadata import version as _pkg_version

        try:
            current = _pkg_version("superqode")
        except Exception:
            current = "unknown"
        log.add_info(f"Installed SuperQode version: {current}. Checking for updates…")
        self.run_worker(self._check_update_worker(current, log), exclusive=False)

    async def _check_update_worker(self, current: str, log: ConversationLog):
        """Fetch the latest version from PyPI without blocking the UI."""
        import asyncio
        import json as _json
        import urllib.request

        def _fetch() -> str:
            with urllib.request.urlopen("https://pypi.org/pypi/superqode/json", timeout=8) as resp:
                data = _json.loads(resp.read().decode("utf-8"))
            return str(data.get("info", {}).get("version", ""))

        try:
            latest = await asyncio.to_thread(_fetch)
        except Exception as exc:
            self._call_ui(log.add_error, f"Could not check for updates: {exc}")
            return
        if not latest:
            self._call_ui(log.add_info, "Could not determine the latest version.")
            return
        if self._version_is_newer(latest, current):
            t = Text()
            t.append("\n  ⬆ ", style=f"bold {THEME['success']}")
            t.append(f"Update available: {current} → {latest}\n", style=f"bold {THEME['text']}")
            t.append("  Upgrade with ", style=THEME["muted"])
            t.append("uv tool upgrade superqode", style=f"bold {THEME['cyan']}")
            t.append(" or ", style=THEME["muted"])
            t.append("uv tool upgrade superqode", style=f"bold {THEME['cyan']}")
            t.append("\n", style="")
            self._call_ui(log.write, t)
        else:
            self._call_ui(log.add_success, f"SuperQode is up to date ({current}).")

    @staticmethod
    def _version_is_newer(latest: str, current: str) -> bool:
        """Compare dotted version strings; True if latest > current."""

        def parse(v: str) -> tuple:
            out = []
            for part in str(v).split("."):
                num = "".join(ch for ch in part if ch.isdigit())
                out.append(int(num) if num else 0)
            return tuple(out)

        try:
            return parse(latest) > parse(current)
        except Exception:
            return False

    def _show_sessions(self, log: ConversationLog):
        """Show recent local coding sessions."""
        manager = self._get_session_manager()
        sessions = manager.list_all_sessions()

        t = Text()
        t.append("\n  📂 ", style=f"bold {THEME['purple']}")
        t.append("Recent Sessions\n\n", style=f"bold {THEME['purple']}")

        if not sessions:
            t.append("  No sessions found yet.\n", style=THEME["muted"])
            t.append("  Connect with ", style=THEME["muted"])
            t.append(":connect byok", style=THEME["cyan"])
            t.append(" or ", style=THEME["muted"])
            t.append(":connect local", style=THEME["cyan"])
            t.append(" and send a message to create one.\n", style=THEME["muted"])
            self._show_command_output(log, t)
            return

        for session in sessions[:12]:
            display_id = session.session_id[:8]
            model = session.model or "unknown"
            provider = session.provider or "-"
            t.append(f"  {display_id:<10}", style=f"bold {THEME['cyan']}")
            t.append(f"{provider:<14}", style=THEME["success"])
            t.append(f"{model:<28}", style=THEME["text"])
            t.append(f"{session.message_count:>3} msgs  ", style=THEME["muted"])
            t.append(f"{session.updated_at[:19]}\n", style=THEME["dim"])

        t.append("\n  Use ", style=THEME["muted"])
        t.append("/resume <id>", style=THEME["cyan"])
        t.append(" to continue or ", style=THEME["muted"])
        t.append("/fork <optional-new-id>", style=THEME["cyan"])
        t.append(" to branch the active session.\n", style=THEME["muted"])
        t.append("  Use ", style=THEME["muted"])
        t.append(":switchboard", style=THEME["cyan"])
        t.append(" for graph, handoff, approvals, and share-tree actions.\n", style=THEME["muted"])
        self._show_command_output(log, t)

    def _handle_sessions_command(self, args: str, log: ConversationLog) -> None:
        """Handle :sessions subcommands without stealing :session."""
        try:
            tokens = shlex.split((args or "").strip())
        except ValueError as exc:
            log.add_error(f"Could not parse :sessions arguments: {exc}")
            return

        if not tokens:
            self._show_sessions(log)
            return

        subcommand = tokens[0].lower()
        rest = tokens[1:]
        if subcommand in {"resume", "switch", "select"}:
            if rest:
                self._handle_resume_session(" ".join(rest), log)
            else:
                self._show_session_resume_picker(log)
            return
        if subcommand in {"list", "ls", "recent"}:
            self._show_sessions(log)
            return
        switchboard_subcommands = {
            "graph",
            "tree",
            "switchboard",
            "info",
            "history",
            "children",
            "handoff",
            "fork-agent",
            "approvals",
            "share-tree",
        }
        if subcommand in switchboard_subcommands:
            self._handle_switchboard(" ".join(tokens), log)
            return

        self._run_cli_passthrough(["sessions", *tokens], log, "Sessions command")

    def _show_session_resume_picker(self, log: ConversationLog, clear_log: bool = True) -> None:
        """Show a keyboard-navigable picker for resuming local sessions."""
        manager = self._get_session_manager()
        sessions = manager.list_all_sessions()[:12]

        self._awaiting_session_resume = bool(sessions)
        self._session_resume_list = sessions
        if not hasattr(self, "_session_resume_highlighted_index"):
            self._session_resume_highlighted_index = 0
        self._session_resume_highlighted_index = min(
            max(0, getattr(self, "_session_resume_highlighted_index", 0)),
            max(0, len(sessions) - 1),
        )

        t = Text()
        t.append("\n  📂 ", style=f"bold {THEME['purple']}")
        t.append("Resume Session\n\n", style=f"bold {THEME['text']}")

        if not sessions:
            t.append("  No sessions found yet.\n", style=THEME["muted"])
            t.append("  Start a conversation with ", style=THEME["muted"])
            t.append(":connect byok", style=THEME["cyan"])
            t.append(" or ", style=THEME["muted"])
            t.append(":connect local", style=THEME["cyan"])
            t.append(".\n", style=THEME["muted"])
            self._show_command_output(log, t, clear_log=clear_log)
            return

        for idx, session in enumerate(sessions, 1):
            highlighted = (idx - 1) == self._session_resume_highlighted_index
            display_id = session.session_id[:8]
            provider = session.provider or "-"
            model = session.model or "unknown"
            title = session.title or "(unnamed)"
            if highlighted:
                t.append("  ▶ ", style=f"bold {THEME['success']}")
                t.append(
                    f"[{idx:2}] ",
                    style=self._picker_link_style(f"bold {THEME['success']}", idx),
                )
                style = f"bold {THEME['success']}"
            else:
                t.append("    ", style="")
                t.append(f"[{idx:2}] ", style=self._picker_link_style(THEME["dim"], idx))
                style = THEME["text"]
            id_style = f"bold {THEME['cyan']}" if not highlighted else style
            count_style = THEME["muted"] if not highlighted else style
            title_style = THEME["dim"] if not highlighted else style
            t.append(f"{display_id:<10}", style=id_style)
            t.append(f"{provider:<12}", style=THEME["success"] if not highlighted else style)
            t.append(f"{model:<24}", style=style)
            t.append(f"{session.message_count:>3} msgs  ", style=count_style)
            t.append(f"{title[:44]}\n", style=title_style)

        t.append("\n  ↑↓ navigate  Enter resume  or type ", style=THEME["muted"])
        t.append(":sessions resume <id>", style=THEME["cyan"])
        t.append("\n", style=THEME["muted"])
        self._show_command_output(log, t, clear_log=clear_log)
        self.set_timer(0.05, self._ensure_input_focus)

    def action_navigate_session_resume_up(self) -> None:
        """Navigate to previous resumable session."""
        if not getattr(self, "_awaiting_session_resume", False):
            return
        sessions = getattr(self, "_session_resume_list", [])
        if not sessions:
            return
        current = getattr(self, "_session_resume_highlighted_index", 0)
        new_idx = max(0, current - 1)
        if new_idx != current:
            self._session_resume_highlighted_index = new_idx
            log = self.query_one("#log", ConversationLog)
            self._show_session_resume_picker(log, clear_log=False)

    def action_navigate_session_resume_down(self) -> None:
        """Navigate to next resumable session."""
        if not getattr(self, "_awaiting_session_resume", False):
            return
        sessions = getattr(self, "_session_resume_list", [])
        if not sessions:
            return
        current = getattr(self, "_session_resume_highlighted_index", 0)
        new_idx = min(len(sessions) - 1, current + 1)
        if new_idx != current:
            self._session_resume_highlighted_index = new_idx
            log = self.query_one("#log", ConversationLog)
            self._show_session_resume_picker(log, clear_log=False)

    def action_select_highlighted_session_resume(self) -> None:
        """Resume the highlighted session."""
        if not getattr(self, "_awaiting_session_resume", False):
            return
        sessions = getattr(self, "_session_resume_list", [])
        if not sessions:
            return
        idx = getattr(self, "_session_resume_highlighted_index", 0)
        if 0 <= idx < len(sessions):
            log = self.query_one("#log", ConversationLog)
            self._handle_resume_session(sessions[idx].session_id, log)

    def _handle_session_resume_selection(self, selection: str, log: ConversationLog) -> bool:
        """Handle a typed number, id prefix, or title fragment in the resume picker."""
        sessions = getattr(self, "_session_resume_list", [])
        if not sessions:
            return False
        choice = (selection or "").strip()
        if not choice:
            self.action_select_highlighted_session_resume()
            return True

        target = None
        if choice.isdigit():
            idx = int(choice) - 1
            if 0 <= idx < len(sessions):
                target = sessions[idx]
        if target is None:
            lowered = choice.lower()
            matches = [
                session
                for session in sessions
                if session.session_id.lower().startswith(lowered)
                or lowered in (session.title or "").lower()
            ]
            if len(matches) == 1:
                target = matches[0]
            elif len(matches) > 1:
                log.add_error(f"Selection is ambiguous: {choice}")
                return True
        if target is None:
            log.add_error(f"Session not found in picker: {choice}")
            return True

        self._handle_resume_session(target.session_id, log)
        return True

    def _show_session_tree(self, log: ConversationLog):
        """Show saved sessions grouped by parent/fork relationship."""
        self._handle_switchboard("graph", log)

    def _handle_switchboard(self, args: str, log: ConversationLog) -> None:
        """TUI session switchboard over the durable graph."""
        try:
            tokens = shlex.split((args or "").strip())
        except ValueError as exc:
            log.add_error(f"Could not parse :switchboard arguments: {exc}")
            return
        subcommand = tokens[0].lower() if tokens else "graph"
        rest = tokens[1:]

        if subcommand in {"", "graph", "tree", "ls", "list"}:
            self._show_switchboard_graph(log)
        elif subcommand in {"help", "?"}:
            self._show_switchboard_help(log)
        elif subcommand in {"active", "current"}:
            self._switchboard_active(log)
        elif subcommand in {"switch", "select", "resume"}:
            self._switchboard_switch(rest, log)
        elif subcommand == "info":
            self._switchboard_info(rest, log)
        elif subcommand in {"history", "tail"}:
            self._switchboard_history(rest, log)
        elif subcommand in {"children", "child"}:
            self._switchboard_children(rest, log)
        elif subcommand in {"handoff", "send"}:
            self._switchboard_handoff(rest, log)
        elif subcommand in {"fork-agent", "forkagent", "fork"}:
            self._switchboard_fork_agent(rest, log)
        elif subcommand in {"approvals", "approval", "inbox"}:
            self._switchboard_approval_inbox(log)
        elif subcommand in {"share-tree", "share"}:
            self._switchboard_share_tree(rest, log)
        else:
            log.add_info(
                "Usage: :switchboard [graph|switch|info|history|children|handoff|fork-agent|approvals|share-tree]"
            )

    def _switchboard(self):
        from superqode.session.switchboard import SessionSwitchboard

        return SessionSwitchboard(storage_dir=".superqode/sessions")

    def _show_switchboard_help(self, log: ConversationLog) -> None:
        t = Text()
        t.append("\n  Session Tree / Session Switchboard\n\n", style=f"bold {THEME['purple']}")
        commands = [
            (":switchboard", "graph cockpit with active marker, status, approvals, and previews"),
            (
                ":switchboard switch <id>",
                "mark a session active and resume it when local storage can",
            ),
            (":switchboard info <id>", "show graph metadata and child sessions"),
            (":switchboard history <id> [limit]", "show recent transcript messages"),
            (":switchboard children <id>", "list child/fork/agent sessions"),
            (
                ':switchboard handoff <source> --to <target> --goal "..."',
                "deliver context to another session",
            ),
            (
                ':switchboard fork-agent <source> --agent reviewer --goal "..."',
                "fork to a named coding agent",
            ),
            (":switchboard approvals", "show cross-agent approval inbox"),
            (":switchboard share-tree <id> [path]", "export a portable session subtree"),
        ]
        for command, desc in commands:
            t.append(f"  {command:<58}", style=f"bold {THEME['cyan']}")
            t.append(f"{desc}\n", style=THEME["muted"])
        self._show_command_output(log, t)

    def _show_switchboard_graph(self, log: ConversationLog) -> None:
        try:
            switchboard = self._switchboard()
            tree = switchboard.graph_tree()
            active = switchboard.active() or self._current_session_id()
        except Exception as exc:
            log.add_error(f"Could not load switchboard graph: {exc}")
            return

        t = Text()
        t.append("\n  Session Tree / Session Switchboard\n\n", style=f"bold {THEME['purple']}")
        if active:
            t.append("  Active  ", style=THEME["muted"])
            t.append(f"{active}\n\n", style=f"bold {THEME['cyan']}")
        if not tree:
            t.append("  No sessions found yet.\n", style=THEME["muted"])
            t.append("  Start a conversation, then use ", style=THEME["muted"])
            t.append(":switchboard", style=THEME["cyan"])
            t.append(" to control the graph.\n", style=THEME["muted"])
            self._show_command_output(log, t)
            return

        def add_node(node: dict[str, Any], prefix: str = "", depth: int = 0) -> None:
            session_id = str(node.get("session_id") or "")
            status = str(node.get("status") or "idle")
            marker = "* " if session_id == active else "  "
            connector = "+- " if depth else ""
            title = str(node.get("title") or "(unnamed)")
            kind = str(node.get("kind") or "session")
            agent = str(node.get("agent_id") or "")
            provider = str(node.get("provider") or "-")
            model = str(node.get("model") or "unknown")
            approvals = int(node.get("pending_approvals_count") or 0)
            preview = " ".join(str(node.get("last_result_preview") or "").split())
            status_style = {
                "running": THEME["warning"],
                "needs_approval": THEME["orange"],
                "error": THEME["error"],
                "closed": THEME["dim"],
            }.get(status, THEME["success"])
            t.append(f"  {prefix}{connector}{marker}", style=THEME["dim"])
            t.append(f"{session_id[:10]:<10}", style=f"bold {THEME['cyan']}")
            t.append(f" {status:<14}", style=f"bold {status_style}")
            t.append(f" {kind:<10}", style=THEME["muted"])
            if agent:
                t.append(f" agent={agent:<12}", style=THEME["purple"])
            if approvals:
                t.append(f" approvals={approvals}", style=f"bold {THEME['orange']}")
            t.append(f"  {title}\n", style=THEME["text"])
            t.append(f"  {prefix}{'   ' if depth else ''}   ", style=THEME["dim"])
            t.append(f"{provider}/{model}", style=THEME["muted"])
            t.append(f"  updated {str(node.get('updated_at') or '')[:19]}", style=THEME["dim"])
            if preview:
                t.append(f"  {preview[:120]}", style=THEME["dim"])
            t.append("\n")
            for child in node.get("children") or []:
                add_node(child, prefix + ("   " if depth else ""), depth + 1)

        for root in tree:
            add_node(root)

        t.append("\n  Keys-as-commands: ", style=THEME["muted"])
        t.append(":sw switch <id>", style=THEME["cyan"])
        t.append("  ", style=THEME["dim"])
        t.append(":sw fork-agent <id> --agent reviewer", style=THEME["cyan"])
        t.append("  ", style=THEME["dim"])
        t.append(":sw approvals", style=THEME["cyan"])
        t.append("\n", style="")
        self._show_command_output(log, t)

    def _switchboard_active(self, log: ConversationLog) -> None:
        active = self._switchboard().active() or self._current_session_id()
        if not active:
            log.add_info("No active switchboard session yet.")
            return
        self._switchboard_info([active], log)

    def _switchboard_switch(self, tokens: list[str], log: ConversationLog) -> None:
        if not tokens:
            self._show_switchboard_graph(log)
            return
        target = tokens[0]
        try:
            record = self._switchboard().switch(target)
        except Exception as exc:
            log.add_error(f"Could not switch session: {exc}")
            return
        log.add_success(f"Active switchboard session -> {record['session_id']}")
        try:
            self._handle_resume_session(record["session_id"], log)
        except Exception:
            pass

    def _switchboard_info(self, tokens: list[str], log: ConversationLog) -> None:
        target = tokens[0] if tokens else ""
        try:
            payload = self._switchboard().info(target)
        except Exception as exc:
            log.add_error(f"Could not load session info: {exc}")
            return
        t = Text()
        t.append("\n  Session Info\n\n", style=f"bold {THEME['purple']}")
        for key in (
            "session_id",
            "title",
            "kind",
            "status",
            "agent_id",
            "parent_session_id",
            "root_session_id",
            "provider",
            "model",
            "message_count",
            "pending_approvals_count",
            "updated_at",
        ):
            value = payload.get(key)
            if value in (None, ""):
                continue
            t.append(f"  {key:<24}", style=THEME["muted"])
            t.append(f"{value}\n", style=THEME["text"])
        children = payload.get("children") or []
        if children:
            t.append("\n  Children\n", style=f"bold {THEME['text']}")
            for child in children:
                t.append(f"    {child['session_id'][:10]:<12}", style=f"bold {THEME['cyan']}")
                t.append(f"{child.get('status') or '-':<14}", style=THEME["muted"])
                t.append(f"{child.get('agent_id') or '-':<16}", style=THEME["purple"])
                t.append(f"{child.get('title') or ''}\n", style=THEME["text"])
        self._show_command_output(log, t)

    def _switchboard_history(self, tokens: list[str], log: ConversationLog) -> None:
        target = tokens[0] if tokens else ""
        limit = 12
        if len(tokens) > 1:
            try:
                limit = int(tokens[1])
            except ValueError:
                pass
        try:
            payload = self._switchboard().history(target, limit=limit)
        except Exception as exc:
            log.add_error(f"Could not load session history: {exc}")
            return
        t = Text()
        t.append(f"\n  History {payload['session_id']}\n\n", style=f"bold {THEME['purple']}")
        for message in payload.get("messages") or []:
            role = str(message.get("role") or "?")
            content = " ".join(str(message.get("content") or "").split())
            t.append(f"  {role:<10}", style=f"bold {THEME['cyan']}")
            t.append(f"{content[:220]}\n", style=THEME["text"])
        self._show_command_output(log, t)

    def _switchboard_children(self, tokens: list[str], log: ConversationLog) -> None:
        target = tokens[0] if tokens else ""
        try:
            children = self._switchboard().children(target)
        except Exception as exc:
            log.add_error(f"Could not load child sessions: {exc}")
            return
        if not children:
            log.add_info("No child sessions.")
            return
        t = Text()
        t.append("\n  Child Sessions\n\n", style=f"bold {THEME['purple']}")
        for child in children:
            t.append(f"  {child['session_id'][:10]:<12}", style=f"bold {THEME['cyan']}")
            t.append(f"{child.get('status') or '-':<14}", style=THEME["muted"])
            t.append(f"{child.get('agent_id') or '-':<16}", style=THEME["purple"])
            t.append(f"{child.get('title') or ''}\n", style=THEME["text"])
        self._show_command_output(log, t)

    @staticmethod
    def _parse_switchboard_options(tokens: list[str]) -> tuple[list[str], dict[str, str | bool]]:
        positionals: list[str] = []
        options: dict[str, str | bool] = {}
        i = 0
        while i < len(tokens):
            token = tokens[i]
            if token.startswith("--"):
                key = token[2:].replace("-", "_")
                if i + 1 < len(tokens) and not tokens[i + 1].startswith("--"):
                    options[key] = tokens[i + 1]
                    i += 2
                else:
                    options[key] = True
                    i += 1
            else:
                positionals.append(token)
                i += 1
        return positionals, options

    def _switchboard_handoff(self, tokens: list[str], log: ConversationLog) -> None:
        positionals, options = self._parse_switchboard_options(tokens)
        source = positionals[0] if positionals else ""
        target = str(
            options.get("to") or options.get("target") or options.get("target_session_id") or ""
        )
        goal = str(options.get("goal") or " ".join(positionals[1:]) or "")
        reason = str(options.get("reason") or "")
        try:
            if target:
                payload = self._switchboard().handoff_to_session(
                    source, target, goal=goal, reason=reason
                )
                log.add_success(
                    f"Delivered handoff {payload['id']} to {payload['target_session_id']}"
                )
            else:
                packet = self._switchboard().make_handoff(
                    source,
                    target_agent=str(options.get("agent") or ""),
                    goal=goal,
                    reason=reason,
                )
                self._show_command_output(log, Text(packet.to_message()))
        except Exception as exc:
            log.add_error(f"Could not create handoff: {exc}")

    def _switchboard_fork_agent(self, tokens: list[str], log: ConversationLog) -> None:
        positionals, options = self._parse_switchboard_options(tokens)
        source = positionals[0] if positionals else ""
        agent = str(options.get("agent") or (positionals[1] if len(positionals) > 1 else ""))
        if not agent:
            log.add_info(
                'Usage: :switchboard fork-agent [source] --agent reviewer --goal "review this"'
            )
            return
        try:
            payload = self._switchboard().fork_to_agent(
                source,
                agent=agent,
                new_session_id=str(options.get("session_id") or ""),
                title=str(options.get("title") or ""),
                goal=str(options.get("goal") or ""),
            )
        except Exception as exc:
            log.add_error(f"Could not fork to agent: {exc}")
            return
        log.add_success(
            f"Forked to {payload['session']['session_id']} for {agent}; handoff {payload['handoff']['id']}"
        )

    def _switchboard_approval_inbox(self, log: ConversationLog) -> None:
        try:
            sessions = self._switchboard().list_sessions()
        except Exception as exc:
            log.add_error(f"Could not load approval inbox: {exc}")
            return
        blocked = [
            item
            for item in sessions
            if item.get("status") == "needs_approval"
            or int(item.get("pending_approvals_count") or 0) > 0
        ]
        t = Text()
        t.append("\n  Approval Inbox\n\n", style=f"bold {THEME['orange']}")
        if not blocked:
            t.append("  No child sessions are waiting for approval.\n", style=THEME["muted"])
            self._show_command_output(log, t)
            return
        for item in blocked:
            t.append(f"  {item['session_id'][:10]:<12}", style=f"bold {THEME['cyan']}")
            t.append(f"{item.get('status') or '-':<16}", style=f"bold {THEME['orange']}")
            t.append(
                f"approvals={item.get('pending_approvals_count') or 0:<3}", style=THEME["muted"]
            )
            t.append(f" {item.get('agent_id') or '-'}", style=THEME["purple"])
            t.append(f"  {item.get('title') or ''}\n", style=THEME["text"])
        t.append("\n  Use the parent session's ", style=THEME["muted"])
        t.append(":approve", style=THEME["cyan"])
        t.append(" / ", style=THEME["muted"])
        t.append(":reject", style=THEME["cyan"])
        t.append(" controls, or switch to the parent session first.\n", style=THEME["muted"])
        self._show_command_output(log, t)

    def _switchboard_share_tree(self, tokens: list[str], log: ConversationLog) -> None:
        session_arg, path_arg = self._parse_share_session_and_path(tokens)
        try:
            session_id = self._resolve_share_session_id(session_arg)
            artifact_path = self._write_share_artifact(session_id, path_arg, include_tree=True)
        except Exception as exc:
            log.add_error(f"Could not share session tree: {exc}")
            return
        log.add_success(f"Created share-tree artifact -> {artifact_path}")

    def _handle_factory(self, args: str, log: ConversationLog) -> None:
        """Software Factory commands for model/harness/provider independence."""
        try:
            tokens = shlex.split((args or "").strip())
        except ValueError as exc:
            log.add_error(f"Could not parse :factory arguments: {exc}")
            return
        subcommand = tokens[0].lower() if tokens else "status"
        rest = tokens[1:]
        if subcommand in {"", "status"}:
            self._factory_status(rest, log)
        elif subcommand in {"help", "?"}:
            self._factory_help(log)
        elif subcommand in {"policy"}:
            self._factory_policy(log)
        elif subcommand in {"init-policy", "init"}:
            self._factory_init_policy(rest, log)
        elif subcommand in {"routes", "route", "models"}:
            self._factory_routes(log)
        elif subcommand in {"mode", "policy"}:
            self._factory_mode(rest, log)
        elif subcommand in {"switch-model", "model"}:
            self._factory_switch_model(rest, log)
        elif subcommand in {"switch-harness", "harness"}:
            self._factory_switch_harness(rest, log)
        elif subcommand in {"fork-model"}:
            self._factory_fork_model(rest, log)
        elif subcommand in {"fork-harness"}:
            self._factory_fork_harness(rest, log)
        elif subcommand in {"lineage", "timeline"}:
            self._factory_lineage(rest, log)
        else:
            self._run_cli_passthrough(["factory", *tokens], log, "Factory command")

    def _factory(self):
        from superqode.session.factory import SoftwareFactory

        return SoftwareFactory(storage_dir=".superqode/sessions")

