    def _claude_runtime_or_connect(self, log):
        pure = getattr(self, "_pure_mode", None)
        runtime = getattr(pure, "_runtime", None) if pure is not None else None
        if (
            runtime is not None
            and getattr(pure, "runtime_name", "") == "claude-agent-sdk"
            and getattr(getattr(pure, "session", None), "connected", False)
        ):
            return runtime
        self._runtime_cmd("claude-agent-sdk", log)
        pure = getattr(self, "_pure_mode", None)
        runtime = getattr(pure, "_runtime", None) if pure is not None else None
        if runtime is None or getattr(pure, "runtime_name", "") != "claude-agent-sdk":
            raise RuntimeError("Claude Agent SDK runtime is not connected")
        return runtime

    def _claude_runtime_action(self, log, label: str, action) -> None:
        try:
            runtime = self._claude_runtime_or_connect(log)
            action(runtime)
            log.add_success(f"Claude {label}")
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not {label}: {exc}")

    def _claude_status(self, log) -> None:
        import importlib.util
        import shutil

        text = Text()
        text.append("\n  Claude Agent SDK status\n\n", style=f"bold {THEME['cyan']}")
        sdk_ok = importlib.util.find_spec("claude_agent_sdk") is not None
        text.append("  SDK          ", style=THEME["muted"])
        text.append(
            "installed\n" if sdk_ok else "missing\n",
            style=THEME["success" if sdk_ok else "error"],
        )
        cli_ok = shutil.which("claude") is not None
        text.append("  Claude CLI   ", style=THEME["muted"])
        text.append(
            "found\n" if cli_ok else "not found (install Claude Code)\n",
            style=THEME["success" if cli_ok else "warning"],
        )
        key_ok = bool(os.environ.get("ANTHROPIC_API_KEY"))
        text.append("  API key      ", style=THEME["muted"])
        text.append(
            "ANTHROPIC_API_KEY set\n" if key_ok else "ANTHROPIC_API_KEY not set\n",
            style=THEME["success" if key_ok else "error"],
        )
        pure = getattr(self, "_pure_mode", None)
        runtime = getattr(pure, "_runtime", None) if pure is not None else None
        connected = runtime is not None and getattr(pure, "runtime_name", "") == "claude-agent-sdk"
        text.append("  Connected    ", style=THEME["muted"])
        text.append(
            "yes\n" if connected else "no (use :claude)\n",
            style=THEME["success" if connected else "warning"],
        )
        if connected:
            model = getattr(runtime, "config", None)
            model_id = getattr(model, "model", "") or "Claude Code default"
            text.append("  Model        ", style=THEME["muted"])
            text.append(f"{model_id}\n", style=THEME["text"])
            text.append("  Permission   ", style=THEME["muted"])
            text.append(
                f"{getattr(runtime, 'permission_mode', None) or 'default'}\n", style=THEME["text"]
            )
            cmds = getattr(runtime, "slash_commands", [])
            text.append("  Slash cmds   ", style=THEME["muted"])
            text.append(f"{len(cmds)} available\n", style=THEME["text"])
        if not (sdk_ok and key_ok):
            text.append("\n  Setup: ", style=THEME["muted"])
            text.append('uv tool install "superqode[claude-agent-sdk]"', style=THEME["cyan"])
            text.append(" + install Claude Code + export ANTHROPIC_API_KEY\n", style=THEME["muted"])
        log.write(text)

    def _claude_model_cmd(self, model: str, log) -> None:
        from superqode.runtime.claude_agent_sdk import CLAUDE_MODELS

        if not model:
            t = Text()
            t.append("\n  Claude models (curated):\n", style=f"bold {THEME['text']}")
            for i, (mid, name) in enumerate(CLAUDE_MODELS, 1):
                t.append(f"    [{i}] ", style=THEME["dim"])
                t.append(f"{name}", style=THEME["text"])
                t.append(f"  {mid or '(default)'}\n", style=THEME["muted"])
            t.append("\n  Set with ", style=THEME["muted"])
            t.append(":claude model <id>", style=THEME["cyan"])
            t.append("  (e.g. :claude model claude-opus-4-8)\n", style=THEME["muted"])
            log.write(t)
            return
        chosen = "" if model.lower() in {"default", "none", "auto"} else model
        try:
            runtime = self._claude_runtime_or_connect(log)
            runtime.set_model(chosen)
            if getattr(self, "_pure_mode", None) is not None:
                self._pure_mode.session.model = chosen
            self._set_status_model(chosen)
            log.add_success(f"Claude model set to {chosen or 'Claude Code default'}")
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not set Claude model: {exc}")

    def _claude_permission_cmd(self, mode: str, log) -> None:
        modes = ("default", "acceptEdits", "plan", "bypassPermissions", "dontAsk", "auto")
        if not mode:
            log.add_info(
                f"Permission modes: {', '.join(modes)}.  Set with :claude permission <mode>"
            )
            return
        try:
            runtime = self._claude_runtime_or_connect(log)
            runtime.set_permission_mode(mode)
            log.add_success(f"Claude permission mode set to {mode}")
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not set permission mode: {exc}")

    def _claude_sessions_cmd(self, log) -> None:
        try:
            runtime = self._claude_runtime_or_connect(log)
            sessions = runtime.list_threads(limit=20)
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not list Claude sessions: {exc}")
            return
        t = Text()
        t.append("\n  Claude sessions\n\n", style=f"bold {THEME['text']}")
        if not sessions:
            t.append("  (none)\n", style=THEME["muted"])
        for s in list(sessions)[:20]:
            sid = getattr(s, "session_id", getattr(s, "id", "")) or "?"
            title = getattr(s, "title", "") or ""
            t.append("  • ", style=THEME["dim"])
            t.append(f"{sid}", style=THEME["text"])
            if title:
                t.append(f"  {title}", style=THEME["muted"])
            t.append("\n", style="")
        t.append("\n  Resume with ", style=THEME["muted"])
        t.append(":claude resume <session-id>\n", style=THEME["cyan"])
        log.write(t)

    def _claude_commands_cmd(self, log) -> None:
        runtime = getattr(getattr(self, "_pure_mode", None), "_runtime", None)
        cmds = list(getattr(runtime, "slash_commands", []) or []) if runtime else []
        t = Text()
        t.append("\n  Claude slash commands\n\n", style=f"bold {THEME['text']}")
        if not cmds:
            t.append(
                "  (none yet — send a message first so the SDK reports them)\n",
                style=THEME["muted"],
            )
        for name in cmds:
            t.append("  • ", style=THEME["dim"])
            t.append(f"/{name}\n", style=THEME["cyan"])
        t.append("\n  Run with ", style=THEME["muted"])
        t.append(":claude command <name> [args]\n", style=THEME["cyan"])
        log.write(t)

    def _codex_runtime_or_connect(self, log):
        pure = getattr(self, "_pure_mode", None)
        runtime = getattr(pure, "_runtime", None) if pure is not None else None
        if (
            runtime is not None
            and getattr(pure, "runtime_name", "") == "codex-sdk"
            and getattr(getattr(pure, "session", None), "connected", False)
        ):
            return runtime
        self._runtime_cmd("codex-sdk", log)
        pure = getattr(self, "_pure_mode", None)
        runtime = getattr(pure, "_runtime", None) if pure is not None else None
        if runtime is None or getattr(pure, "runtime_name", "") != "codex-sdk":
            raise RuntimeError("Codex runtime is not connected")
        return runtime

    @staticmethod
    def _codex_obj_dict(obj) -> dict:
        if obj is None:
            return {}
        if isinstance(obj, dict):
            return dict(obj)
        if hasattr(obj, "model_dump"):
            dumped = obj.model_dump(mode="json", by_alias=True)
            return dumped if isinstance(dumped, dict) else {}
        return {
            key: getattr(obj, key)
            for key in dir(obj)
            if not key.startswith("_") and not callable(getattr(obj, key))
        }

    def _codex_runtime_action(self, log, label: str, action) -> None:
        try:
            runtime = self._codex_runtime_or_connect(log)
            action(runtime)
            log.add_success(f"Codex {label} complete.")
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Codex {label} failed: {exc}")

    @staticmethod
    def _codex_effort_options() -> list[dict[str, str]]:
        return [
            {
                "id": "default",
                "name": "Codex default",
                "desc": "Use the effort configured in ~/.codex or selected by Codex.",
            },
            {
                "id": "minimal",
                "name": "Minimal",
                "desc": "Fastest reasoning for small edits and straightforward prompts.",
            },
            {
                "id": "low",
                "name": "Low",
                "desc": "Light reasoning for simple coding tasks.",
            },
            {
                "id": "medium",
                "name": "Medium",
                "desc": "Balanced reasoning for normal development work.",
            },
            {
                "id": "high",
                "name": "High",
                "desc": "Deeper reasoning for complex changes and reviews.",
            },
            {
                "id": "xhigh",
                "name": "Extra high",
                "desc": "Maximum reasoning when latency is less important.",
            },
        ]

    def _codex_picker_line(
        self,
        text: Text,
        number: int,
        primary: str,
        secondary: str,
        desc: str,
        *,
        highlighted: bool,
    ) -> None:
        pointer = "> " if highlighted else "  "
        number_style = self._picker_link_style(
            f"bold {THEME['success'] if highlighted else THEME['cyan']}", number
        )
        primary_style = f"bold {THEME['success'] if highlighted else THEME['text']}"
        text.append("  ")
        text.append(pointer, style=f"bold {THEME['success']}" if highlighted else THEME["dim"])
        text.append(f"[{number}]", style=number_style)
        text.append(" ")
        text.append(primary, style=primary_style)
        if secondary:
            text.append(f"  {secondary}", style=THEME["muted"])
        if desc:
            text.append(f"\n       {desc}", style=THEME["dim"])
        if highlighted:
            text.append("  selected", style=f"bold {THEME['success']}")
        text.append("\n")

    def _show_codex_model_picker(
        self, log, *, clear_log: bool = True, refetch: bool = True
    ) -> None:
        try:
            if refetch or not getattr(self, "_codex_models", None):
                runtime = self._codex_runtime_or_connect(log)
                response = runtime.models()
                self._codex_models = self._models_from_codex_response(response)
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not list Codex models: {exc}")
            return

        models = list(getattr(self, "_codex_models", None) or [])
        if not models:
            models = [
                {
                    "id": "",
                    "name": "Codex default",
                    "desc": "Use the model configured in ~/.codex.",
                    "efforts": [],
                }
            ]
            self._codex_models = models

        self._reset_connect_selection_states()
        self._awaiting_codex_model = True
        self._codex_highlighted_model_index = min(
            getattr(self, "_codex_highlighted_model_index", 0), len(models) - 1
        )

        current_runtime = getattr(getattr(self, "_pure_mode", None), "_runtime", None)
        current = getattr(current_runtime, "model", None) or ""
        text = Text()
        text.append("\n  Codex model\n\n", style=f"bold {THEME['cyan']}")
        if current:
            text.append("  Current override: ", style=THEME["muted"])
            text.append(current, style=f"bold {THEME['text']}")
            text.append("\n\n")
        else:
            text.append("  Current: Codex default from ~/.codex\n\n", style=THEME["muted"])

        for idx, model in enumerate(models):
            model_id = str(model.get("id") or "")
            name = str(model.get("name") or model_id or "Codex default")
            efforts = ", ".join(model.get("efforts") or [])
            secondary = model_id if model_id and model_id != name else ""
            desc = f"effort: {efforts}" if efforts else str(model.get("desc") or "")
            self._codex_picker_line(
                text,
                idx + 1,
                name,
                secondary,
                desc,
                highlighted=idx == self._codex_highlighted_model_index,
            )

        text.append(
            "\n  Use Up/Down + Enter, click a number, or type a model id.\n", style=THEME["muted"]
        )
        text.append("  Esc cancels. ", style=THEME["muted"])
        text.append(":codex models", style=THEME["cyan"])
        text.append(" shows a plain list.\n", style=THEME["muted"])
        self._show_command_output(log, text, clear_log=clear_log)

    def _show_codex_effort_picker(self, log, *, clear_log: bool = True) -> None:
        self._reset_connect_selection_states()
        self._awaiting_codex_effort = True
        options = self._codex_effort_options()
        self._codex_highlighted_effort_index = min(
            getattr(self, "_codex_highlighted_effort_index", 0), len(options) - 1
        )
        try:
            runtime = self._codex_runtime_or_connect(log)
            current = runtime.reasoning_effort or "default"
        except Exception:
            current = "default"

        text = Text()
        text.append("\n  Codex reasoning effort\n\n", style=f"bold {THEME['cyan']}")
        text.append("  Current: ", style=THEME["muted"])
        text.append(current, style=f"bold {THEME['text']}")
        text.append("\n\n")
        for idx, option in enumerate(options):
            label = option["name"]
            option_id = option["id"]
            if option_id == current:
                label = f"{label} (current)"
            self._codex_picker_line(
                text,
                idx + 1,
                label,
                option_id,
                option["desc"],
                highlighted=idx == self._codex_highlighted_effort_index,
            )

        text.append(
            "\n  Use Up/Down + Enter, click a number, or type an effort name.\n",
            style=THEME["muted"],
        )
        text.append("  Esc cancels.\n", style=THEME["muted"])
        self._show_command_output(log, text, clear_log=clear_log)

    def _handle_codex_model_selection(self, selection: str, log) -> bool:
        if not getattr(self, "_awaiting_codex_model", False):
            return False
        raw = (selection or "").strip()
        models = list(getattr(self, "_codex_models", None) or [])
        if not raw:
            self.action_select_highlighted_codex_model()
            return True

        selected = None
        if raw.isdigit():
            idx = int(raw) - 1
            if 0 <= idx < len(models):
                selected = models[idx]
            else:
                log.add_error(f"Invalid Codex model selection. Choose 1-{len(models)}.")
                return True
        else:
            lowered = raw.lower()
            for model in models:
                model_id = str(model.get("id") or "")
                name = str(model.get("name") or "")
                if lowered in {model_id.lower(), name.lower()}:
                    selected = model
                    break
            if selected is None:
                matches = [
                    model
                    for model in models
                    if lowered in str(model.get("id") or "").lower()
                    or lowered in str(model.get("name") or "").lower()
                ]
                if len(matches) == 1:
                    selected = matches[0]
                elif len(matches) > 1:
                    log.add_error(
                        f"'{raw}' matches multiple Codex models. Type the exact model id."
                    )
                    return True
            if selected is None:
                log.add_error(f"Codex model '{raw}' not found.")
                return True

        self._awaiting_codex_model = False
        self._apply_codex_model_override(str(selected.get("id") or ""), log)
        return True

    def _handle_codex_effort_selection(self, selection: str, log) -> bool:
        if not getattr(self, "_awaiting_codex_effort", False):
            return False
        raw = (selection or "").strip().lower()
        options = self._codex_effort_options()
        if not raw:
            self.action_select_highlighted_codex_effort()
            return True

        selected = None
        if raw.isdigit():
            idx = int(raw) - 1
            if 0 <= idx < len(options):
                selected = options[idx]
            else:
                log.add_error(f"Invalid Codex effort selection. Choose 1-{len(options)}.")
                return True
        else:
            for option in options:
                if raw in {option["id"], option["name"].lower()}:
                    selected = option
                    break
            if selected is None:
                log.add_error(
                    "Invalid Codex effort. Choose minimal, low, medium, high, xhigh, or default."
                )
                return True

        self._awaiting_codex_effort = False
        self._codex_effort_cmd(selected["id"], log)
        return True

    def _codex_models_cmd(self, log, *, include_hidden: bool = False) -> None:
        try:
            runtime = self._codex_runtime_or_connect(log)
            response = runtime.models(include_hidden=include_hidden)
            self._codex_models = self._models_from_codex_response(response)
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not list Codex models: {exc}")
            return

        text = Text()
        text.append("\n  Codex models\n\n", style=f"bold {THEME['cyan']}")
        for model in self._codex_models[:30]:
            text.append("  ")
            text.append(str(model.get("id") or ""), style=f"bold {THEME['text']}")
            name = model.get("name")
            if name and name != model.get("id"):
                text.append(f"  {name}", style=THEME["muted"])
            efforts = model.get("efforts") or []
            if efforts:
                text.append(f"  effort: {', '.join(efforts)}", style=THEME["dim"])
            text.append("\n")
        if len(self._codex_models) > 30:
            text.append(
                f"\n  +{len(self._codex_models) - 30} more hidden/listed models\n",
                style=THEME["dim"],
            )
        text.append("\n  Use ", style=THEME["muted"])
        text.append(":codex model <id>", style=THEME["cyan"])
        text.append(" to switch future turns.\n", style=THEME["muted"])
        log.write(text)

    def _codex_model_cmd(self, model: str, log) -> None:
        if not model:
            self._show_codex_model_picker(log)
            return
        if model.lower() in {"default", "none", "auto"}:
            self._apply_codex_model_override("", log)
            return
        self._apply_codex_model_override(model, log)

    def _apply_codex_model_override(self, model: str, log) -> None:
        try:
            runtime = self._codex_runtime_or_connect(log)
            runtime.set_model(model)
            if getattr(self, "_pure_mode", None) is not None:
                self._pure_mode.session.model = model
            label = model or "Codex default"
            self._set_status_model(model)  # reflect in the status-bar badge
            log.add_success(f"Codex model set to {label}")
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not set Codex model: {exc}")

    def _codex_effort_cmd(self, effort: str, log) -> None:
        if not effort:
            self._show_codex_effort_picker(log)
            return
        try:
            runtime = self._codex_runtime_or_connect(log)
            runtime.set_reasoning_effort(effort)
            current = runtime.reasoning_effort or "default"
            log.add_success(f"Codex reasoning effort set to {current}")
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not set Codex effort: {exc}")

    def _codex_sandbox_cmd(self, mode: str, log) -> None:
        if not mode:
            log.add_info("Usage: :codex sandbox <read-only|workspace-write|full-access|default>")
            return
        try:
            runtime = self._codex_runtime_or_connect(log)
            runtime.set_sandbox_backend(None if mode in {"default", "none"} else mode)
            log.add_success(f"Codex sandbox set to {mode}")
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not set Codex sandbox: {exc}")

    def _codex_thread_cmd(self, log) -> None:
        try:
            runtime = self._codex_runtime_or_connect(log)
            thread = runtime.read_thread(include_turns=False).thread
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not read Codex thread: {exc}")
            return
        data = self._codex_obj_dict(thread)
        text = Text()
        text.append("\n  Codex thread\n\n", style=f"bold {THEME['cyan']}")
        for key in ("id", "name", "model", "modelProvider", "preview", "path", "cwd"):
            value = data.get(key)
            if value:
                text.append(f"  {key:<14}", style=THEME["muted"])
                text.append(str(value), style=THEME["text"])
                text.append("\n")
        log.write(text)

    def _codex_sessions_cmd(self, args: str, log) -> None:
        archived = "archived" in args.split() or "--archived" in args.split()
        try:
            runtime = self._codex_runtime_or_connect(log)
            response = runtime.list_threads(limit=20, archived=archived)
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not list Codex sessions: {exc}")
            return
        threads = list(getattr(response, "data", []) or getattr(response, "threads", []) or [])
        text = Text()
        text.append("\n  Codex sessions\n\n", style=f"bold {THEME['cyan']}")
        if not threads:
            text.append("  No Codex sessions returned.\n", style=THEME["muted"])
        for thread in threads:
            data = self._codex_obj_dict(thread)
            tid = str(data.get("id") or "")
            text.append(f"  {tid[:12]:<14}", style=f"bold {THEME['cyan']}")
            text.append(
                str(data.get("name") or data.get("preview") or "(unnamed)")[:80],
                style=THEME["text"],
            )
            text.append("\n")
        text.append("\n  Use ", style=THEME["muted"])
        text.append(":codex resume <thread_id>", style=THEME["cyan"])
        text.append(" or ", style=THEME["muted"])
        text.append(":codex fork <thread_id>", style=THEME["cyan"])
        text.append(".\n", style=THEME["muted"])
        log.write(text)

    def _codex_resume_cmd(self, thread_id: str, log) -> None:
        if not thread_id:
            log.add_info("Usage: :codex resume <thread_id>")
            return
        self._codex_runtime_action(
            log, f"resume {thread_id[:12]}", lambda runtime: runtime.resume_thread(thread_id)
        )

    def _codex_fork_cmd(self, thread_id: str, log) -> None:
        if not thread_id:
            log.add_info("Usage: :codex fork <thread_id>")
            return
        self._codex_runtime_action(
            log, f"fork {thread_id[:12]}", lambda runtime: runtime.fork_thread(thread_id)
        )

    def _codex_rename_cmd(self, name: str, log) -> None:
        if not name:
            log.add_info("Usage: :codex rename <thread name>")
            return
        self._codex_runtime_action(log, "rename", lambda runtime: runtime.rename_thread(name))

    def _codex_archive_cmd(self, thread_id: str, log) -> None:
        try:
            runtime = self._codex_runtime_or_connect(log)
            target = thread_id or runtime.thread_id
            if not target:
                log.add_info("Usage: :codex archive [thread_id]")
                return
            runtime.archive_thread(target)
            log.add_success(f"Codex archived {str(target)[:12]}.")
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not archive Codex thread: {exc}")

    def _codex_account_cmd(self, log) -> None:
        try:
            runtime = self._codex_runtime_or_connect(log)
            response = runtime.account()
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not read Codex account: {exc}")
            return
        data = self._codex_obj_dict(response)
        account = self._codex_obj_dict(data.get("account"))
        text = Text()
        text.append("\n  Codex account\n\n", style=f"bold {THEME['cyan']}")
        for key, value in {**data, **account}.items():
            if value in (None, "", [], {}):
                continue
            text.append(f"  {str(key):<24}", style=THEME["muted"])
            text.append(str(value)[:120], style=THEME["text"])
            text.append("\n")
        log.write(text)

    def _codex_review_cmd(self, prompt: str, log) -> None:
        try:
            runtime = self._codex_runtime_or_connect(log)
            runtime.set_next_turn_sandbox("read-only")
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Could not start Codex review: {exc}")
            return
        review_prompt = prompt or (
            "Review the current uncommitted diff only. Do not edit files or run commands that modify state. "
            "Prioritize correctness bugs, regressions, safety risks, and missing tests. "
            "Return findings first with file/line references where possible."
        )
        log.add_user(f":codex review\n{review_prompt}")
        self._last_user_message = review_prompt
        self._update_terminal_title("Codex review")
        self.is_busy = True
        self._cancel_requested = False
        self._send_to_pure_mode(review_prompt, log)

    def _codex_status(self, log, *, probe: bool = False) -> None:
        """Show Codex SDK/app-server/auth status."""
        from importlib import metadata
        from superqode.runtime import list_runtimes

        info = next((item for item in list_runtimes() if item.name == "codex-sdk"), None)
        text = Text()
        text.append("\n  Codex SDK status\n\n", style=f"bold {THEME['cyan']}")

        installed = bool(info and info.installed)
        text.append("  Runtime     ", style=THEME["muted"])
        text.append(
            "ready\n" if installed else "missing\n",
            style=THEME["success" if installed else "error"],
        )

        for package in ("openai-codex", "openai-codex-cli-bin"):
            text.append(f"  {package:<12}", style=THEME["muted"])
            try:
                text.append(f"{metadata.version(package)}\n", style=THEME["text"])
            except metadata.PackageNotFoundError:
                text.append("not installed\n", style=THEME["error"])

        text.append("  Config      ", style=THEME["muted"])
        text.append(str(Path.home() / ".codex"), style=THEME["text"])
        text.append("\n")

        active = (
            getattr(getattr(self, "_pure_mode", None), "runtime_name", "") == "codex-sdk"
            and getattr(getattr(self, "_pure_mode", None), "session", None) is not None
            and getattr(self._pure_mode.session, "connected", False)
        )
        text.append("  TUI bridge  ", style=THEME["muted"])
        text.append(
            "connected\n" if active else "not connected\n",
            style=THEME["success" if active else "warning"],
        )
        runtime = getattr(getattr(self, "_pure_mode", None), "_runtime", None)
        thread_id = getattr(runtime, "thread_id", None) if active else None
        sessions_dir = getattr(
            runtime, "codex_sessions_dir", str(Path.home() / ".codex" / "sessions")
        )
        text.append("  Sessions    ", style=THEME["muted"])
        text.append(str(sessions_dir), style=THEME["text"])
        text.append("\n")
        if thread_id:
            text.append("  Thread      ", style=THEME["muted"])
            text.append(str(thread_id), style=THEME["text"])
            text.append("\n")

        if not installed:
            text.append("\n  Install     ", style=THEME["muted"])
            text.append('uv tool install "superqode[codex-sdk]"\n', style=THEME["cyan"])
            log.write(text)
            return

        if not probe:
            text.append("  Probe       ", style=THEME["muted"])
            text.append("skipped (fast status)\n", style=THEME["dim"])
            text.append("  Next        ", style=THEME["muted"])
            text.append(":codex status --probe", style=THEME["cyan"])
            text.append(" to start the SDK app-server and list models\n", style=THEME["muted"])
            log.write(text)
            return

        try:
            models = self._fetch_live_codex_models()
            self._codex_models = models
            text.append("  Auth/probe  ", style=THEME["muted"])
            text.append("ok\n", style=THEME["success"])
            text.append("  Models      ", style=THEME["muted"])
            if models:
                names = [str(model.get("id") or model.get("name")) for model in models[:5]]
                text.append(", ".join(names), style=THEME["text"])
                if len(models) > 5:
                    text.append(f" (+{len(models) - 5} more)", style=THEME["dim"])
                text.append("\n")
            else:
                text.append("none returned\n", style=THEME["warning"])
        except Exception as exc:  # noqa: BLE001
            text.append("  Auth/probe  ", style=THEME["muted"])
            text.append("failed\n", style=THEME["error"])
            text.append("  Hint        ", style=THEME["muted"])
            text.append(self._codex_error_hint(str(exc)), style=THEME["warning"])
            text.append("\n")
            text.append("  Error       ", style=THEME["muted"])
            text.append(str(exc), style=THEME["text"])
            text.append("\n")

        log.write(text)

    def _harness_cmd(self, args: str, log) -> None:
        """Handle :harness status/list/templates/off/<path>."""
        import os as _os

        parts = args.split(maxsplit=1)
        sub = parts[0].strip() if parts else "status"
        subargs = parts[1].strip() if len(parts) > 1 else ""
        if not sub:
            sub = "status"

        try:
            from superqode.harness import BUILTIN_TEMPLATES, get_harness_template, load_harness_spec
        except Exception as exc:
            log.add_error(f"Harness support is unavailable: {exc}")
            return

        if sub in ("status", "current"):
            pure = getattr(self, "_pure_mode", None)
            status = pure.get_status().get("harness", {}) if pure else {}
            if status.get("enabled"):
                log.add_info(
                    f"Harness: {status.get('name')} "
                    f"({status.get('flavor')}, runtime={status.get('runtime')})"
                )
                if status.get("path"):
                    log.add_info(f"Spec: {status.get('path')}")
            else:
                env_path = _os.getenv("SUPERQODE_HARNESS", "").strip()
                if env_path:
                    log.add_info(f"Harness configured for next connection: {env_path}")
                else:
                    log.add_info("No HarnessSpec is active. Use :harness <path> to load one.")
            return

        if sub in ("templates", "list-templates"):
            for name in sorted(BUILTIN_TEMPLATES):
                if "_" in name:
                    continue
                spec = get_harness_template(name)
                log.add_info(
                    f"  {name:18} {spec.flavor.value:8} {spec.runtime.backend:14} {spec.description}"
                )
            return

        if sub in ("wizard", "init", "create"):
            self._harness_wizard_cmd(subargs, log)
            return

        if sub in ("inspect", "show", "summary"):
            self._show_harness_inspect(log)
            return

        if sub in ("doctor", "check"):
            self._show_harness_doctor(log)
            return

        if sub in ("graph", "plan"):
            self._show_harness_graph(log, run_id=subargs if sub == "graph" else "")
            return

        if sub in ("runs", "history"):
            self._show_harness_runs(log)
            return

        if sub in ("replay", "replay-plan"):
            if not subargs:
                log.add_error("Usage: :harness replay <run_id>")
                return
            self._show_harness_replay(log, subargs)
            return

        if sub in ("fork", "branch"):
            if not subargs:
                log.add_error("Usage: :harness fork <run_id> [after_index]")
                return
            self._show_harness_fork(log, subargs)
            return

        if sub in ("evidence", "receipt"):
            if not subargs:
                log.add_error("Usage: :harness evidence <run_id>")
                return
            self._show_harness_evidence(log, subargs)
            return

        if sub in ("events", "timeline"):
            if not subargs:
                log.add_error("Usage: :harness events <run_id>")
                return
            self._show_harness_events(log, subargs)
            return

        if sub in ("improve", "optimize", "optimize-inspect", "optimize-ledger"):
            try:
                tokens = shlex.split(subargs or "")
            except ValueError as exc:
                log.add_error(f"Could not parse :harness {sub} arguments: {exc}")
                return
            if sub == "optimize" and not tokens:
                log.add_info(
                    "Usage: :harness optimize --spec <path> --tasks <path> [--export-only]"
                )
                return
            if sub == "improve" and not tokens:
                log.add_info(
                    "Usage: :harness improve --spec <path> --tasks <path> [--from-failures failures.json] [--export-only]"
                )
                return
            if sub in {"optimize-inspect", "optimize-ledger"} and not tokens:
                log.add_info(f"Usage: :harness {sub} <run_dir>")
                return
            label = "Harness self-improvement" if sub == "improve" else "Harness optimization"
            self.run_worker(self._superqode_cli_cmd(["harness", sub, *tokens], log, label))
            return

        cli_backed_harness_subcommands = {
            "audit-candidate",
            "auto-bench",
            "candidates",
            "compile",
            "diff",
            "drain",
            "eval",
            "eval-packs",
            "explain",
            "import-agent",
            "import-omnigent",
            "inbox",
            "list-backends",
            "logbook",
            "mine-failures",
            "registry",
            "run",
            "test",
            "validate",
            "worker",
            "observability",
        }
        if sub in cli_backed_harness_subcommands:
            try:
                tokens = shlex.split(subargs or "")
            except ValueError as exc:
                log.add_error(f"Could not parse :harness {sub} arguments: {exc}")
                return
            self._run_cli_passthrough(["harness", sub, *tokens], log, "Harness command")
            return

        if sub in ("off", "disable", "none"):
            _os.environ.pop("SUPERQODE_HARNESS", None)
            if hasattr(self, "_pure_mode") and self._pure_mode is not None:
                self._pure_mode.clear_harness()
                if self._pure_mode.session.connected:
                    self._pure_mode.disconnect()
            self._refresh_harness_panel()
            log.add_info("HarnessSpec disabled. Reconnect with :connect byok or :connect local.")
            return

        if sub in ("load", "use"):
            path = subargs
        else:
            path = args.strip()

        if not path:
            log.add_info(
                "Usage: :harness <spec.yaml> | :harness wizard [name] --starter <template> --output <path> [--load] | :harness inspect | :harness doctor | :harness graph | :harness replay <run_id> | :harness fork <run_id> | :harness evidence <run_id> | :harness runs | :harness mine-failures --eval-result eval.json | :harness audit-candidate --base <path> --candidate <path> | :harness candidates list | :harness improve --spec <path> --tasks <path> | :harness optimize --spec <path> --tasks <path> | :harness optimize-inspect <run_dir> | :harness optimize-ledger <run_dir> | :harness templates | :harness off"
            )
            return

        try:
            spec = load_harness_spec(path)
        except Exception as exc:
            log.add_error(f"Could not load harness spec: {exc}")
            return

        _os.environ["SUPERQODE_HARNESS"] = path
        pure = self._ensure_pure_mode()
        pure.set_harness(spec, path=path)
        if pure.session.connected:
            pure.disconnect()
        self._refresh_harness_panel()

        log.add_success(
            f"✓ Loaded harness {spec.name} ({spec.flavor.value}, runtime={spec.runtime.backend})"
        )
        log.add_info(
            "Reconnect with :connect byok or :connect local to run the TUI through this spec."
        )

    def _harness_wizard_cmd(self, args: str, log) -> None:
        """Create a HarnessSpec from wizard answers supplied as TUI flags."""
        try:
            from superqode.harness import (
                APPROVAL_PROFILES,
                TOOL_CALL_FORMATS,
                WIZARD_STARTERS,
                WizardAnswers,
                build_wizard_spec,
                explain_harness,
                render_explanation,
                save_harness_spec,
            )
        except Exception as exc:
            log.add_error(f"Harness wizard is unavailable: {exc}")
            return

        try:
            tokens = shlex.split(args or "")
        except ValueError as exc:
            log.add_error(f"Could not parse :harness wizard arguments: {exc}")
            return

        if not tokens:
            self._start_harness_wizard_flow(log)
            return

        starter_keys = {key for key, _label in WIZARD_STARTERS}
        approval_keys = {key for key, _label in APPROVAL_PROFILES}
        tool_format_keys = {key for key, _label in TOOL_CALL_FORMATS}
        workflow_keys = {
            "single",
            "plan-implement-review",
            "fix-and-verify",
            "parallel-review",
            "security-review",
        }
        output = Path("harness.yaml")
        force = False
        load_after_write = False
        answers_kwargs: dict[str, Any] = {
            "name": "my-harness",
            "starter": "qwen-coding",
            "provider": "",
            "model": "",
            "allow_write": True,
            "allow_shell": True,
            "allow_network": False,
            "approval_profile": "balanced",
            "tool_call_format": "auto",
            "workflow_preset": "single",
        }

        def _require_value(index: int, flag: str) -> str:
            if index + 1 >= len(tokens) or tokens[index + 1].startswith("--"):
                raise ValueError(f"{flag} requires a value")
            return tokens[index + 1]

        i = 0
        positional: list[str] = []
        try:
            while i < len(tokens):
                token = tokens[i]
                if token in {"--help", "-h"}:
                    self._show_harness_wizard_help(log)
                    return
                if token in {"--starter", "-t"}:
                    answers_kwargs["starter"] = _require_value(i, token)
                    i += 2
                    continue
                if token in {"--output", "-o"}:
                    output = Path(_require_value(i, token)).expanduser()
                    i += 2
                    continue
                if token == "--provider":
                    answers_kwargs["provider"] = _require_value(i, token)
                    i += 2
                    continue
                if token == "--model":
                    answers_kwargs["model"] = _require_value(i, token)
                    i += 2
                    continue
                if token in {"--workflow", "--workflow-preset"}:
                    answers_kwargs["workflow_preset"] = _require_value(i, token)
                    i += 2
                    continue
                if token in {"--approval", "--approval-profile"}:
                    answers_kwargs["approval_profile"] = _require_value(i, token)
                    i += 2
                    continue
                if token in {"--tool-format", "--tool-call-format"}:
                    answers_kwargs["tool_call_format"] = _require_value(i, token)
                    i += 2
                    continue
                if token in {"--read-only", "--no-write"}:
                    answers_kwargs["allow_write"] = False
                    i += 1
                    continue
                if token == "--no-shell":
                    answers_kwargs["allow_shell"] = False
                    i += 1
                    continue
                if token == "--allow-network":
                    answers_kwargs["allow_network"] = True
                    i += 1
                    continue
                if token == "--no-network":
                    answers_kwargs["allow_network"] = False
                    i += 1
                    continue
                if token == "--force":
                    force = True
                    i += 1
                    continue
                if token == "--load":
                    load_after_write = True
                    i += 1
                    continue
                if token.startswith("-"):
                    raise ValueError(f"Unknown option {token}")
                positional.append(token)
                i += 1
        except ValueError as exc:
            log.add_error(str(exc))
            self._show_harness_wizard_help(log)
            return

        if positional:
            answers_kwargs["name"] = positional[0]
        if len(positional) > 1:
            log.add_error(f"Unexpected extra argument: {positional[1]}")
            self._show_harness_wizard_help(log)
            return

        if answers_kwargs["starter"] not in starter_keys:
            log.add_error(
                f"Unknown starter {answers_kwargs['starter']!r}. Try: {', '.join(sorted(starter_keys))}"
            )
            return
        if answers_kwargs["approval_profile"] not in approval_keys:
            log.add_error(
                f"Unknown approval profile {answers_kwargs['approval_profile']!r}. Try: {', '.join(sorted(approval_keys))}"
            )
            return
        if answers_kwargs["tool_call_format"] not in tool_format_keys:
            log.add_error(
                f"Unknown tool-call format {answers_kwargs['tool_call_format']!r}. Try: {', '.join(sorted(tool_format_keys))}"
            )
            return
        if answers_kwargs["workflow_preset"] not in workflow_keys:
            log.add_error(
                f"Unknown workflow {answers_kwargs['workflow_preset']!r}. Try: {', '.join(sorted(workflow_keys))}"
            )
            return

        if output.exists() and not force:
            log.add_error(f"{output} already exists. Add --force to overwrite it.")
            return

        try:
            answers = WizardAnswers(**answers_kwargs)
            spec = build_wizard_spec(answers)
            path = save_harness_spec(spec, output)
            (Path(".agents") / "skills").mkdir(parents=True, exist_ok=True)
            (Path(".agents") / "roles").mkdir(parents=True, exist_ok=True)
        except Exception as exc:
            log.add_error(f"Could not create harness: {exc}")
            return

        t = Text()
        t.append("\n  ▣ ", style=f"bold {THEME['purple']}")
        t.append("Harness Wizard\n\n", style=f"bold {THEME['text']}")
        t.append("  Wrote       ", style=THEME["muted"])
        t.append(str(path), style=f"bold {THEME['cyan']}")
        t.append("\n  Starter     ", style=THEME["muted"])
        t.append(answers.starter, style=THEME["text"])
        t.append("\n  Runtime     ", style=THEME["muted"])
        t.append(spec.runtime.backend, style=THEME["text"])
        t.append("\n  Model       ", style=THEME["muted"])
        t.append(spec.model_policy.primary or "active connection", style=THEME["text"])
        t.append("\n\n")
        explanation = render_explanation(
            explain_harness(spec, provider=answers.provider, model=answers.model)
        )
        for line in explanation.splitlines()[:18]:
            t.append("  ", style="")
            t.append(line, style=THEME["text"])
            t.append("\n")
        t.append("\n  Next        ", style=THEME["muted"])
        t.append(f":harness {path}", style=THEME["cyan"])
        t.append("  ", style="")
        t.append(f":harness doctor", style=THEME["cyan"])
        t.append("\n")
        self._show_command_output(log, t)

        if load_after_write:
            self._harness_cmd(f"load {path}", log)

    def _start_harness_wizard_flow(self, log) -> None:
        """Start the step-by-step HarnessSpec wizard in the TUI."""
        self._awaiting_harness_wizard = True
        self._harness_wizard_state = {
            "step": "name",
            "history": [],
            "answers": {
                "name": "my-harness",
                "starter": "qwen-coding",
                "provider": "",
                "model": "",
                "allow_write": True,
                "allow_shell": True,
                "allow_network": False,
                "approval_profile": "balanced",
                "tool_call_format": "auto",
                "workflow_preset": "single",
            },
            "output": self._default_harness_wizard_output(),
            "load": True,
            "force": False,
        }
        self._render_harness_wizard_step(log)

    def _handle_harness_wizard_input(self, text: str, log) -> bool:
        """Advance the guided HarnessSpec wizard."""
        state = getattr(self, "_harness_wizard_state", None)
        if not getattr(self, "_awaiting_harness_wizard", False) or not state:
            return False

        raw = (text or "").strip()
        lowered = raw.lower()
        if lowered in {"cancel", ":cancel", "/cancel", "quit", "exit"}:
            self._awaiting_harness_wizard = False
            self._harness_wizard_state = None
            log.add_info("Harness wizard cancelled.")
            return True
        if lowered in {"back", ":back", "/back"}:
            history = state.get("history", [])
            if history:
                state["step"] = history.pop()
            self._render_harness_wizard_step(log)
            return True

        step = state["step"]
        answers = state["answers"]

        try:
            if step == "name":
                if raw:
                    answers["name"] = raw
                self._harness_wizard_next(state, "starter")
            elif step == "starter":
                starter = self._harness_wizard_choice(
                    raw,
                    [key for key, _ in self._wizard_starters()],
                    default=str(answers.get("starter") or "qwen-coding"),
                )
                if starter is None:
                    log.add_error("Choose a starter by number or name.")
                    self._render_harness_wizard_step(log)
                    return True
                answers["starter"] = starter
                if starter == "no-tool":
                    answers["allow_write"] = False
                    answers["allow_shell"] = False
                self._harness_wizard_next(state, "provider")
            elif step == "provider":
                answers["provider"] = raw
                self._harness_wizard_next(state, "model")
            elif step == "model":
                answers["model"] = raw
                self._harness_wizard_next(state, "tools")
            elif step == "tools":
                choice = self._harness_wizard_choice(
                    raw,
                    ["full", "read-only", "no-shell", "no-tools"],
                    default="full",
                )
                if choice is None:
                    log.add_error("Choose tools by number or name.")
                    self._render_harness_wizard_step(log)
                    return True
                if choice == "full":
                    answers["allow_write"] = True
                    answers["allow_shell"] = True
                elif choice == "read-only":
                    answers["allow_write"] = False
                    answers["allow_shell"] = False
                elif choice == "no-shell":
                    answers["allow_write"] = True
                    answers["allow_shell"] = False
                elif choice == "no-tools":
                    answers["starter"] = "no-tool"
                    answers["allow_write"] = False
                    answers["allow_shell"] = False
                self._harness_wizard_next(state, "permissions")
            elif step == "permissions":
                choice = self._harness_wizard_choice(
                    raw,
                    ["balanced", "careful", "yolo", "balanced-network"],
                    default="balanced",
                )
                if choice is None:
                    log.add_error("Choose permissions by number or name.")
                    self._render_harness_wizard_step(log)
                    return True
                answers["allow_network"] = choice == "balanced-network"
                answers["approval_profile"] = "balanced" if choice == "balanced-network" else choice
                self._harness_wizard_next(state, "tool_format")
            elif step == "tool_format":
                choice = self._harness_wizard_choice(
                    raw,
                    ["auto", "native", "prompt"],
                    default="auto",
                )
                if choice is None:
                    log.add_error("Choose a tool-call format by number or name.")
                    self._render_harness_wizard_step(log)
                    return True
                answers["tool_call_format"] = choice
                self._harness_wizard_next(state, "workflow")
            elif step == "workflow":
                choice = self._harness_wizard_choice(
                    raw,
                    [
                        "single",
                        "plan-implement-review",
                        "fix-and-verify",
                        "parallel-review",
                        "security-review",
                    ],
                    default="single",
                )
                if choice is None:
                    log.add_error("Choose a workflow by number or name.")
                    self._render_harness_wizard_step(log)
                    return True
                answers["workflow_preset"] = choice
                self._harness_wizard_next(state, "output")
            elif step == "output":
                load_answer = self._parse_yes_no(raw) if raw else None
                if load_answer is not None:
                    state["load"] = load_answer
                    self._finish_harness_wizard_flow(log)
                    return True
                if raw:
                    state["output"] = raw
                self._harness_wizard_next(state, "load")
            elif step == "load":
                if raw:
                    load = self._parse_yes_no(raw)
                    if load is None:
                        log.add_error("Answer yes or no.")
                        self._render_harness_wizard_step(log)
                        return True
                    state["load"] = load
                self._finish_harness_wizard_flow(log)
                return True
            else:
                log.add_error("Harness wizard state was invalid; restarting.")
                self._start_harness_wizard_flow(log)
                return True
        except Exception as exc:
            log.add_error(f"Harness wizard failed: {exc}")
            self._awaiting_harness_wizard = False
            self._harness_wizard_state = None
            return True

        self._render_harness_wizard_step(log)
        return True

    @staticmethod
    def _harness_wizard_next(state: dict[str, Any], next_step: str) -> None:
        state.setdefault("history", []).append(state["step"])
        state["step"] = next_step

    @staticmethod
    def _default_harness_wizard_output() -> str:
        base = Path("harness.yaml")
        if not base.exists():
            return str(base)
        for index in range(2, 1000):
            candidate = Path(f"harness-{index}.yaml")
            if not candidate.exists():
                return str(candidate)
        return "harness-new.yaml"

    @staticmethod
    def _parse_yes_no(raw: str) -> bool | None:
        lowered = raw.strip().lower()
        if lowered in {"y", "yes", "true", "1"}:
            return True
        if lowered in {"n", "no", "false", "0"}:
            return False
        return None

    @staticmethod
    def _harness_wizard_choice(
        raw: str,
        keys: list[str],
        *,
        default: str | None = None,
    ) -> str | None:
        value = raw.strip().lower()
        if not value and default:
            return default
        if value.isdigit():
            index = int(value) - 1
            return keys[index] if 0 <= index < len(keys) else None
        for key in keys:
            if value == key.lower():
                return key
        matches = [key for key in keys if key.lower().startswith(value)]
        return matches[0] if len(matches) == 1 else None

    @staticmethod
    def _wizard_starters() -> tuple[tuple[str, str], ...]:
        from superqode.harness import WIZARD_STARTERS

        return WIZARD_STARTERS

    def _render_harness_wizard_step(self, log) -> None:
        state = getattr(self, "_harness_wizard_state", None)
        if not state:
            return
        step = state["step"]
        answers = state["answers"]
        t = Text()
        t.append("\n  ▣ ", style=f"bold {THEME['purple']}")
        t.append("Harness Wizard\n", style=f"bold {THEME['text']}")
        t.append("  Type ", style=THEME["muted"])
        t.append("back", style=THEME["cyan"])
        t.append(" or ", style=THEME["muted"])
        t.append("cancel", style=THEME["cyan"])
        t.append(" anytime. Press Enter for defaults.\n\n", style=THEME["muted"])

        if step == "name":
            t.append("  Step 1/9  Harness name\n", style=f"bold {THEME['cyan']}")
            t.append(f"  Default: {answers['name']}\n", style=THEME["muted"])
            t.append("  Example: my-coder\n", style=THEME["text"])
        elif step == "starter":
            t.append("  Step 2/9  Choose starting point\n", style=f"bold {THEME['cyan']}")
            for index, (key, label) in enumerate(self._wizard_starters(), 1):
                marker = " (default)" if key == answers["starter"] else ""
                t.append(f"  {index}. {key:<18} {label}{marker}\n", style=THEME["text"])
        elif step == "provider":
            t.append("  Step 3/9  Provider\n", style=f"bold {THEME['cyan']}")
            t.append("  Leave blank to keep the template default.\n", style=THEME["muted"])
            t.append(
                "  Examples: ollama, lmstudio, mlx, ds4, openai, anthropic\n", style=THEME["text"]
            )
        elif step == "model":
            t.append("  Step 4/9  Model\n", style=f"bold {THEME['cyan']}")
            t.append("  Leave blank to keep the template model.\n", style=THEME["muted"])
            t.append("  Example: qwen3-coder\n", style=THEME["text"])
        elif step == "tools":
            t.append("  Step 5/9  Tools\n", style=f"bold {THEME['cyan']}")
            options = (
                ("full", "file read/edit, search, shell, todos"),
                ("read-only", "read/search/review only"),
                ("no-shell", "file edits allowed, shell blocked"),
                ("no-tools", "model-only reasoning/review"),
            )
            for index, (key, label) in enumerate(options, 1):
                default = " (default)" if key == "full" else ""
                t.append(f"  {index}. {key:<10} {label}{default}\n", style=THEME["text"])
        elif step == "permissions":
            t.append("  Step 6/9  Permissions\n", style=f"bold {THEME['cyan']}")
            options = (
                ("balanced", "auto safe reads/searches; ask before writes and shell"),
                ("careful", "ask before most actions"),
                ("yolo", "auto-approve actions allowed by the harness"),
                ("balanced-network", "balanced approvals plus network access"),
            )
            for index, (key, label) in enumerate(options, 1):
                default = " (default)" if key == "balanced" else ""
                t.append(f"  {index}. {key:<18} {label}{default}\n", style=THEME["text"])
        elif step == "tool_format":
            t.append("  Step 7/9  Tool-call format\n", style=f"bold {THEME['cyan']}")
            for index, (key, label) in enumerate(
                (
                    ("auto", "use template/runtime default"),
                    ("native", "model-native tool calling"),
                    ("prompt", "prompt-described tools for weaker local models"),
                ),
                1,
            ):
                default = " (default)" if key == "auto" else ""
                t.append(f"  {index}. {key:<8} {label}{default}\n", style=THEME["text"])
        elif step == "workflow":
            t.append("  Step 8/9  Workflow\n", style=f"bold {THEME['cyan']}")
            options = (
                ("single", "one agent handles the task"),
                ("plan-implement-review", "planner, implementer, reviewer chain"),
                ("fix-and-verify", "fix then verify with checks"),
                ("parallel-review", "multiple reviewers in parallel"),
                ("security-review", "security-focused review chain"),
            )
            for index, (key, label) in enumerate(options, 1):
                default = " (default)" if key == "single" else ""
                t.append(f"  {index}. {key:<22} {label}{default}\n", style=THEME["text"])
        elif step == "output":
            t.append("  Step 9/10  Output file\n", style=f"bold {THEME['cyan']}")
            t.append(f"  Default: {state['output']}\n", style=THEME["muted"])
            t.append("  Example: harness.yaml\n", style=THEME["text"])
        elif step == "load":
            t.append("  Step 10/10  Load this harness now?\n", style=f"bold {THEME['cyan']}")
            t.append("  Default: yes\n", style=THEME["muted"])
            t.append("  Answer: yes or no\n", style=THEME["text"])

        self._show_command_output(log, t)

    def _finish_harness_wizard_flow(self, log) -> None:
        state = getattr(self, "_harness_wizard_state", None)
        if not state:
            return
        answers_kwargs = dict(state["answers"])
        output = Path(state["output"]).expanduser()
        load_after_write = bool(state.get("load", True))

        if output.exists() and not state.get("force", False):
            state["output"] = self._default_harness_wizard_output()
            log.add_error(
                f"{output} already exists. Suggested next available path: {state['output']}"
            )
            state["step"] = "output"
            self._render_harness_wizard_step(log)
            return

        try:
            from superqode.harness import (
                WizardAnswers,
                build_wizard_spec,
                explain_harness,
                render_explanation,
                save_harness_spec,
            )

            answers = WizardAnswers(**answers_kwargs)
            spec = build_wizard_spec(answers)
            path = save_harness_spec(spec, output)
            (Path(".agents") / "skills").mkdir(parents=True, exist_ok=True)
            (Path(".agents") / "roles").mkdir(parents=True, exist_ok=True)
        except Exception as exc:
            log.add_error(f"Could not create harness: {exc}")
            self._awaiting_harness_wizard = False
            self._harness_wizard_state = None
            return

        self._awaiting_harness_wizard = False
        self._harness_wizard_state = None

        t = Text()
        t.append("\n  ▣ ", style=f"bold {THEME['purple']}")
        t.append("Harness Created\n\n", style=f"bold {THEME['text']}")
        t.append("  Wrote       ", style=THEME["muted"])
        t.append(str(path), style=f"bold {THEME['cyan']}")
        t.append("\n  Name        ", style=THEME["muted"])
        t.append(spec.name, style=THEME["text"])
        t.append("\n  Runtime     ", style=THEME["muted"])
        t.append(spec.runtime.backend, style=THEME["text"])
        t.append("\n  Model       ", style=THEME["muted"])
        t.append(spec.model_policy.primary or "active connection", style=THEME["text"])
        t.append("\n\n")
        explanation = render_explanation(
            explain_harness(
                spec,
                provider=answers.provider,
                model=answers.model,
            )
        )
        for line in explanation.splitlines()[:14]:
            t.append("  ", style="")
            t.append(line, style=THEME["text"])
            t.append("\n")
        t.append("\n  Next        ", style=THEME["muted"])
        t.append(f":harness {path}", style=THEME["cyan"])
        t.append("  ", style="")
        t.append(":harness doctor", style=THEME["cyan"])
        t.append("\n")
        self._show_command_output(log, t)

        if load_after_write:
            self._harness_cmd(f"load {path}", log)

    def _show_harness_wizard_help(self, log) -> None:
        t = Text()
        t.append("\n  ▣ ", style=f"bold {THEME['purple']}")
        t.append("Harness Wizard Usage\n\n", style=f"bold {THEME['text']}")
        t.append("  :harness wizard [name] [options]\n\n", style=THEME["cyan"])
        t.append("  Common:\n", style=f"bold {THEME['text']}")
        t.append(
            "    :harness wizard my-coder --starter qwen-coding --output harness.yaml --load\n",
            style=THEME["text"],
        )
        t.append(
            "    :harness wizard reviewer --starter no-tool --output reviewer.yaml\n",
            style=THEME["text"],
        )
        t.append("\n  Options:\n", style=f"bold {THEME['text']}")
        for line in (
            "--starter/-t <template>",
            "--output/-o <path>",
            "--provider <id> --model <id>",
            "--workflow <single|plan-implement-review|fix-and-verify|parallel-review|security-review>",
            "--approval <balanced|careful|yolo>",
            "--tool-format <auto|native|prompt>",
            "--read-only, --no-shell, --allow-network",
            "--force, --load",
        ):
            t.append("    " + line + "\n", style=THEME["text"])
        self._show_command_output(log, t)

    def _show_harness_inspect(self, log) -> None:
        """Show a readable summary for the active HarnessSpec."""
        spec, path = self._active_harness_spec()
        if spec is None:
            log.add_error("No HarnessSpec is active. Load one with :harness <spec.yaml>.")
            return
        try:
            from superqode.harness import inspect_harness
        except Exception as exc:
            log.add_error(f"Harness inspect is unavailable: {exc}")
            return
        summary = inspect_harness(spec)
        workflow = summary["workflow"]
        permissions = summary["permissions"]
        t = Text()
        t.append("\n  ▣ ", style=f"bold {THEME['purple']}")
        t.append("Harness Inspect\n\n", style=f"bold {THEME['text']}")
        t.append("  Name        ", style=THEME["muted"])
        t.append(f"{summary['name']} v{summary['version']}", style=f"bold {THEME['cyan']}")
        t.append(f"  {summary['flavor']}\n", style=THEME["dim"])
        if summary["description"]:
            t.append("  Summary     ", style=THEME["muted"])
            t.append(summary["description"], style=THEME["text"])
            t.append("\n")
        if path:
            t.append("  Spec        ", style=THEME["muted"])
            t.append(path, style=THEME["dim"])
            t.append("\n")
        t.append("  Runtime     ", style=THEME["muted"])
        t.append(summary["runtime"]["backend"], style=THEME["text"])
        t.append("\n  Workflow    ", style=THEME["muted"])
        t.append(workflow["mode"], style=f"bold {THEME['success']}")
        if workflow["preset"]:
            t.append(f"  preset={workflow['preset']}", style=THEME["dim"])
        t.append(f"  parallelism={workflow['parallelism']}\n", style=THEME["dim"])
        t.append("  Model       ", style=THEME["muted"])
        t.append(summary["model_policy"]["primary"] or "active connection", style=THEME["text"])
        t.append("\n  Permissions ", style=THEME["muted"])
        t.append(
            f"read={permissions['allow_read']} write={permissions['allow_write']} shell={permissions['allow_shell']} network={permissions['allow_network']}",
            style=THEME["text"],
        )
        t.append(f"  approvals={permissions['approval_profile']}\n", style=THEME["dim"])
        t.append("  Tools       ", style=THEME["muted"])
        t.append(", ".join(summary["tools"]) if summary["tools"] else "-", style=THEME["text"])
        t.append("\n  Skills      ", style=THEME["muted"])
        t.append(", ".join(summary["skills"]) if summary["skills"] else "-", style=THEME["text"])
        t.append("\n  MCP         ", style=THEME["muted"])
        t.append(
            ", ".join(summary["mcp"]["servers"]) if summary["mcp"]["servers"] else "none declared",
            style=THEME["text"],
        )
        t.append("\n  Checks  ", style=THEME["muted"])
        t.append("enabled" if summary["checks"]["enabled"] else "disabled", style=THEME["text"])
        t.append("\n  Run store   ", style=THEME["muted"])
        t.append(summary["observability"]["run_store"], style=THEME["text"])

        t.append("\n\n  Agents\n", style=f"bold {THEME['text']}")
        for agent in summary["agents"]:
            t.append("  - ", style=THEME["dim"])
            t.append(agent["id"], style=f"bold {THEME['cyan']}")
            if agent["role"]:
                t.append(f"  {agent['role']}", style=THEME["muted"])
            if agent["model"]:
                t.append(f"  model={agent['model']}", style=THEME["dim"])
            t.append("\n")
        if not summary["agents"]:
            t.append("  - prompt step generated from run input\n", style=THEME["muted"])
        t.append("\n  Next        ", style=THEME["muted"])
        t.append(":harness doctor", style=THEME["cyan"])
        t.append("  ", style="")
        t.append(":harness graph", style=THEME["cyan"])
        t.append("\n")
        self._show_command_output(log, t)

    def _show_harness_doctor(self, log) -> None:
        """Show active HarnessSpec readiness checks."""
        spec, _path = self._active_harness_spec()
        if spec is None:
            log.add_error("No HarnessSpec is active. Load one with :harness <spec.yaml>.")
            return
        try:
            from superqode.harness import doctor_harness
        except Exception as exc:
            log.add_error(f"Harness doctor is unavailable: {exc}")
            return
        report = doctor_harness(spec)
        status_style = (
            THEME["error"]
            if report.status == "error"
            else THEME["warning"]
            if report.status == "warning"
            else THEME["success"]
        )
        t = Text()
        t.append("\n  ▣ ", style=f"bold {THEME['purple']}")
        t.append("Harness Doctor\n\n", style=f"bold {THEME['text']}")
        t.append("  Harness     ", style=THEME["muted"])
        t.append(report.name, style=f"bold {THEME['cyan']}")
        t.append("\n  Status      ", style=THEME["muted"])
        t.append(report.status, style=f"bold {status_style}")
        t.append("\n\n  Checks\n", style=f"bold {THEME['text']}")
        for check in report.checks:
            style = (
                THEME["error"]
                if check.status == "error"
                else THEME["warning"]
                if check.status == "warning"
                else THEME["success"]
            )
            icon = "!" if check.status == "error" else "!" if check.status == "warning" else "✓"
            t.append(f"  {icon} ", style=style)
            t.append(f"{check.name:<14}", style=f"bold {style}")
            t.append(check.message, style=THEME["text"])
            if check.data.get("missing"):
                t.append(f"  missing: {', '.join(check.data['missing'])}", style=THEME["muted"])
            t.append("\n")
        self._show_command_output(log, t)

    def _show_harness_graph(self, log, run_id: str = "") -> None:
        """Show the planned graph or a persisted actual graph."""
        spec, _path = self._active_harness_spec()
        if spec is None:
            log.add_error("No HarnessSpec is active. Load one with :harness <spec.yaml>.")
            return
        try:
            from superqode.harness import FileHarnessStore, plan_harness_graph, render_harness_graph
        except Exception as exc:
            log.add_error(f"Harness graph is unavailable: {exc}")
            return
        run_id = run_id.strip()
        if run_id:
            try:
                graph = FileHarnessStore(Path(spec.context.session_storage)).get_event_graph(run_id)
            except Exception as exc:
                log.add_error(f"Could not load harness graph for {run_id}: {exc}")
                return
            title = f"Harness Graph  {run_id}"
            graph_note = "This is the persisted actual event graph."
        else:
            graph = plan_harness_graph(spec)
            title = "Harness Graph"
            graph_note = "This is the planned graph. Completed runs persist the actual event graph."
        graph_text = render_harness_graph(graph)
        t = Text()
        t.append("\n  ▣ ", style=f"bold {THEME['purple']}")
        t.append(title + "\n\n", style=f"bold {THEME['text']}")
        for line in graph_text.splitlines():
            t.append("  ", style="")
            t.append(line, style=THEME["cyan"] if "->" in line else THEME["text"])
            t.append("\n")
        t.append(f"\n  {graph_note}\n", style=THEME["muted"])
        self._show_command_output(log, t)

    def _show_harness_runs(self, log) -> None:
        """Show recent persisted harness runs."""
        spec, _path = self._active_harness_spec()
        if spec is None:
            log.add_error("No HarnessSpec is active. Load one with :harness <spec.yaml>.")
            return
        try:
            from superqode.harness import FileHarnessStore
        except Exception as exc:
            log.add_error(f"Harness runs are unavailable: {exc}")
            return
        runs = FileHarnessStore(Path(spec.context.session_storage)).list_runs()
        t = Text()
        t.append("\n  ▣ ", style=f"bold {THEME['purple']}")
        t.append("Harness Runs\n\n", style=f"bold {THEME['text']}")
        if not runs:
            t.append("  No persisted harness runs found.\n", style=THEME["muted"])
            self._show_command_output(log, t)
            return
        for run in runs[:12]:
            t.append("  ", style="")
            t.append(run.run_id, style=f"bold {THEME['cyan']}")
            t.append(
                f"  {run.status}",
                style=THEME["success"] if run.status == "succeeded" else THEME["warning"],
            )
            if run.metadata.get("workflow"):
                t.append("  workflow", style=THEME["purple"])
            t.append(f"  {run.prompt_preview}\n", style=THEME["muted"])
        t.append("\n  Inspect graph with ", style=THEME["muted"])
        t.append(":harness graph <run_id>\n", style=THEME["cyan"])
        self._show_command_output(log, t)

    def _show_harness_evidence(self, log, run_id: str) -> None:
        """Show a readable evidence report for a persisted harness run."""
        spec, _path = self._active_harness_spec()
        if spec is None:
            log.add_error("No HarnessSpec is active. Load one with :harness <spec.yaml>.")
            return
        try:
            from superqode.harness import FileHarnessStore, build_harness_evidence
        except Exception as exc:
            log.add_error(f"Harness evidence is unavailable: {exc}")
            return
        try:
            evidence = build_harness_evidence(
                FileHarnessStore(Path(spec.context.session_storage)),
                run_id.strip(),
            )
        except Exception as exc:
            log.add_error(f"Could not load harness evidence for {run_id}: {exc}")
            return
        run = evidence["run"]
        workflow = evidence["workflow"]
        changes = evidence["changes"] if isinstance(evidence["changes"], dict) else {}
        checks = evidence["checks"] if isinstance(evidence["checks"], dict) else {}
        result = evidence["result"]
        t = Text()
        t.append("\n  ▣ ", style=f"bold {THEME['purple']}")
        t.append("Harness Evidence\n\n", style=f"bold {THEME['text']}")
        t.append("  Run         ", style=THEME["muted"])
        t.append(run["run_id"], style=f"bold {THEME['cyan']}")
        t.append(
            f"  {run['status']}\n",
            style=THEME["success"] if run["status"] == "succeeded" else THEME["warning"],
        )
        t.append("  Harness     ", style=THEME["muted"])
        t.append(f"{run['harness']}  {run['runtime']}", style=THEME["text"])
        t.append("\n  Model       ", style=THEME["muted"])
        t.append(f"{run['provider']}/{run['model']}", style=THEME["text"])
        if workflow.get("mode"):
            t.append("\n  Workflow    ", style=THEME["muted"])
            t.append(str(workflow["mode"]), style=THEME["text"])
        t.append("\n\n  Steps\n", style=f"bold {THEME['text']}")
        for step in workflow.get("completed_steps") or []:
            t.append("  ✓ ", style=THEME["success"])
            t.append(str(step.get("step_id") or "-"), style=f"bold {THEME['cyan']}")
            if step.get("child_run_id"):
                t.append(f"  {step['child_run_id']}", style=THEME["dim"])
            if step.get("detail"):
                t.append(f"  {step['detail']}", style=THEME["muted"])
            t.append("\n")
        for step in workflow.get("failed_steps") or []:
            t.append("  ! ", style=THEME["error"])
            t.append(str(step.get("step_id") or "-"), style=f"bold {THEME['error']}")
            if step.get("detail"):
                t.append(f"  {step['detail']}", style=THEME["muted"])
            t.append("\n")
        file_count = int(changes.get("file_count") or 0)
        t.append("\n  Changes     ", style=THEME["muted"])
        t.append(
            f"{file_count} file(s) (+{int(changes.get('additions') or 0)} -{int(changes.get('deletions') or 0)})",
            style=THEME["text"],
        )
        t.append("\n  Checks  ", style=THEME["muted"])
        t.append(str(checks.get("status") or "unknown"), style=THEME["text"])
        t.append(f"  {len(checks.get('steps') or [])} step(s)", style=THEME["dim"])
        t.append("\n  Approvals   ", style=THEME["muted"])
        t.append(f"{len(evidence.get('approvals') or [])} event(s)", style=THEME["text"])
        t.append("\n  Result      ", style=THEME["muted"])
        t.append(str(result.get("status") or run["status"]), style=THEME["text"])
        if result.get("content_preview"):
            t.append("\n\n", style="")
            t.append(str(result["content_preview"]), style=THEME["text"])
        t.append("\n\n  Next        ", style=THEME["muted"])
        t.append(f":harness graph {run['run_id']}", style=THEME["cyan"])
        t.append("  ", style="")
        t.append(f":harness events {run['run_id']}", style=THEME["cyan"])
        t.append("\n")
        self._show_command_output(log, t)

