    def _show_final_response(
        self, response_text: str, name: str, duration: float, log: ConversationLog
    ):
        """Show the final response with proper formatting and word wrapping."""
        # Store the response for :copy command
        self._last_response = response_text

        # Header separator
        sep = Text()
        sep.append("\n")
        sep.append("  ━" * 30 + "\n", style="#a855f7")
        sep.append(f"  ✅ {name} ", style="bold #22c55e")
        sep.append(f"completed in {duration:.1f}s\n", style="#71717a")
        sep.append("  ━" * 30 + "\n", style="#a855f7")
        log.write(sep)

        if response_text.strip():
            log.write_final_response(
                response_text, agent=name, success=True, trailing_newline=False
            )

        # Simple footer line (no copy/open hints for cleaner UX)
        footer = Text()
        footer.append("\n", style="")
        log.write(footer)

    # Keep old method name for compatibility
    def _show_beautiful_response(
        self,
        response_text: str,
        name: str,
        duration: float,
        thinking_count: int,
        log: ConversationLog,
    ):
        """Alias for _show_final_response."""
        self._show_final_response(response_text, name, duration, log)

    def _format_tool_message_rich(self, tool_name: str, tool_input: dict) -> str:
        """Format a tool use message as a single compact line.

        Style: `<icon> <target>` - icon conveys the action, target shows what
        is being acted on. Paths are made relative to cwd. No "Reading:" /
        "Modifying:" labels because the icon already says so.
        """
        tool_lower = tool_name.lower()

        tool_icons = {
            "read": "↳",
            "write": "↲",
            "edit": "⟳",
            "patch": "⟳",
            "bash": "▸",
            "shell": "▸",
            "terminal": "▸",
            "exec": "▸",
            "run": "▸",
            "search": "⌕",
            "grep": "⌕",
            "find": "⌕",
            "glob": "⋮",
            "list": "⋮",
            "ls": "⋮",
            "tree": "⋮",
            "git": "◎",
            "fetch": "◎",
            "web": "◎",
            "http": "◎",
            "create": "↲",
            "mkdir": "⋮",
            "delete": "✕",
            "rm": "✕",
        }
        icon = "•"
        for key, ic in tool_icons.items():
            if key in tool_lower:
                icon = ic
                break

        def _relpath(p: str) -> str:
            if not p:
                return p
            try:
                if os.path.isabs(p):
                    rel = os.path.relpath(p, os.getcwd())
                    if not rel.startswith(".."):
                        return rel
            except Exception:
                pass
            return p

        def _first_arg(*keys: str) -> str:
            for key in keys:
                value = tool_input.get(key)
                if isinstance(value, str) and value.strip():
                    return value.strip()
            return ""

        # Cover snake_case and camelCase: harness tools, ACP agents, and the
        # codex-sdk runtime all spell these keys differently.
        file_path = _relpath(
            _first_arg(
                "filePath", "file_path", "path", "file", "abs_path", "filename", "target_file"
            )
        )

        # Substring matching ("read_file", "Read file", "edit" all count as reads/
        # edits); exact-name matching left every external agent in the generic branch.
        def _matches(*fragments: str) -> bool:
            return any(fragment in tool_lower for fragment in fragments)

        if _matches("read", "write", "edit", "patch", "create") and file_path:
            return f"{icon} {file_path}"
        if _matches("bash", "shell", "terminal", "exec", "command", "run"):
            cmd = _first_arg("command", "cmd", "script")
            if cmd:
                return f"{icon} {cmd}"
        if _matches("search", "grep", "find"):
            query = _first_arg("pattern", "query", "search", "regex")
            if query:
                return f"{icon} {query}"
        if _matches("list", "ls", "glob", "tree"):
            path = _relpath(_first_arg("path", "directory", "dir_path"))
            if path:
                return f"{icon} {path}"
        if tool_lower == "todo_write":
            todos = tool_input.get("todos", [])
            return f"{icon} todo list ({len(todos)} items)"
        if _matches("fetch", "web", "http"):
            url = _first_arg("url", "uri")
            if url:
                return f"{icon} {url}"
        if file_path:
            return f"{icon} {tool_name} {file_path}"

        # Generic: show a short hint of the first argument value, not full JSON.
        if tool_input:
            first_key = next(iter(tool_input), None)
            if first_key:
                val_str = str(tool_input[first_key])
                if len(val_str) > 80:
                    val_str = val_str[:77] + "…"
                return f"{icon} {tool_name} {val_str}"
        return f"{icon} {tool_name}"

    def _write_collapsed_changes_line(
        self, log: ConversationLog, files_modified: list, file_diffs: dict
    ) -> None:
        """One muted line for file changes, hidden details, expandable on demand.

        The full file panel and inline diffs are intentionally not printed; the
        user opens them with ``:diff`` (working tree) or ``:work verbose``
        (inline in the transcript).
        """
        count = len(files_modified)
        total_add = sum(d.get("additions", 0) for d in file_diffs.values())
        total_del = sum(d.get("deletions", 0) for d in file_diffs.values())
        line = Text()
        line.append("  ▸ ", style=f"bold {SQ_COLORS.info}")
        label = f"{count} file{'s' if count != 1 else ''} changed"
        if total_add or total_del:
            label += f" (+{total_add}/-{total_del})"
        line.append(label, style=SQ_COLORS.text_secondary)
        line.append("  ·  ", style=SQ_COLORS.text_muted)
        line.append(":diff", style=f"bold {SQ_COLORS.info}")
        line.append(" to view  ·  ", style=SQ_COLORS.text_muted)
        line.append(":work verbose", style=f"bold {SQ_COLORS.info}")
        line.append(" for inline diffs\n", style=SQ_COLORS.text_muted)
        log.write(line)

    def _show_final_outcome(
        self, response_text: str, name: str, summary: dict, log: ConversationLog
    ):
        """Show a compact final outcome with the answer first."""
        # Store the response for :copy command
        log._last_response = response_text
        self._last_response = response_text

        duration = summary.get("duration", 0)
        tool_count = summary.get("tool_count", 0)
        files_modified = summary.get("files_modified", [])
        files_read = summary.get("files_read", [])
        file_diffs = summary.get("file_diffs", {})  # NEW: Get diff data

        # Only report files this turn actually changed (tracked by the agent).
        # We intentionally do NOT fall back to the ambient git working tree:
        # a simple question that edits nothing should show no change block,
        # even when the repo already has unrelated uncommitted edits. Use
        # ``:diff`` or the Changes sidebar to inspect the full working tree.

        # Keep prior turns in the log so users can scroll back through the
        # whole conversation (PgUp/PgDn). Instead of wiping the view each turn,
        # divide completed turns with a subtle separator.
        log.auto_scroll = True
        separator = Text()
        separator.append("\n")
        separator.append("  " + "─" * 44 + "\n", style=SQ_COLORS.text_muted)
        log.write(separator)

        header = Text()
        header.append("  Done", style=f"bold {SQ_COLORS.success}")
        header.append("  •  ", style=SQ_COLORS.text_muted)
        header.append(name, style=f"bold {SQ_COLORS.text_primary}")

        total_additions = sum(d.get("additions", 0) for d in file_diffs.values())
        total_deletions = sum(d.get("deletions", 0) for d in file_diffs.values())

        facts = [f"{duration:.1f}s"]
        if tool_count > 0:
            facts.append(f"{tool_count} tools")
        if files_read:
            facts.append(f"{len(files_read)} read")
        if files_modified:
            change_label = f"{len(files_modified)} changed"
            if total_additions > 0 or total_deletions > 0:
                change_label += f" (+{total_additions}/-{total_deletions})"
            facts.append(change_label)
        header.append("  •  ", style=SQ_COLORS.text_muted)
        header.append("  •  ".join(facts), style=SQ_COLORS.text_muted)
        header.append("\n\n")

        log.write(header)

        if response_text.strip():
            log.write_final_response(response_text, agent=name, success=True)

        # File changes are HIDDEN by default: a turn shows only a one-line
        # summary the user can expand. The full file panel and inline diffs
        # appear only in verbose mode (``:work verbose``); ``:diff`` opens the
        # changes on demand. This keeps simple turns from dumping a diff block.
        change_mode = getattr(log, "tool_output_mode", "normal")
        if files_modified and change_mode == "verbose":
            from superqode.widgets.response_changes import (
                render_file_changes_section,
                render_inline_file_diffs,
            )
            from rich.console import Console
            from io import StringIO

            changes_section = render_file_changes_section(files_modified, file_diffs, max_files=10)
            console = Console(file=StringIO(), width=120, legacy_windows=False)
            console.print(changes_section)
            inline_diffs = render_inline_file_diffs(files_modified, file_diffs, max_files=10)
            console.print(inline_diffs)
            log.write(console.file.getvalue())
        elif files_modified:
            # Collapsed one-liner (normal and minimal modes).
            self._write_collapsed_changes_line(log, files_modified, file_diffs)

        footer = Text()
        footer.append("  Actions: ", style=SQ_COLORS.text_muted)
        footer.append(":work", style=f"bold {SQ_COLORS.info}")
        footer.append(" summary", style=SQ_COLORS.text_muted)
        if files_modified:
            footer.append("  •  ", style=SQ_COLORS.text_muted)
            footer.append(":diff", style=f"bold {SQ_COLORS.info}")
            footer.append(" changes", style=SQ_COLORS.text_muted)
            footer.append("  •  ", style=SQ_COLORS.text_muted)
            footer.append(":undo", style=f"bold {SQ_COLORS.info}")
        footer.append("  •  ", style=SQ_COLORS.text_muted)
        footer.append(":select response", style=f"bold {SQ_COLORS.info}")
        footer.append("\n", style=SQ_COLORS.text_muted)
        log.write(footer)

        # NEW: Trigger sidebar auto-navigation if files were modified
        if files_modified:
            self.set_timer(0.2, lambda: self._navigate_to_sidebar_changes(files_modified))

        # Keep the view pinned to the latest response. We no longer clear the
        # log each turn, so scrolling home would jump away from the answer the
        # user just asked for — scroll to the end and resume follow mode.
        log.auto_scroll = True
        self.set_timer(0.1, lambda: log.scroll_end(animate=False))

    def _show_completion_summary(self, name: str, summary: dict, log: ConversationLog):
        """Show completion summary when there's no text response."""
        from superqode.widgets.response_changes import (
            render_file_changes_compact,
            render_file_changes_section,
        )

        duration = summary.get("duration", 0)
        tool_count = summary.get("tool_count", 0)
        files_modified = summary.get("files_modified", [])
        files_read = summary.get("files_read", [])
        file_diffs = summary.get("file_diffs", {})  # NEW: Get diff data

        # Only report files this turn actually changed (no ambient git-tree
        # fallback); see _show_final_outcome for the rationale.

        # Disable auto-scroll
        log.auto_scroll = False

        # Clear and show fresh summary
        log.clear()

        t = Text()
        t.append("\n\n")

        # Celebration header
        celebration = "═" * 50
        gradient = ["#22c55e", "#10b981", "#14b8a6", "#06b6d4"]
        for i, char in enumerate(celebration):
            t.append(char, style=gradient[i % len(gradient)])
        t.append("\n")
        t.append("     🎉 ", style="#fbbf24")
        t.append("DONE!", style="bold #22c55e")
        t.append(" 🎉\n", style="#fbbf24")
        for i, char in enumerate(celebration):
            t.append(char, style=gradient[i % len(gradient)])
        t.append("\n\n")

        # Stats
        t.append(f"  ⏱️ Completed in {duration:.1f}s\n", style="#71717a")

        if tool_count > 0:
            t.append(f"  ⚡ {tool_count} tools executed\n", style="#a855f7")

        # NEW: Show file changes with visual indicators
        if files_modified:
            changes_text = render_file_changes_compact(files_modified, file_diffs)
            t.append_text(changes_text)
        elif files_read:
            t.append(f"  📖 {len(files_read)} files analyzed\n", style="#06b6d4")

        t.append("\n", style="")
        log.write(t)

        # Hidden by default: full file panel + inline diffs only in verbose
        # mode; otherwise a single collapsed line (the compact summary above
        # in ``t`` already names the count).
        change_mode = getattr(log, "tool_output_mode", "normal")
        if files_modified and change_mode == "verbose":
            from rich.console import Console
            from io import StringIO
            from superqode.widgets.response_changes import render_inline_file_diffs

            changes_section = render_file_changes_section(files_modified, file_diffs, max_files=10)
            console = Console(file=StringIO(), width=120, legacy_windows=False)
            console.print(changes_section)
            inline_diffs = render_inline_file_diffs(files_modified, file_diffs, max_files=10)
            console.print(inline_diffs)
            log.write(console.file.getvalue())
        elif files_modified:
            self._write_collapsed_changes_line(log, files_modified, file_diffs)

        # NEW: Trigger sidebar auto-navigation if files were modified
        if files_modified:
            self.set_timer(0.2, lambda: self._navigate_to_sidebar_changes(files_modified))

        # Schedule scroll to top with a small delay to ensure content is rendered
        self.set_timer(0.1, lambda: log.scroll_home())

    def _go_home(self, log: ConversationLog):
        # First, cancel any running agent process
        if self._agent_process is not None:
            self._cancel_requested = True
            try:
                self._agent_process.terminate()
                log.add_info("🛑 Agent process terminated")
            except Exception:
                pass
            self._agent_process = None

        # Stop ACP client if running
        if self._acp_client is not None:
            try:
                if self._acp_loop_runner is not None:
                    self._acp_loop_runner.run(self._acp_client.stop())
                else:
                    asyncio.create_task(self._acp_client.stop())
            except Exception:
                pass
            self._acp_client = None
            self._acp_client_key = None

        # Stop any animations
        self._stop_thinking()
        self._stop_stream_animation()
        self.is_busy = False

        # Reset session tracking for conversation continuity
        self._is_first_message = True
        self._opencode_session_id = None
        approved_tools = self._ensure_approved_tools()
        approved_tools.clear()  # Clear approved tools for new session
        self._pending_tool_name = None
        self._pending_tool_input = None
        self._tool_id_map = {}  # Clear tool tracking for new session

        session = get_session()

        if session.is_connected_to_agent():
            session.disconnect_agent()

        self.current_mode = "home"
        self.current_role = ""
        self.current_agent = ""
        self.current_model = ""
        self.current_provider = ""
        set_mode("home")
        session.state = "superqode"
        session.execution_mode = "acp"  # Reset execution mode

        badge = self.query_one("#mode-badge", ModeBadge)
        badge.mode = "home"
        badge.role = ""
        badge.agent = ""
        badge.model = ""
        badge.provider = ""
        badge.execution_mode = ""

        # Clear and show homepage
        self.action_clear_screen()

    def _reset_mode_badge_after_role_run(self):
        """Reset mode badge to HOME after a role run completes."""
        try:
            badge = self.query_one("#mode-badge", ModeBadge)
            badge.mode = "home"
            badge.role = ""
            badge.agent = ""
            badge.model = ""
            badge.provider = ""
            badge.execution_mode = ""
        except Exception:
            pass  # Silently fail if badge not found

    # ========================================================================
    # Provider session commands
    # ========================================================================

    def _connect_pure_mode(self, provider: str, model: str, level, log: ConversationLog):
        """Connect to provider session with specified provider/model."""
        from superqode.pure_mode import PureMode
        from superqode.tools.base import ToolResult

        if not hasattr(self, "_pure_mode"):
            self._pure_mode = PureMode()

        # Set up callbacks for tool calls
        def on_tool_call(name: str, args: dict):
            self._call_ui(self._show_pure_tool_call, name, args, log)

        def on_tool_result(name: str, result: ToolResult):
            self._call_ui(self._show_pure_tool_result, name, result, log)

        self._pure_mode.on_tool_call = on_tool_call
        self._pure_mode.on_tool_result = on_tool_result
        self._install_pure_permission_bridge(self._pure_mode, log)

        # Connect
        self._pure_mode.connect(provider, model, level)

        # Update state
        session = get_session()
        session.execution_mode = "pure"

        self.current_mode = "pure"
        self.current_agent = "pure"
        self.current_model = model
        self.current_provider = provider

        # Update badge
        badge = self.query_one("#mode-badge", ModeBadge)
        badge.mode = "pure"
        badge.agent = ""
        badge.model = model
        badge.provider = provider
        badge.execution_mode = "pure"

        # Clear screen and show fresh workspace
        self._clear_for_workspace(log, f"PURE • {provider}")

    def _show_pure_tool_call(self, name: str, args: dict, log: ConversationLog):
        """Show Pure/BYOK/local tool calls through the shared tool renderer."""
        # Calm mode: surface the action in the live throbber, not a full row.
        if self._is_calm_output():
            self._calm_tool_running(name, args, log)
            return
        file_path = args.get("path", args.get("file_path", args.get("filePath", "")))
        command = args.get("command", "")
        log.add_tool_call(name, "running", file_path, command, "", args)

    def _show_pure_tool_result(self, name: str, result, log: ConversationLog):
        """Show Pure/BYOK/local tool results through the shared tool renderer."""
        success = bool(getattr(result, "success", False))
        # Calm mode: one tidy line per finished tool, no raw output/diff.
        if self._is_calm_output():
            metadata = getattr(result, "metadata", None) or {}
            args = {"path": metadata.get("path")} if metadata.get("path") else {}
            self._calm_tool_done(name, args, log, ok=success)
            return
        status = "success" if success else "error"
        output = getattr(result, "output", "") if success else getattr(result, "error", "")
        output_str = str(output) if output else ""
        metadata = getattr(result, "metadata", None) or {}
        file_path = str(metadata.get("path") or "")
        diff_text = str(metadata.get("diff_text") or "")
        additions = metadata.get("additions")
        deletions = metadata.get("deletions")
        if not diff_text and output_str and self._looks_like_diff(output_str):
            diff_text = output_str
            output_str = "updated"
        log.add_tool_call(
            name,
            status,
            file_path,
            "",
            output_str,
            None,
            diff_text,
            None,
            additions if isinstance(additions, int) else None,
            deletions if isinstance(deletions, int) else None,
            metadata,
        )

    def _show_byok_thinking_line(self, text: str, log: ConversationLog):
        """Show thinking line for BYOK - handles threading correctly.

        The agent loop runs in an async context which might be in the same thread
        as the Textual app. This method safely handles both cases.
        """
        # Use call_from_thread, but catch the error if we're already in UI thread
        try:
            self._call_ui(self._show_thinking_line, text, log)
        except RuntimeError as e:
            # If we get "must run in a different thread" error, we're already in UI thread
            # Call directly
            if "different thread" in str(e).lower():
                self._show_thinking_line(text, log)
            else:
                # Re-raise other errors
                raise

    def _handle_byok_provider_selection(self, selection: str, log: ConversationLog):
        """Handle provider selection from :connect picker."""
        # Only process if we're actually awaiting provider selection
        if not getattr(self, "_awaiting_byok_provider", False):
            return False

        # Check for _byok_connect_list (from :connect command)
        if hasattr(self, "_byok_connect_list") and self._byok_connect_list:
            selection = selection.strip()
            provider_id = None
            provider_def = None

            # Try numeric selection first
            try:
                idx = int(selection) - 1
                if 0 <= idx < len(self._byok_connect_list):
                    provider_id, provider_def = self._byok_connect_list[idx]
            except ValueError:
                # Not a number - try to match by provider name/ID
                selection_lower = selection.lower()
                for pid, pdef in self._byok_connect_list:
                    if selection_lower == pid.lower() or selection_lower in pdef.name.lower():
                        provider_id, provider_def = pid, pdef
                        break

            if provider_id:
                self._awaiting_byok_provider = False
                # CRITICAL: Clear _awaiting_byok_model to prevent any auto-connection
                # The model list must be shown first, and user must explicitly select a model
                self._awaiting_byok_model = False
                # CRITICAL: Store the selection that was used to select the provider
                # This prevents the same input from being processed as a model selection
                self._last_provider_selection = selection.strip()
                # CRITICAL: Prevent _show_provider_models from setting _awaiting_byok_model immediately
                # This prevents the same input from being processed as a model selection
                self._skip_set_awaiting_model = True
                # Reset model highlight index when entering a new provider
                self._byok_highlighted_model_index = 0
                # Always use numbered list (not picker) to ensure model list is shown
                # Disable picker mode to prevent any auto-selection issues
                self._show_provider_models(provider_id, log, use_picker=False)
                # The provider input event has already been consumed, so it is safe
                # to enable model navigation immediately. Delaying this made
                # arrow/Enter feel broken when users acted quickly after the list appeared.
                self._awaiting_byok_model = True
                self.set_timer(0.1, lambda: setattr(self, "_last_provider_selection", None))
                return True
            else:
                # Invalid selection
                log.add_error(f"Unknown provider: {selection}")
                log.add_info("Enter a number or provider name (e.g., 'openai', 'anthropic')")
                return True

        return False

    def _handle_local_provider_selection(self, selection: str, log: ConversationLog):
        """Handle local provider selection from :connect local picker."""
        # Check for _local_provider_list (from :connect local command)
        if hasattr(self, "_local_provider_list") and self._local_provider_list:
            try:
                # Strip whitespace and try to parse as number
                selection = selection.strip()
                idx = int(selection) - 1
                if 0 <= idx < len(self._local_provider_list):
                    provider_id, provider_def = self._local_provider_list[idx]
                    self._awaiting_local_provider = False
                    # Reset model highlight index when entering a new provider
                    self._local_highlighted_model_index = 0
                    # Show models for this local provider (async function)
                    self.run_worker(self._show_local_provider_models(provider_id, log))
                    return True
                else:
                    log.add_error(
                        f"Invalid selection. Enter a number between 1 and {len(self._local_provider_list)}"
                    )
                    return True  # Return True to prevent further processing
            except ValueError:
                # Not a number, might be a provider name - try to match
                selection_lower = selection.lower()
                for provider_id, provider_def in self._local_provider_list:
                    if (
                        selection_lower == provider_id.lower()
                        or selection_lower in provider_def.name.lower()
                    ):
                        self._awaiting_local_provider = False
                        # Reset model highlight index when entering a new provider
                        self._local_highlighted_model_index = 0
                        self.run_worker(self._show_local_provider_models(provider_id, log))
                        return True
                log.add_error(f"Unknown provider: {selection}")
                return True  # Return True to prevent further processing

        return False

    def _handle_local_model_selection(self, selection: str, log: ConversationLog):
        """Handle local model selection from :connect local picker."""
        if not hasattr(self, "_local_selected_provider"):
            return False

        provider_id = self._local_selected_provider
        model_list = getattr(self, "_local_model_list", [])

        model = None

        if selection.isdigit():
            # Number selection
            idx = int(selection)
            if model_list and 1 <= idx <= len(model_list):
                model = model_list[idx - 1]
            else:
                log.add_error(f"Invalid selection. Choose 1-{len(model_list)}")
                return True
        else:
            # Search by model name/ID
            selection_lower = selection.lower().strip()

            # Try exact match first
            for m in model_list:
                if selection_lower == m.lower():
                    model = m
                    break
                # Try partial match (contains)
                if selection_lower in m.lower():
                    if model is None:  # First match
                        model = m
                    else:
                        # Multiple matches - prefer shorter match
                        if len(m) < len(model):
                            model = m

            if not model:
                log.add_error(f"Model '{selection}' not found for {provider_id}")
                if model_list:
                    log.add_info(f"Available models: {', '.join(model_list[:5])}")
                    if len(model_list) > 5:
                        log.add_info(f"... and {len(model_list) - 5} more")
                return True

        self._awaiting_local_model = False
        self._connect_local_mode(provider_id, model, log)
        return True

    def _handle_acp_agent_selection(self, selection: str, log: ConversationLog) -> bool:
        """Handle ACP agent selection from numbered list."""
        # Check for _acp_agent_list (from :connect acp command)
        if hasattr(self, "_acp_agent_list") and self._acp_agent_list:
            try:
                idx = int(selection) - 1
                if 0 <= idx < len(self._acp_agent_list):
                    agent_id, agent_data = self._acp_agent_list[idx]
                    self._awaiting_acp_agent_selection = False

                    # Check if agent is installed
                    from superqode.commands.acp import check_agent_installed

                    is_installed = check_agent_installed(agent_data)

                    if is_installed:
                        # Connect to the agent
                        log.add_info(f"Connecting to {agent_data['name']}...")
                        self._connect_agent(agent_data["short_name"])
                        return True
                    else:
                        # Show install message
                        from superqode.agents.registry import get_agent_installation_info

                        install_info = get_agent_installation_info(agent_data)
                        install_cmd = install_info.get("command", "")

                        t = Text()
                        t.append(f"\n  ⚠️  ", style=THEME["warning"])
                        t.append(
                            f"{agent_data['name']} is not installed.\n\n",
                            style=f"bold {THEME['text']}",
                        )

                        if install_cmd:
                            t.append(f"  Install with:\n", style=THEME["muted"])
                            t.append(f"    ", style=THEME["dim"])
                            t.append(f"{install_cmd}\n", style=THEME["cyan"])
                            t.append(f"\n  Or use: ", style=THEME["dim"])
                            t.append(
                                f":acp install {agent_data['short_name']}\n", style=THEME["cyan"]
                            )
                        else:
                            t.append(
                                f"  Installation instructions not available.\n",
                                style=THEME["muted"],
                            )
                            t.append(f"  Try: ", style=THEME["dim"])
                            t.append(
                                f":acp install {agent_data['short_name']}\n", style=THEME["cyan"]
                            )

                        log.write(t)
                        return True
                else:
                    log.add_error(
                        f"Invalid selection. Choose a number between 1 and {len(self._acp_agent_list)}"
                    )
                    return True
            except ValueError:
                # Not a number, might be a command or agent name
                pass

        return False

    def _handle_byok_model_selection(self, selection: str, log: ConversationLog):
        """Handle model selection from :connect picker with search support."""
        if not hasattr(self, "_byok_selected_provider"):
            return False

        # CRITICAL: Only process model selection if we're actually awaiting it
        # and the model list has been displayed (not immediately after provider selection)
        if not getattr(self, "_awaiting_byok_model", False):
            return False

        # CRITICAL: Prevent the same input that selected the provider from being
        # processed as a model selection
        last_provider_selection = getattr(self, "_last_provider_selection", None)
        if last_provider_selection and selection.strip() == last_provider_selection:
            # This is the same input that selected the provider - ignore it
            return False

        provider_id = self._byok_selected_provider
        model_list = getattr(self, "_byok_model_list", [])
        searchable_model_list = getattr(self, "_byok_all_model_list", model_list)

        # CRITICAL: Ensure model list is populated before allowing selection
        if not model_list:
            return False

        model = None

        if selection.isdigit():
            # Number selection
            idx = int(selection)
            if model_list and 1 <= idx <= len(model_list):
                model = model_list[idx - 1]
            else:
                log.add_error(f"Invalid selection. Choose 1-{len(model_list)}")
                return True
        else:
            # Search by model name/ID
            selection_lower = selection.lower().strip()

            # CRITICAL: Prevent provider names from matching models
            # If the selection matches the provider name, don't auto-select
            if selection_lower == provider_id.lower() or selection_lower in provider_id.lower():
                log.add_error(
                    f"'{selection}' is the provider name. Please enter a model number (1-{len(model_list)}) or model name."
                )
                return True

            # Try exact match first
            for m in searchable_model_list:
                if selection_lower == m.lower():
                    model = m
                    break
                # Try partial match (contains)
                if selection_lower in m.lower():
                    if model is None:  # First match
                        model = m
                    else:
                        # Multiple matches - be more specific
                        if selection_lower in m.lower() and len(m) < len(model):
                            model = m  # Prefer shorter match

            if not model:
                log.add_error(f"Model '{selection}' not found for {provider_id}")
                log.add_info(f"Available models: {', '.join(searchable_model_list[:5])}")
                if len(searchable_model_list) > 5:
                    log.add_info(f"... and {len(searchable_model_list) - 5} more")
                return True

        self._awaiting_byok_model = False
        self._connect_byok_mode(provider_id, model, log)
        return True

    async def _refresh_catalog_then_connect_byok(
        self, provider: str, model: str, log: ConversationLog, resolved_role=None
    ) -> None:
        """Fetch a models.dev-only provider before retrying a direct connection."""
        try:
            from superqode.providers.models_dev import get_models_dev

            client = get_models_dev()
            await client.ensure_loaded()
            if client.get_provider(provider) is None:
                await client.refresh(force=True)
            self._apply_live_models(client)
        except Exception:
            pass
        self.call_later(
            lambda: self._connect_byok_mode(
                provider,
                model,
                log,
                resolved_role,
                _catalog_refresh_attempted=True,
            )
        )

    def _connect_byok_mode(
        self,
        provider: str,
        model: str,
        log: ConversationLog,
        resolved_role=None,
        *,
        _catalog_refresh_attempted: bool = False,
    ):
        """Connect to BYOK mode with specified provider/model.

        Args:
            provider: Provider ID (e.g., "ollama", "anthropic")
            model: Model name (e.g., "qwen3.6:35b-a3b", "claude-opus-4-8")
            log: Conversation log for output
            resolved_role: Optional ResolvedRole object for role-based connections
                          (used to inject job description into system prompt)
        """
        from superqode.providers.dynamic import resolve_provider_def

        provider = normalize_provider_id(provider)
        model = normalize_model_for_provider(provider, model)
        provider_def = resolve_provider_def(provider)
        if provider_def is None:
            if not _catalog_refresh_attempted:
                self.run_worker(
                    self._refresh_catalog_then_connect_byok(provider, model, log, resolved_role)
                )
                return
            log.add_error(
                f"Provider '{provider}' is not available from the current models.dev catalog."
            )
            return

        # Clear any existing ACP connection when switching to BYOK
        if hasattr(self, "_acp_client") and self._acp_client:
            # Disconnect ACP client if switching from ACP to BYOK
            try:
                if self._acp_loop_runner is not None:
                    self._acp_loop_runner.run(self._acp_client.stop())
                else:
                    asyncio.create_task(self._acp_client.stop())
            except Exception:
                pass
            self._acp_client = None
            self._acp_client_key = None

        # Clear session state
        session = get_session()
        if hasattr(session, "connected_agent"):
            session.connected_agent = None
        if hasattr(session, "acp_manager"):
            session.acp_manager = None
        from superqode.providers.registry import ProviderCategory
        from superqode.pure_mode import PureMode
        from superqode.agent.system_prompts import SystemPromptLevel
        from superqode.providers.usage import get_usage_tracker
        import os

        provider_name = provider_def.name if provider_def else provider.upper()

        # Show experimental warning for vLLM and SGLang
        if provider in ("vllm", "sglang"):
            t = Text()
            t.append(f"\n  ⚠️  ", style=THEME["warning"])
            t.append(f"Experimental Provider Warning\n\n", style=f"bold {THEME['warning']}")
            t.append(f"  {provider_name} support is ", style=THEME["text"])
            t.append(f"EXPERIMENTAL", style=f"bold {THEME['warning']}")
            t.append(f". Features may be unstable and behavior may change.\n", style=THEME["text"])
            t.append(f"  Please report any issues you encounter.\n\n", style=THEME["dim"])
            log.write(t)

        # Check API key before connecting (except for local providers)
        if (
            provider_def
            and provider_def.category != ProviderCategory.LOCAL
            and provider_def.env_vars
        ):
            has_key = False
            for env_var in provider_def.env_vars:
                if os.environ.get(env_var):
                    has_key = True
                    break

            if not has_key:
                t = Text()
                t.append(f"\n  ⚠️  ", style=THEME["warning"])
                t.append("API Key Required\n\n", style=f"bold {THEME['warning']}")
                t.append(f"  Provider: ", style=THEME["muted"])
                t.append(f"{provider_name}\n", style=THEME["text"])
                t.append(f"  Required: ", style=THEME["muted"])
                t.append(f"{' or '.join(provider_def.env_vars)}\n\n", style=THEME["yellow"])
                t.append(f"  Setup:\n", style=THEME["muted"])
                t.append(f"    1. Get API key from: ", style=THEME["dim"])
                if provider_def.docs_url:
                    t.append(f"{provider_def.docs_url}\n", style=THEME["cyan"])
                else:
                    t.append(f"{provider_name} website\n", style=THEME["cyan"])
                t.append(f"    2. Export key:\n", style=THEME["dim"])
                for env_var in provider_def.env_vars[:1]:  # Show first option
                    t.append(f"       export {env_var}='your-api-key'\n", style=THEME["cyan"])
                t.append(
                    f"    3. Add to ~/.zshrc or ~/.bashrc for persistence\n\n", style=THEME["dim"]
                )
                t.append(f"  Then run: ", style=THEME["muted"])
                t.append(f":connect {provider}/{model}\n", style=THEME["success"])
                log.write(t)
                return

        # Store previous provider for quick switching
        if hasattr(self, "current_provider") and self.current_provider:
            self._previous_provider = (self.current_provider, self.current_model)

        # For BYOK, we use the provider session infrastructure with STANDARD system prompt
        # (includes role context) instead of MINIMAL
        if not hasattr(self, "_pure_mode"):
            self._pure_mode = PureMode()

        # Set up callbacks
        # Note: BYOK runs in the same event loop as Textual, but callbacks are invoked from async code
        # Use call_later to ensure UI updates happen on the next event loop tick
        # (ACP uses call_from_thread() because it runs in a separate subprocess)
        def on_tool_call(name: str, args: dict):
            # Schedule UI update on the next event loop tick
            self.call_later(self._show_pure_tool_call, name, args, log)

        def on_tool_result(name: str, result):
            # Schedule UI update on the next event loop tick
            self.call_later(self._show_pure_tool_result, name, result, log)

        is_local_provider = bool(provider_def and provider_def.category == ProviderCategory.LOCAL)

        async def on_thinking_async(text: str):
            """Handle thinking logs from AgentLoop - honors the :thinking toggle.

            OFF  -> nothing. NORMAL -> loop bookkeeping folds into the live
            throbber ("Working… step N"); for local models the raw reasoning is
            kept quiet so the screen stays clean. VERBOSE -> show everything,
            so users can see exactly what a local/ACP/BYOK model is doing.
            """
            if not (text and text.strip()):
                return
            if not self.show_thinking_logs:
                return  # OFF
            loop_status = self._thinking_loop_status(text)
            if loop_status is not None and self.thinking_verbosity != "verbose":
                self.call_later(self._set_thinking_status, loop_status)
                return
            # Calm mode stays quiet beyond the throbber to avoid flooding; flip
            # to :thinking verbose (or Ctrl+T) to see the full reasoning.
            if self.thinking_verbosity != "verbose":
                self.call_later(self._set_thinking_status, "💭 Thinking…")
                self.call_later(self._maybe_show_thinking_hint, log)
                return
            # Schedule UI update on the next event loop tick
            # ACP uses call_from_thread() because it runs in a separate subprocess
            self.call_later(self._show_thinking_line, text, log)

        # Thinking is always wired now; the handler above gates by verbosity so
        # the :thinking / Ctrl+T toggle works for local, BYOK, and ACP alike.
        self._pure_mode.on_tool_call = on_tool_call
        self._pure_mode.on_tool_result = on_tool_result
        self._pure_mode.on_thinking = on_thinking_async
        self._install_pure_permission_bridge(self._pure_mode, log)

        # Use STANDARD for cloud providers, MINIMAL for local to avoid confusion
        from superqode.providers.registry import ProviderCategory
        from superqode.agent.system_prompts import get_job_description_prompt
        from superqode.config import find_config_file
        from pathlib import Path

        system_level = (
            SystemPromptLevel.STANDARD
            if provider == "ds4"
            or not (provider_def and provider_def.category == ProviderCategory.LOCAL)
            else SystemPromptLevel.MINIMAL
        )

        # Determine project root (where superqode.yaml is located)
        # For local models, restrict to project root to prevent filesystem traversal
        config_file = find_config_file()
        if config_file:
            project_root = config_file.parent.resolve()
        else:
            # If no config file found, use current directory
            project_root = Path.cwd().resolve()

        # For local providers, use project root as working directory
        # For cloud providers, use current directory (existing behavior)
        working_dir = (
            project_root
            if (provider_def and provider_def.category == ProviderCategory.LOCAL)
            else None
        )

        # Extract job description from resolved role if available
        job_description = None
        if resolved_role:
            base_job_description = getattr(resolved_role, "job_description", None) or ""
            if base_job_description:
                # Build job description prompt for the role
                job_description = get_job_description_prompt(
                    base_job_description, role_config=resolved_role
                )

        # Connect with job description and working directory for role-based connections
        self._pure_mode.connect(
            provider,
            model,
            system_level,
            working_directory=working_dir,
            job_description=job_description,
            role_config=resolved_role,
        )

        # Update state
        session = get_session()
        # Determine execution mode: "local" for local providers, "byok" for cloud
        is_local = provider_def and provider_def.category == ProviderCategory.LOCAL
        # Check if session already has execution_mode set (from role)
        if hasattr(session, "execution_mode") and session.execution_mode == "local":
            exec_mode = "local"
        elif is_local:
            exec_mode = "local"
        else:
            exec_mode = "byok"

        session.execution_mode = exec_mode

        self.current_mode = exec_mode
        self.current_agent = ""
        self.current_model = model
        self.current_provider = provider

        # Start usage tracking
        tracker = get_usage_tracker()
        tracker.set_provider(provider, model)

        # Save to persistent config
        self._save_byok_config(provider, model)

        # Update badge
        badge = self.query_one("#mode-badge", ModeBadge)
        badge.mode = exec_mode
        badge.agent = ""
        badge.model = model
        badge.provider = provider
        badge.execution_mode = exec_mode

        # Clear screen and show fresh workspace
        mode_label = "LOCAL" if exec_mode == "local" else "BYOK"
        self._clear_for_workspace(log, f"{mode_label} • {provider_name}")

        try:
            status_bar = self.query_one("#status-bar", ColorfulStatusBar)
            status_bar.update_byok_status(provider, model)
        except Exception:
            pass

        local_host = self._local_provider_host(provider) if is_local else ""
        self._show_connection_summary(
            log,
            mode=exec_mode,
            provider=provider,
            provider_name=provider_name,
            model=model,
            host=local_host,
        )

        if is_local:
            self.run_worker(self._test_local_connection(provider, model, log, quiet=True))
        else:
            log.add_info("Ready to chat! Type your message below.")

    def _local_provider_host(self, provider: str) -> str:
        import os

        if provider == "ollama":
            return os.getenv("OLLAMA_HOST", "http://localhost:11434")
        if provider == "ds4":
            return os.getenv("DS4_HOST", "http://127.0.0.1:8000/v1")
        if provider == "lmstudio":
            return os.getenv("LMSTUDIO_HOST", "http://localhost:1234/v1")
        if provider == "mlx":
            return os.getenv("MLX_HOST", "http://127.0.0.1:8080/v1")
        if provider == "vllm":
            return os.getenv("VLLM_HOST", "http://127.0.0.1:8000/v1")
        if provider == "sglang":
            return os.getenv("SGLANG_HOST", "http://127.0.0.1:30000/v1")
        if provider == "tgi":
            return os.getenv("TGI_HOST", "http://127.0.0.1:8080/v1")
        return ""

    def _show_connection_summary(
        self,
        log: ConversationLog,
        *,
        mode: str,
        provider: str,
        provider_name: str,
        model: str,
        host: str = "",
    ) -> None:
        t = Text()
        local = mode == "local"
        title = "Local Model Connected" if local else "Provider Connected"
        icon = "✓"
        color = THEME["success"]
        t.append(f"\n  {icon} ", style=f"bold {color}")
        t.append(f"{title}\n\n", style=f"bold {THEME['text']}")
        t.append("    Method   ", style=THEME["muted"])
        t.append("Local" if local else "BYOK", style=THEME["text"])
        t.append("\n")
        t.append("    Provider ", style=THEME["muted"])
        t.append(provider_name or provider, style=THEME["text"])
        t.append("\n")
        t.append("    Model    ", style=THEME["muted"])
        t.append(model, style=f"bold {THEME['cyan']}")
        t.append("\n")
        if host:
            t.append("    Host     ", style=THEME["muted"])
            t.append(host, style=THEME["dim"])
            t.append("\n")
        t.append("\n  Ready. Type a message to start.", style=THEME["muted"])
        if local:
            t.append(" Use ", style=THEME["muted"])
            t.append(":local test", style=THEME["cyan"])
            t.append(" for a manual smoke check.", style=THEME["muted"])

        log.write(
            Panel(
                t,
                title=f"[bold {THEME['cyan']}]Connection[/]",
                border_style=color,
                box=ROUNDED,
                padding=(1, 2),
            )
        )

    async def _test_local_connection(
        self,
        provider: str,
        model: str,
        log: ConversationLog,
        *,
        quiet: bool = False,
    ):
        """Test connection to a local provider."""
        try:
            from superqode.providers.registry import PROVIDERS, ProviderCategory
            import os

            provider_def = PROVIDERS.get(provider)
            is_local = provider_def and provider_def.category == ProviderCategory.LOCAL

            if not quiet:
                log.add_info(f"Testing: {provider}/{model}")

            if is_local:
                if provider == "ds4":
                    from superqode.providers.local.ds4 import DS4Client

                    ds4_host = os.getenv("DS4_HOST", "http://127.0.0.1:8000/v1")
                    if not quiet:
                        log.add_info(f"DS4 host: {ds4_host}")
                    client = DS4Client(host=ds4_host)
                    health = await client.get_status()
                    if health.available:
                        if not quiet:
                            log.add_success(f"✓ DS4 server ready at {ds4_host}")
                        # Warm the model so the first real prompt isn't the one
                        # paying the one-time cold load (~81GB paged from disk).
                        await self._warmup_ds4(client, model, log)
                    else:
                        log.add_warning(f"DS4 server not ready: {health.error or 'unavailable'}")
                elif provider == "ollama":
                    from superqode.providers.local.ollama import OllamaClient

                    ollama_host = os.getenv("OLLAMA_HOST", "http://localhost:11434")
                    if not quiet:
                        log.add_info(f"Ollama host: {ollama_host}")
                    health = await OllamaClient(host=ollama_host).get_status()
                    if health.available:
                        if not quiet:
                            log.add_success(f"✓ Ollama server ready at {ollama_host}")
                        await self._warmup_local_generation(provider, model, log)
                    else:
                        log.add_warning(f"Ollama server not ready: {health.error or 'unavailable'}")
                else:
                    if not quiet:
                        log.add_info(
                            "Local provider selected. First prompt will validate generation."
                        )
                    await self._warmup_local_generation(provider, model, log)
            else:
                from superqode.providers.gateway.litellm_gateway import LiteLLMGateway
                from superqode.providers.gateway.base import Message

                gateway = LiteLLMGateway()
                model_string = gateway.get_model_string(provider, model)
                log.add_info(f"Testing: {model_string}")

                # Cloud/BYOK providers can afford a tiny completion test. Local
                # providers avoid this path so we do not contend with the first
                # real user prompt on single-request local servers.
                test_messages = [Message(role="user", content="Say 'test'")]
                response = await gateway.chat_completion(
                    messages=test_messages,
                    model=model,
                    provider=provider,
                    max_tokens=10,
                )

                if response and response.content:
                    log.add_success(f"✓ Connected to {provider}/{model}")
                    log.add_info(f"Test response: {response.content[:50]}")
                else:
                    log.add_warning(f"Connected but no response content. Response: {response}")

            # Ensure focus returns to input after connection test
            # Use set_timer since we're in the app's event loop, not a separate thread
            self.set_timer(0.1, self._ensure_input_focus)

        except Exception as e:
            import traceback

            error_msg = str(e)
            error_type = type(e).__name__
            log.add_error(f"✗ Connection test failed ({error_type}): {error_msg}")

            # Show full traceback for debugging
            if hasattr(self, "show_thinking_logs") and self.show_thinking_logs:
                log.add_info(f"Traceback:\n{traceback.format_exc()}")

            # Show helpful hints based on provider
            if provider == "ollama":
                log.add_info("💡 Troubleshooting:")
                log.add_info("   1. Make sure Ollama is running: ollama serve")
                log.add_info(f"   2. Check if model exists: ollama list")
                log.add_info(f"   3. Pull the model if needed: ollama pull {model}")
                log.add_info(f"   4. Test manually: curl http://localhost:11434/api/tags")
                log.add_info(
                    f"   5. Check Ollama host: echo $OLLAMA_HOST (default: http://localhost:11434)"
                )
            elif provider == "lmstudio":
                log.add_info("💡 Troubleshooting:")
                log.add_info("   1. Open LM Studio application")
                log.add_info("   2. Load a model in LM Studio")
                log.add_info("   3. Start the local server (usually on port 1234)")
            elif provider == "ds4":
                log.add_info("💡 Troubleshooting:")
                log.add_info("   1. Start ds4-server")
                log.add_info("   2. Test manually: curl http://127.0.0.1:8000/v1/models")
                log.add_info("   3. Set DS4_HOST if using a different URL")
            elif provider in ("vllm", "sglang", "mlx", "tgi"):
                log.add_info(f"💡 Make sure {provider} server is running and accessible")
                log.add_info(f"   Check the base URL in environment or provider config")

            # Still allow connection attempt (user might fix the issue)
            self._clear_for_workspace(log, f"BYOK • {provider}")

            # Ensure focus returns to input even after error
            # Use set_timer since we're in the app's event loop, not a separate thread
            self.set_timer(0.1, self._ensure_input_focus)

    async def _warmup_local_generation(
        self,
        provider: str,
        model: str,
        log: ConversationLog,
    ) -> None:
        """Send a tiny local request so the first real prompt avoids cold start.

        This is best-effort and never fails the connection. Local servers often
        load weights, allocate KV cache, or JIT paths on the first generation;
        doing that visibly during connect makes the first user response feel
        much less broken.
        """
        import asyncio
        import os
        import time

        if os.getenv("SUPERQODE_LOCAL_WARMUP", "1").strip().lower() in (
            "0",
            "false",
            "no",
            "off",
        ):
            return
        if provider == "ds4":
            return

        from superqode.providers.gateway.base import Message
        from superqode.providers.gateway.litellm_gateway import LiteLLMGateway

        log.add_info("⏳ Warming local model with a tiny request...")
        gateway = LiteLLMGateway()
        started = time.monotonic()
        try:
            await asyncio.wait_for(
                gateway.chat_completion(
                    messages=[Message(role="user", content="Reply with exactly: ok")],
                    model=model,
                    provider=provider,
                    max_tokens=4,
                    temperature=0.0,
                ),
                timeout=float(os.getenv("SUPERQODE_LOCAL_WARMUP_TIMEOUT", "45")),
            )
        except asyncio.TimeoutError:
            log.add_warning(
                "Local warmup timed out; connected, but the first prompt may still be slow."
            )
            return
        except Exception as exc:  # noqa: BLE001
            log.add_warning(f"Local warmup skipped: {exc}")
            return

        elapsed = time.monotonic() - started
        log.add_success(f"✓ Local model warm — {elapsed:.1f}s")
        log.add_info("Ready to chat! Type your message below.")

    async def _warmup_ds4(self, client, model: str, log: ConversationLog) -> None:
        """Pre-load the DS4 model on connect, with a live elapsed-time indicator.

        DS4's first inference pays a large one-time cost paging the ~81GB model
        in from disk; doing it here (visibly) keeps the user's first prompt
        fast. Opt out with ``SUPERQODE_DS4_WARMUP=0``. Never fails the connect:
        a slow/failed warmup just leaves the model to load on first prompt.
        """
        import asyncio
        import os
        import time

        if os.getenv("SUPERQODE_DS4_WARMUP", "1").strip().lower() in ("0", "false", "no", "off"):
            return

        log.add_info("⏳ Loading model into memory (first start can be slow on a cold cache)…")
        task = asyncio.ensure_future(client.warmup(model))
        start = time.monotonic()
        next_tick = 10.0
        while not task.done():
            await asyncio.sleep(0.5)
            elapsed = time.monotonic() - start
            if elapsed >= next_tick:
                log.add_info(f"   …still loading the model ({int(elapsed)}s)")
                next_tick += 10.0

        result = await task
        if result.get("ok"):
            log.add_success(f"✓ DS4 ready (warm) — {result.get('elapsed', 0.0):.0f}s")
            log.add_info("Ready to chat! Type your message below.")
        else:
            # Don't block usage — the model will simply load on the first prompt.
            log.add_warning(
                "DS4 warmup did not complete "
                f"({result.get('error') or 'unknown error'}); the first prompt may be slow."
            )

    # =========================================================================
    # BYOK ENHANCED COMMANDS
    # =========================================================================

    def _connect_byok_cmd(self, args: str, log: ConversationLog):
        """Handle :connect byok command - Interactive provider/model picker."""
        args = args.strip()

        # If no args provided, show the provider picker
        # This is the main entry point for :connect byok
        if not args:
            # Clear any existing state that might interfere
            self._awaiting_byok_model = False
            self._awaiting_byok_provider = False
            if hasattr(self, "_byok_selected_provider"):
                delattr(self, "_byok_selected_provider")
            if hasattr(self, "_byok_model_list"):
                delattr(self, "_byok_model_list")
            # Show the provider list
            self._show_connect_picker(log)
            return

        # :connect - (switch to previous)
        if args == "-":
            self._connect_previous(log)
            return

        # :connect ! (show history)
        if args == "!":
            self._connect_history(log)
            return

        # :connect last (reconnect to last used)
        if args == "last":
            self._connect_last(log)
            return

        # :connect <provider>[/<model>] (direct connect with / separator)
        if args:
            # Prevent "byok", "acp", "local" from being treated as provider names
            # These are subcommands, not providers
            if args.lower().strip() in ("byok", "acp", "local"):
                # This shouldn't happen if parsing is correct, but be defensive
                self._show_connect_picker(log)
                return

            parsed = split_provider_model_ref(args)
            if parsed.provider and parsed.model:
                self._connect_byok_mode(parsed.provider, parsed.model, log)
                return

            # Support provider/model syntax
            if "/" in args:
                parts = args.split("/", 1)
                provider = parts[0].strip()
                model = parts[1].strip() if len(parts) > 1 else None
                if provider and model:
                    self._connect_byok_mode(provider, model, log)
                    return

            # Support space-separated syntax
            parts = args.split(maxsplit=1)
            provider = parts[0].strip()
            model = parts[1].strip() if len(parts) > 1 else None

            # Double-check provider is not a subcommand
            if provider.lower() in ("byok", "acp", "local"):
                self._show_connect_picker(log)
                return

            if model:
                # Direct connect with provider and model
                self._connect_byok_mode(provider, model, log)
            else:
                # Show models for this provider - always use numbered list
                self._show_provider_models(provider, log, use_picker=False)
            return

    def _connect_local_cmd(self, args: str, log: ConversationLog):
        """Handle :connect local command - Interactive local provider/model picker."""
        args = args.strip()

        # :connect local - (switch to previous)
        if args == "-":
            self._connect_previous(log)
            return

        # :connect local ! (show history)
        if args == "!":
            self._connect_history(log)
            return

        # :connect local last (reconnect to last used)
        if args == "last":
            self._connect_last(log)
            return

        # :connect local <provider>[/<model>] (direct connect with / separator)
        if args:
            # Support provider/model syntax
            if "/" in args:
                parts = args.split("/", 1)
                provider = parts[0].strip()
                model = parts[1].strip() if len(parts) > 1 else None
                if provider and model:
                    self._connect_local_mode(provider, model, log)
                    return

            # Support space-separated syntax
            parts = args.split(maxsplit=1)
            provider = parts[0]
            model = parts[1] if len(parts) > 1 else None

            if model:
                # Direct connect with provider and model
                self._connect_local_mode(provider, model, log)
            else:
                # Show models for this local provider
                self.run_worker(self._show_local_provider_models(provider, log))
            return

        # :connect local (show interactive local provider picker)
        # CRITICAL: Clear any existing state to ensure we show provider picker, not models
        self._awaiting_local_provider = False
        self._awaiting_local_model = False
        if hasattr(self, "_local_selected_provider"):
            delattr(self, "_local_selected_provider")
        if hasattr(self, "_local_provider_list"):
            delattr(self, "_local_provider_list")
        if hasattr(self, "_local_model_list"):
            delattr(self, "_local_model_list")
        if hasattr(self, "_local_highlighted_provider_index"):
            self._local_highlighted_provider_index = 0
        if hasattr(self, "_local_highlighted_model_index"):
            self._local_highlighted_model_index = 0

        # Now show the provider picker
        self._show_local_provider_picker(log)

    def _connect_previous(self, log: ConversationLog):
        """Switch to previous provider/model."""
        if hasattr(self, "_previous_provider") and self._previous_provider:
            provider, model = self._previous_provider
            self._connect_byok_mode(provider, model, log)
        else:
            log.add_info("No previous provider to switch to")
            log.add_system("Use :connect to select a provider")

    def _connect_history(self, log: ConversationLog):
        """Show connection history."""
        history = self._load_byok_history()

        if not history:
            log.add_info("No connection history yet")
            log.add_system("Use :connect to connect to a provider")
            return

        t = Text()
        t.append(f"\n  ◈ ", style=f"bold {THEME['purple']}")
        t.append("Connection History\n\n", style=f"bold {THEME['text']}")

        for i, entry in enumerate(history[:10], 1):
            provider, model = entry.split("/", 1) if "/" in entry else (entry, "")
            t.append(f"  [{i}] ", style=THEME["dim"])
            t.append(f"{provider}", style=f"bold {THEME['success']}")
            if model:
                t.append(f"/{model}", style=THEME["muted"])
            t.append("\n", style="")

        t.append(f"\n  💡 ", style=THEME["muted"])
        t.append(":connect <number>", style=THEME["success"])
        t.append(" to reconnect\n", style=THEME["muted"])

        log.write(t)

    def _connect_last(self, log: ConversationLog):
        """Connect to the last used provider/model."""
        config = self._load_byok_config()

        if config.get("last_provider") and config.get("last_model"):
            self._connect_byok_mode(config["last_provider"], config["last_model"], log)
        else:
            log.add_info("No previous connection saved")
            log.add_system("Use :connect to select a provider")

    def _connect_local_mode(self, provider: str, model: str, log: ConversationLog):
        """Connect to LOCAL mode with specified provider/model.

        This is a wrapper around _connect_byok_mode() that ensures
        local providers are properly identified. Local providers are
        already handled in _connect_byok_mode() via ProviderCategory.LOCAL.
        """
        # HuggingFace cached models need a local runtime (e.g., MLX/TGI), not HF Inference API
        if provider == "huggingface-local":
            model_lower = model.lower()
            if "mlx" in model_lower or model_lower.startswith("mlx-community/"):
                log.add_info("Routing cached MLX model to MLX local provider.")
                provider = "mlx"
            else:
                log.add_error(
                    "HuggingFace cached models require a local runtime (mlx/tgi/vllm/sglang)."
                )
                log.add_info("Use: :connect local <provider> <model>")
                return

        # MLX and llama.cpp serve exactly one model per process and are NOT
        # always-on background apps like Ollama or LM Studio. Connecting alone
        # would point at a dead endpoint, so if their server is not already up
        # ask before launching a managed server. Note the provider id
        # "llamacpp" maps to the server-manager engine "llama.cpp".
        engine_for_provider = {"mlx": "mlx", "llamacpp": "llama.cpp"}
        if provider in engine_for_provider and model:
            engine = engine_for_provider[provider]
            try:
                from superqode.local.servers import get_manager

                running = bool(get_manager().status(engine).get("running"))
            except Exception:
                running = False
            if not running:
                self._prompt_local_connect_start(provider, engine, model, log)
                return

        # Local providers use the same connection mechanism as BYOK
        # but are identified by ProviderCategory.LOCAL
        self._connect_byok_mode(provider, model, log)

    @staticmethod
    def _local_serve_command(engine: str, model: str) -> str:
        import shlex

        return f":local serve {engine} --model {shlex.quote(model)}"

    @staticmethod
    def _native_local_server_command(
        engine: str,
        *,
        model: str = "",
        host: str | None = None,
        port: int | None = None,
        ctx: int | None = None,
    ) -> str:
        """Native command users can run outside SuperQode."""
        import shlex
        import sys

        from superqode.local.servers import (
            DS4_DEFAULT_CTX,
            DS4_DEFAULT_KV_DIR,
            DS4_DEFAULT_KV_DISK_MB,
            SPECS,
        )

        spec = SPECS[engine]
        host = host or spec.default_host
        port = port or spec.default_port
        q = shlex.quote

        if engine == "ollama":
            env = [f"OLLAMA_HOST={host}:{port}"]
            if ctx:
                env.append(f"OLLAMA_CONTEXT_LENGTH={ctx}")
            return " ".join([*env, "ollama", "serve"])

        if engine == "lmstudio":
            cmd = ["lms", "server", "start", "-p", str(port)]
            if host not in ("127.0.0.1", "localhost"):
                cmd += ["--bind", host]
            return shlex.join(cmd)

        if engine == "mlx":
            cmd = [
                sys.executable,
                "-m",
                "mlx_lm",
                "server",
                "--model",
                model or "<model-id>",
                "--host",
                host,
                "--port",
                str(port),
            ]
            return shlex.join(cmd)

        if engine == "ds4":
            cmd = [
                "ds4-server",
                "--host",
                host,
                "--port",
                str(port),
                "--ctx",
                str(ctx or DS4_DEFAULT_CTX),
                "--kv-disk-dir",
                str(DS4_DEFAULT_KV_DIR),
                "--kv-disk-space-mb",
                str(DS4_DEFAULT_KV_DISK_MB),
            ]
            return shlex.join(cmd)

        if engine == "llama.cpp":
            cmd = [
                "llama-server",
                "-m",
                model or "/path/to/model.gguf",
                "--host",
                host,
                "--port",
                str(port),
            ]
            if ctx:
                cmd += ["-c", str(ctx)]
            return shlex.join(cmd)

        return q(f":local serve {engine}")

    def _prompt_local_connect_start(
        self, provider: str, engine: str, model: str, log: ConversationLog
    ) -> None:
        """Ask before starting a one-model local server during connect."""
        from pathlib import Path as _Path

        label = _Path(model).name if engine == "llama.cpp" else model
        command = self._local_serve_command(engine, model)
        native_command = self._native_local_server_command(engine, model=model)
        self._awaiting_local_connect_start = {
            "provider": provider,
            "engine": engine,
            "model": model,
            "command": command,
            "native_command": native_command,
        }
        self._awaiting_local_model = False

        t = Text()
        t.append("\n  🟡 ", style=THEME["warning"])
        t.append(f"{engine} is not running", style=f"bold {THEME['text']}")
        t.append(f" for {label}\n", style=THEME["cyan"])
        t.append(
            "  Recommended: start the server yourself with the native command:\n",
            style=THEME["muted"],
        )
        t.append("      ", style="")
        t.append(native_command, style=THEME["cyan"])
        t.append("\n", style="")
        t.append(
            "      Edit the model, port, or context if your setup needs it.\n", style=THEME["dim"]
        )
        t.append("      SuperQode managed fallback: ", style=THEME["muted"])
        t.append(command, style=THEME["cyan"])
        t.append("\n", style="")
        t.append("  SuperQode can also help by starting a managed server.\n", style=THEME["muted"])
        t.append("  Managed start runs in the background, writes logs under ", style=THEME["muted"])
        t.append("~/.superqode/servers/", style=THEME["cyan"])
        t.append(", and can be stopped with ", style=THEME["muted"])
        t.append(f":local stop {engine}", style=THEME["success"])
        t.append(".\n", style=THEME["muted"])
        t.append("\n  Press ", style=THEME["muted"])
        t.append("Enter", style=f"bold {THEME['success']}")
        t.append(" if you want SuperQode to start it for you, ", style=THEME["muted"])
        t.append("'n'", style=THEME["warning"])
        t.append(" to skip, or type ", style=THEME["muted"])
        t.append("manual", style=THEME["cyan"])
        t.append(" to show the command again.\n", style=THEME["muted"])
        if engine == "mlx":
            t.append(
                "  MLX will not download missing Hugging Face weights unless you explicitly use --allow-download.\n",
                style=THEME["dim"],
            )
        log.write(t)
        self._pin_local_prompt_to_input(
            f"Start {engine} yourself, or press Enter for SuperQode managed start",
            log,
            notify=f"{engine} is stopped. Start it yourself, or press Enter for help.",
        )

    def _handle_local_connect_start_input(self, text: str, log: ConversationLog) -> bool:
        pending = getattr(self, "_awaiting_local_connect_start", None)
        if not pending:
            return False

        choice = text.strip().lower()
        command = pending["command"]
        engine = pending["engine"]
        provider = pending["provider"]
        model = pending["model"]

        if choice in ("n", "no", "skip", "cancel", "q"):
            self._awaiting_local_connect_start = None
            self._reset_input_placeholder()
            t = Text()
            t.append("\n  ⏭  ", style=THEME["warning"])
            t.append(f"Left {engine} stopped.", style=f"bold {THEME['text']}")
            t.append(" Start it later with: ", style=THEME["muted"])
            t.append(f"{command}\n", style=THEME["cyan"])
            log.write(t)
            self._show_local_provider_picker(log, clear_log=False)
            return True

        if choice in ("manual", "command", "cmd"):
            self._awaiting_local_connect_start = None
            self._reset_input_placeholder()
            native_command = pending.get("native_command", command)
            log.add_system(f"Native command: {native_command}")
            log.add_system(f"SuperQode managed fallback: {command}")
            self._show_local_provider_picker(log, clear_log=False)
            return True

        if choice not in ("", "y", "yes", "start", "ok"):
            log.add_error(
                "Start it yourself with the shown command, press Enter for SuperQode help, "
                "type 'manual' to repeat the command, or 'n' to skip."
            )
            self._pin_local_prompt_to_input(
                f"Start {engine} yourself, or press Enter for SuperQode managed start",
                log,
            )
            return True

        self._awaiting_local_connect_start = None
        self._reset_input_placeholder()
        self.run_worker(self._start_local_then_connect(provider, engine, model, log))
        return True

    async def _start_local_then_connect(
        self, provider: str, engine: str, model: str, log: ConversationLog
    ):
        """Launch a one-model local server (MLX/llama.cpp), then connect to it.

        ``model`` is an HF id for MLX or a ``.gguf`` path for llama.cpp. After
        the server is up it serves the model under a short id (the GGUF
        basename for llama.cpp), which is what we connect with.
        """
        import asyncio
        from pathlib import Path as _Path

        from superqode.local.servers import ServerError, get_manager

        label = _Path(model).name if engine == "llama.cpp" else model
        t0 = Text()
        t0.append("\n  ⏳ ", style=THEME["warning"])
        t0.append(f"Starting {engine} server", style=f"bold {THEME['text']}")
        t0.append(f" with {label}", style=THEME["cyan"])
        t0.append(
            " — loading the model into memory, this can take a minute...\n", style=THEME["muted"]
        )
        self._call_ui(log.write, t0)

        self.is_busy = True
        try:
            # Large models load slowly; give the server room before the
            # readiness probe gives up. Cached files only, so no download.
            handle = await asyncio.to_thread(
                get_manager().start, engine, model=model, timeout=300.0
            )
        except ServerError as exc:
            self._call_ui(log.add_error, str(exc))
            self._call_ui(
                log.add_system,
                f"Start it manually with: superqode local serve {engine} --model {model}",
            )
            return
        except Exception as exc:  # noqa: BLE001
            self._call_ui(log.add_error, f"Failed to start {engine}: {exc}")
            return
        finally:
            self.is_busy = False

        t = Text()
        verb = "Adopted running" if getattr(handle, "adopted", False) else "Started"
        t.append("  ● ", style=f"bold {THEME['success']}")
        t.append(f"{verb} {engine}", style=f"bold {THEME['text']}")
        t.append(f"  {handle.base_url}\n", style=THEME["cyan"])
        self._call_ui(log.write, t)

        # llama-server serves the GGUF under its basename; MLX serves the HF id.
        connect_model = _Path(model).name if engine == "llama.cpp" else model
        self._call_ui(self._connect_byok_mode, provider, connect_model, log)

    def _show_local_provider_picker(self, log: ConversationLog, clear_log: bool = True):
        """Show interactive local provider picker with discovery.

        Args:
            log: The conversation log widget
            clear_log: If True, clear the log before writing (default: True).
                      Set to False when updating during navigation to reduce flickering.
        """
        # CRITICAL: Force complete state reset - we MUST show provider picker, not models
        # Clear ALL local-related state to prevent any auto-selection
        self._awaiting_local_provider = True
        self._awaiting_local_model = False  # MUST be False - we're selecting provider, not model
        # Clear any BYOK selection state so numeric input routes to local picker
        self._awaiting_byok_provider = False
        self._awaiting_byok_model = False
        self._just_showed_byok_picker = False

        # Delete local selection state (but keep _local_provider_list - we'll set it later)
        for attr in ["_local_selected_provider", "_local_model_list", "_local_cached_models"]:
            if hasattr(self, attr):
                delattr(self, attr)

        # Reset indices only on a fresh show. Navigation redraws pass
        # clear_log=False and must preserve the highlighted provider, otherwise
        # arrow keys move the index and it's immediately reset back to 0 here.
        if clear_log:
            self._local_highlighted_provider_index = 0
            if hasattr(self, "_local_highlighted_model_index"):
                self._local_highlighted_model_index = 0

        from superqode.providers.registry import PROVIDERS, ProviderCategory, get_local_providers
        from superqode.providers.local.discovery import get_discovery_service
        import asyncio

        # Get local providers from registry FIRST
        local_providers = get_local_providers()

        # Filter out unsupported providers from TUI display
        # (they remain in registry for backward compatibility)
        unsupported_local_providers = {"ollama-cloud"}
        local_providers = {
            pid: pdef
            for pid, pdef in local_providers.items()
            if pid not in unsupported_local_providers
        }

        # huggingface-local removed: downloaded HF weights aren't directly
        # runnable — they need a runtime (Ollama/mlx_lm.server/vLLM/TGI) to
        # serve them. Use `superqode models download` then connect to that
        # runtime. (Filtered above via the registry no longer listing it.)

        t = Text()
        t.append(f"  ◈ ", style=f"bold {THEME['purple']}")
        t.append("Local Providers\n", style=f"bold {THEME['text']}")
        t.append(
            "  Select a local/self-hosted runtime. No API key required.\n\n", style=THEME["muted"]
        )
        t.append("  Local Model Lab\n", style=f"bold {THEME['text']}")
        t.append("  Start with ", style=THEME["muted"])
        t.append(":chat on", style=f"bold {THEME['cyan']}")
        t.append(
            " to sanity-check a Local/BYOK model with no repo context or tools.\n",
            style=THEME["muted"],
        )
        t.append("  Switch to ", style=THEME["muted"])
        t.append(":build", style=f"bold {THEME['cyan']}")
        t.append(" when you want the repo-aware coding harness and tools.\n", style=THEME["muted"])
        t.append("  Use ", style=THEME["muted"])
        t.append(":plan on", style=f"bold {THEME['cyan']}")
        t.append(
            " to reason first before any edits or native tool execution.\n", style=THEME["muted"]
        )
        t.append("  Toggle modes anytime with ", style=THEME["muted"])
        t.append(":mode", style=f"bold {THEME['cyan']}")
        t.append(" (Chat / Build / Plan).\n", style=THEME["muted"])
        t.append("  Explore: ", style=THEME["dim"])
        t.append(":local doctor", style=THEME["cyan"])
        t.append(" · ", style=THEME["dim"])
        t.append(":local setup", style=THEME["cyan"])
        t.append(" · ", style=THEME["dim"])
        t.append(":local build", style=THEME["cyan"])
        t.append(" · ", style=THEME["dim"])
        t.append(":local optimize", style=THEME["cyan"])
        t.append(" · ", style=THEME["dim"])
        t.append(":local labs", style=THEME["cyan"])
        t.append("\n\n", style="")

        if not local_providers:
            t.append("  ⚠️  No local providers configured\n", style=THEME["warning"])
            t.append(
                "  Local providers include: ds4, ollama, lmstudio, mlx, vllm, etc.\n",
                style=THEME["dim"],
            )
            if clear_log:
                log.clear()
            log.write(t)
            return

        # Sort providers: prioritize main local coding flows first.
        priority_order = ["ds4", "ollama", "mlx", "lmstudio", "vllm", "sglang"]

        def sort_key(item):
            provider_id, _ = item
            if provider_id in priority_order:
                return (0, priority_order.index(provider_id))
            return (1, provider_id)

        # Show local providers with highlighting
        highlighted_idx = getattr(self, "_local_highlighted_provider_index", 0)
        local_providers_list = sorted(local_providers.items(), key=sort_key)

        # Debug: Ensure all providers are included
        if not local_providers_list:
            t.append("  ⚠️  No local providers found in registry\n", style=THEME["warning"])
            if clear_log:
                log.clear()
            log.write(t)
            return

        provider_count = len(local_providers_list)
        t.append(f"  Available ({provider_count})\n", style=f"bold {THEME['text']}")

        # Provider-specific emojis
        provider_emojis = {
            "ds4": "◆",
            "ollama": "🐼",  # Panda
            "lmstudio": "🎨",  # Paint palette (GUI application)
            "mlx": "🍏",  # Green Apple (Apple Silicon)
            "vllm": "🚀",  # Rocket (high performance)
            "sglang": "🪝",  # Hook
            "tgi": "📚",  # Books
            "huggingface": "🤗",  # HuggingFace signature emoji
            "openai-compatible": "🔌",  # Plug (generic connection)
        }

        for idx, (provider_id, provider_def) in enumerate(local_providers_list, 1):
            status_icon = provider_emojis.get(provider_id, "🟢")
            labels = ["local"]
            if provider_id == "ds4":
                labels.extend(["recommended", "tools", "1M ctx"])
            elif provider_id in ("ollama", "mlx", "lmstudio"):
                labels.extend(["popular", "tools"])
            elif provider_id in ("vllm", "sglang", "tgi"):
                labels.extend(["server", "advanced"])

            is_highlighted = (idx - 1) == highlighted_idx
            marker = "▶ " if is_highlighted else "  "
            name_style = f"bold {THEME['success']}" if is_highlighted else f"bold {THEME['cyan']}"
            num_style = (
                self._picker_link_style(f"bold {THEME['success']}", idx)
                if is_highlighted
                else self._picker_link_style(THEME["dim"], idx)
            )
            t.append(f"  {marker}", style=f"bold {THEME['success']}")
            t.append(f"[{idx}] ", style=num_style)
            t.append(f"{status_icon} ", style=THEME["success"])
            t.append(f"{provider_def.name}", style=name_style)
            if provider_id in ("vllm", "sglang"):
                t.append(" [EXPERIMENTAL]", style=f"bold {THEME['warning']}")
            t.append(f" ({provider_id})", style=THEME["muted"])
            t.append("  ", style=THEME["dim"])
            t.append(" • ".join(labels), style=THEME["dim"])
            t.append("\n", style="")

        t.append("\n  Type a number or use ", style=THEME["muted"])
        t.append("↑↓ Enter", style=f"bold {THEME['cyan']}")
        t.append(". Direct connect: ", style=THEME["muted"])
        t.append(f":connect local <provider>/<model>\n", style=THEME["cyan"])
        t.append(f"  Example: ", style=THEME["dim"])
        t.append(f":connect local ds4/deepseek-v4-flash\n", style=THEME["cyan"])

        if clear_log:
            log.clear()
            log.auto_scroll = False
            log.write(t)
            log.scroll_home(animate=False)
            log.auto_scroll = True  # set synchronously; avoids per-keystroke scroll-jump flicker
        else:
            # Update during navigation - clear and write but preserve scroll position better
            # by not calling scroll_home which resets to top
            log.auto_scroll = False
            log.clear()
            log.write(t)
            # Don't scroll to home on navigation updates to reduce flickering
            # The scroll will be adjusted by _scroll_to_highlighted_item if needed
            log.auto_scroll = True  # set synchronously; avoids per-keystroke scroll-jump flicker

        # Set up selection handler for local providers
        # CRITICAL: Always set these flags to ensure provider picker is shown, NOT model selection
        # This MUST happen AFTER we write to log, to prevent any race conditions
        self._awaiting_local_provider = True
        self._awaiting_local_model = False  # Make sure we're NOT in model selection mode
        self._local_provider_list = local_providers_list  # Use sorted list
        # Preserve current highlight if already set, otherwise start with first
        if not hasattr(self, "_local_highlighted_provider_index"):
            self._local_highlighted_provider_index = 0
        # CRITICAL: Ensure NO provider is selected - we must show the picker
        if hasattr(self, "_local_selected_provider"):
            delattr(self, "_local_selected_provider")
        if hasattr(self, "_local_model_list"):
            delattr(self, "_local_model_list")
        if hasattr(self, "_local_cached_models"):
            delattr(self, "_local_cached_models")

        # CRITICAL: Set flag to prevent auto-selection when picker first appears
        # This prevents empty input from immediately selecting the first provider
        self._just_showed_local_picker = True
        # Clear the flag after a delay to allow normal selection
        self.set_timer(0.5, lambda: setattr(self, "_just_showed_local_picker", False))

        # Ensure input stays focused for keyboard navigation
        self.set_timer(0.05, self._ensure_input_focus)

    def _show_connect_type_picker(self, log: ConversationLog, clear_log: bool = True):
        """Show picker to choose between ACP, BYOK, and LOCAL connection types.

        Args:
            log: The conversation log widget
            clear_log: If True, clear the log before writing (default: True).
                      Set to False when updating during navigation to reduce flickering.
        """
        # Clear any BYOK state to prevent interference
        self._awaiting_byok_provider = False
        self._awaiting_byok_model = False
        if hasattr(self, "_byok_selected_provider"):
            delattr(self, "_byok_selected_provider")
