    def _set_byok_model(self, model: str, log: ConversationLog):
        """Switch model without reconnecting."""
        session = get_session()
        if session.execution_mode not in ("byok", "local") or not hasattr(self, "_pure_mode"):
            log.add_error("Not connected to BYOK provider")
            return

        provider = getattr(self._pure_mode, "_provider", None)
        if not provider:
            log.add_error("No provider selected")
            return

        # Reconnect with new model
        self._connect_byok_mode(provider, model, log)

    def _usage_cmd(self, args: str, log: ConversationLog):
        """Handle :usage command - Show token/cost usage."""
        from superqode.providers.usage import get_usage_tracker

        tracker = get_usage_tracker()
        args = args.strip()

        if args == "reset":
            tracker.reset()
            log.add_success("Usage stats reset")
            return

        summary = tracker.get_summary()

        t = Text()
        t.append(f"\n  ◈ ", style=f"bold {THEME['purple']}")
        t.append("Session Usage\n\n", style=f"bold {THEME['text']}")

        if not summary["connected"]:
            t.append("  Not connected to any provider\n", style=THEME["muted"])
            t.append(f"\n  💡 ", style=THEME["muted"])
            t.append(":connect", style=THEME["success"])
            t.append(" to select a provider\n", style=THEME["muted"])
            log.write(t)
            return

        # Provider/Model
        t.append(f"  Provider: ", style=THEME["muted"])
        t.append(f"{summary['provider']}", style=f"bold {THEME['success']}")
        t.append(f" / ", style=THEME["dim"])
        t.append(f"{summary['model']}\n\n", style=THEME["cyan"])

        # Token counts
        t.append(f"  Total Tokens:  ", style=THEME["muted"])
        total = summary["tokens"]
        if total >= 1000:
            t.append(f"{total / 1000:.1f}K", style=f"bold {THEME['text']}")
        else:
            t.append(f"{total}", style=f"bold {THEME['text']}")
        t.append("\n", style="")

        t.append(f"  ├─ Input:      ", style=THEME["dim"])
        input_tokens = summary.get("input_tokens", 0)
        if input_tokens >= 1000:
            t.append(f"{input_tokens / 1000:.1f}K\n", style=THEME["text"])
        else:
            t.append(f"{input_tokens}\n", style=THEME["text"])

        t.append(f"  └─ Output:     ", style=THEME["dim"])
        output_tokens = summary.get("output_tokens", 0)
        if output_tokens >= 1000:
            t.append(f"{output_tokens / 1000:.1f}K\n\n", style=THEME["text"])
        else:
            t.append(f"{output_tokens}\n\n", style=THEME["text"])

        # Cost
        cost = summary["cost"]
        t.append(f"  Estimated Cost: ", style=THEME["muted"])
        if cost > 0:
            t.append(f"${cost:.4f}\n", style=f"bold {THEME['gold']}")
        else:
            t.append("Free\n", style=f"bold {THEME['success']}")

        # Messages
        t.append(f"\n  Messages:      ", style=THEME["muted"])
        t.append(f"{summary['messages']}\n", style=THEME["text"])

        t.append(f"  Tool Calls:    ", style=THEME["muted"])
        t.append(f"{summary['tools']}\n", style=THEME["text"])

        t.append(f"\n  💡 ", style=THEME["muted"])
        t.append(":usage reset", style=THEME["success"])
        t.append(" to reset stats\n", style=THEME["muted"])

        log.write(t)

    def _load_byok_config(self) -> dict:
        """Load BYOK config from file."""
        import json
        from pathlib import Path

        config_path = Path.home() / ".superqode" / "config.json"
        try:
            if config_path.exists():
                data = json.loads(config_path.read_text())
                return data.get("byok", {})
        except Exception:
            pass
        return {}

    def _save_byok_config(self, provider: str, model: str):
        """Save BYOK config to file."""
        import json
        from pathlib import Path

        config_path = Path.home() / ".superqode" / "config.json"
        try:
            config_path.parent.mkdir(parents=True, exist_ok=True)

            # Load existing config
            data = {}
            if config_path.exists():
                data = json.loads(config_path.read_text())

            # Update BYOK section
            if "byok" not in data:
                data["byok"] = {}

            data["byok"]["last_provider"] = provider
            data["byok"]["last_model"] = model

            # Update history
            history = data["byok"].get("history", [])
            entry = f"{provider}/{model}"
            if entry in history:
                history.remove(entry)
            history.insert(0, entry)
            data["byok"]["history"] = history[:20]  # Keep last 20

            config_path.write_text(json.dumps(data, indent=2))
        except Exception:
            pass

    def _load_byok_history(self) -> list:
        """Load BYOK connection history."""
        config = self._load_byok_config()
        return config.get("history", [])

    def _health_cmd(self, args: str, log: ConversationLog):
        """Handle :health command - Check provider connectivity."""
        self.run_worker(self._check_provider_health(log))

    async def _check_provider_health(self, log: ConversationLog):
        """Check provider health asynchronously."""
        from superqode.providers.health import get_health_checker, ProviderStatus

        log.add_info("Checking provider health...")

        checker = get_health_checker()
        results = await checker.check_all(force=True)

        t = Text()
        t.append(f"\n  ◈ ", style=f"bold {THEME['purple']}")
        t.append("Provider Health Status\n\n", style=f"bold {THEME['text']}")

        # Group by status
        ready = []
        not_configured = []
        errors = []

        for pid, result in sorted(results.items()):
            if result.status == ProviderStatus.READY:
                ready.append((pid, result))
            elif result.status == ProviderStatus.NOT_CONFIGURED:
                not_configured.append((pid, result))
            else:
                errors.append((pid, result))

        # Ready providers
        if ready:
            t.append(f"  ✓ Ready ({len(ready)})\n", style=f"bold {THEME['success']}")
            for pid, result in ready:
                t.append(f"    {result.status_icon} ", style=THEME["success"])
                t.append(f"{pid}", style=THEME["text"])
                if result.model_available:
                    t.append(f"  {result.model_available}", style=THEME["muted"])
                t.append("\n", style="")
            t.append("\n", style="")

        # Not configured
        if not_configured:
            t.append(f"  ○ Not Configured ({len(not_configured)})\n", style=f"{THEME['dim']}")
            for pid, result in not_configured[:5]:  # Show first 5
                t.append(f"    {result.status_icon} ", style=THEME["dim"])
                t.append(f"{pid}", style=THEME["muted"])
                t.append(f"  {result.message}\n", style=THEME["dim"])
            if len(not_configured) > 5:
                t.append(f"    ... and {len(not_configured) - 5} more\n", style=THEME["dim"])
            t.append("\n", style="")

        # Errors
        if errors:
            t.append(f"  ✗ Errors ({len(errors)})\n", style=f"bold {THEME['error']}")
            for pid, result in errors:
                t.append(f"    {result.status_icon} ", style=THEME["error"])
                t.append(f"{pid}", style=THEME["text"])
                t.append(f"  {result.message}\n", style=THEME["dim"])
            t.append("\n", style="")

        t.append(f"  💡 ", style=THEME["muted"])
        t.append(":connect <provider>", style=THEME["success"])
        t.append(" to connect to a ready provider\n", style=THEME["muted"])

        self._call_ui(log.write, t)

    # ========================================================================
    # Local Provider Commands
    # ========================================================================

    def _local_cmd(self, args: str, log: ConversationLog):
        """Handle :local command - Manage local LLM providers."""
        args = args.strip()
        parts = args.split(maxsplit=1)
        sub = parts[0].lower() if parts else ""
        subargs = parts[1] if len(parts) > 1 else ""

        if sub == "" or sub == "status":
            # :local - Show all local providers status
            self.run_worker(self._local_status(log))
        elif sub == "scan":
            # :local scan - Scan for running providers
            self.run_worker(self._local_scan(log))
        elif sub == "models":
            # :local models - List all local models
            self.run_worker(self._local_models(log))
        elif sub == "init":
            self.run_worker(self._local_init(subargs, log))
        elif sub == "setup":
            self.run_worker(self._local_setup(subargs, log))
        elif sub == "smoke":
            self.run_worker(self._local_smoke(subargs, log))
        elif sub == "labs":
            self.run_worker(self._local_labs(subargs, log))
        elif sub == "optimize":
            try:
                tokens = shlex.split(subargs or "")
            except ValueError as exc:
                log.add_error(f"Could not parse :local optimize arguments: {exc}")
                return
            self.run_worker(
                self._superqode_cli_cmd(["local", "optimize", *tokens], log, "Local optimization")
            )
        elif sub == "airplane":
            try:
                tokens = shlex.split(subargs or "")
            except ValueError as exc:
                log.add_error(f"Could not parse :local airplane arguments: {exc}")
                return
            if not tokens:
                log.add_info(
                    "Usage: :local airplane <doctor|prepare|index|smoke|models|health> [options]"
                )
                log.add_system(
                    "e.g. :local airplane prepare --repo . --model ollama/qwen3:8b --force"
                )
                return
            self.run_worker(
                self._superqode_cli_cmd(
                    ["local", "airplane", *tokens],
                    log,
                    "Airplane Mode",
                )
            )
        elif sub == "build":
            self.run_worker(self._local_build(subargs, log))
        elif sub == "migrate":
            self.run_worker(self._local_migrate(subargs, log))
        elif sub == "pack":
            parts2 = subargs.split(maxsplit=1)
            if parts2 and parts2[0].lower() == "init":
                self.run_worker(self._local_pack_init(parts2[1] if len(parts2) > 1 else "", log))
            else:
                log.add_info("Usage: :local pack init [name] [--model MODEL] [--dry-run]")
        elif sub == "search":
            if subargs.strip():
                self.run_worker(self._local_search(subargs.strip(), log))
            else:
                log.add_info("Usage: :local search <query>   (e.g. :local search qwen3-coder)")
        elif sub == "warm":
            self.run_worker(self._local_warm(subargs, log))
        elif sub == "test":
            # :local test <model> - Test tool calling
            if subargs:
                self.run_worker(self._local_test(subargs, log))
            else:
                log.add_info("Usage: :local test <model>")
        elif sub == "info":
            # :local info <model> - Show model info
            if subargs:
                self.run_worker(self._local_info(subargs, log))
            else:
                log.add_info("Usage: :local info <model>")
        elif sub == "recommend":
            # :local recommend - Show recommended coding models
            self._local_recommend(log)
        elif sub == "serve":
            # :local serve <engine> [--model X] [--port N] [--ctx N]
            if subargs:
                self.run_worker(self._local_serve(subargs, log))
            else:
                log.add_info(
                    "Usage: :local serve <ollama|lmstudio|mlx|ds4|llama.cpp> [--model X] [--port N] [--ctx N] [--host H]"
                )
                log.add_system(
                    "e.g. :local serve mlx --model mlx-community/Qwen3-Coder-30B-A3B-Instruct-4bit --port 8090"
                )
                log.add_system(
                    "e.g. :local serve ds4 --ctx 32768   ·   long DS4: --ctx 100000   ·   Think Max: --ctx 393216"
                )
        elif sub == "servers":
            # :local servers - Show managed/running server status
            self.run_worker(self._local_servers(log))
        elif sub == "stop":
            # :local stop <engine> - Stop a server SuperQode started
            if subargs:
                self.run_worker(self._local_stop(subargs.strip(), log))
            else:
                log.add_info("Usage: :local stop <ollama|lmstudio|mlx|ds4|llama.cpp>")
        else:
            try:
                tokens = shlex.split(args or "")
            except ValueError as exc:
                log.add_error(f"Could not parse :local arguments: {exc}")
                return
            self._run_cli_passthrough(["local", *tokens], log, "Local command")

    @staticmethod
    def _parse_local_kv_args(subargs: str) -> dict:
        import shlex

        opts: dict = {"_pos": []}
        for tok in shlex.split(subargs or ""):
            if tok.startswith("--repo="):
                opts["repo"] = tok.split("=", 1)[1]
            elif tok == "--repo":
                opts["_expect"] = "repo"
            elif tok.startswith("--output="):
                opts["output"] = tok.split("=", 1)[1]
            elif tok == "--output":
                opts["_expect"] = "output"
            elif tok.startswith("--engine="):
                opts["engine"] = tok.split("=", 1)[1]
            elif tok == "--engine":
                opts["_expect"] = "engine"
            elif tok.startswith("--model="):
                opts["model"] = tok.split("=", 1)[1]
            elif tok == "--model":
                opts["_expect"] = "model"
            elif tok.startswith("--endpoint="):
                opts["endpoint"] = tok.split("=", 1)[1]
            elif tok == "--endpoint":
                opts["_expect"] = "endpoint"
            elif tok.startswith("--pack="):
                opts["pack"] = tok.split("=", 1)[1]
            elif tok == "--pack":
                opts["_expect"] = "pack"
            elif tok.startswith("--from-smoke="):
                opts["from_smoke"] = tok.split("=", 1)[1]
            elif tok == "--from-smoke":
                opts["_expect"] = "from_smoke"
            elif tok in ("--skip-smoke", "--no-smoke"):
                opts["skip_smoke"] = True
            elif tok in ("--yes", "-y"):
                opts["yes"] = True
            elif tok == "--dry-run":
                opts["dry_run"] = True
            elif tok == "--force":
                opts["force"] = True
            elif tok == "--write-pack":
                opts["write_pack"] = True
            elif tok == "--json":
                opts["json"] = True
            elif opts.get("_expect"):
                opts[opts.pop("_expect")] = tok
            else:
                opts["_pos"].append(tok)
        opts.pop("_expect", None)
        return opts

    async def _local_init(self, subargs: str, log: ConversationLog):
        """Run the MVP local setup path from the TUI."""
        import asyncio

        from superqode.local.doctor import generate_harness_yaml, render_report, run_doctor
        from superqode.local.smoke import render_smoke, run_smoke

        try:
            opts = self._parse_local_kv_args(subargs)
        except ValueError as exc:
            log.add_error(f"Could not parse :local init arguments: {exc}")
            return

        repo = Path(opts.get("repo") or ".")
        output = Path(opts.get("output") or "superqode.local.yaml")
        if output.exists() and not opts.get("yes"):
            log.add_error(f"{output} already exists. Use :local init --yes to overwrite.")
            return

        t0 = Text()
        t0.append("\n  ◈ ", style=f"bold {THEME['purple']}")
        t0.append("Local Coding Init\n\n", style=f"bold {THEME['text']}")
        t0.append(
            "  Detecting hardware, engines, trusted model routes, and repo shape...\n",
            style=THEME["muted"],
        )
        log.write(t0)

        self.is_busy = True
        try:
            report = await asyncio.to_thread(run_doctor, str(repo), include_guardrails=True)
            smoke = None
            if not opts.get("skip_smoke"):
                best = report.recommendation.best_model
                chosen_engine = opts.get("engine") or report.recommendation.engine or ""
                chosen_model = opts.get("model") or ""
                if not chosen_model and best is not None:
                    chosen_model = (
                        best.downloaded.bare_id if best.downloaded else best.pull.split()[-1]
                    )
                smoke = await asyncio.to_thread(
                    run_smoke,
                    engine=chosen_engine,
                    model=chosen_model,
                    repo_path=repo,
                )
            harness = generate_harness_yaml(
                report,
                name="local-coder",
                pack_override=opts.get("pack", ""),
            )
            await asyncio.to_thread(output.write_text, harness, encoding="utf-8")
        except Exception as exc:  # noqa: BLE001
            log.add_error(f"Local init failed: {exc}")
            return
        finally:
            self.is_busy = False

        t = Text()
        t.append("\n  ◈ ", style=f"bold {THEME['purple']}")
        t.append("Local Coding Init\n\n", style=f"bold {THEME['text']}")
        for line in render_report(report).splitlines():
            t.append(
                f"  {line}\n",
                style=f"bold {THEME['text']}"
                if line in {"Verdict", "Engines", "Recommended models"}
                or line.startswith("SuperQode")
                else THEME["text"],
            )
        if smoke is not None:
            t.append("\n")
            for line in render_smoke(smoke).splitlines():
                t.append(f"  {line}\n", style=THEME["text"])
        t.append("\n  Wrote local harness: ", style=THEME["muted"])
        t.append(f"{output}\n", style=f"bold {THEME['success']}")
        if opts.get("pack"):
            t.append("  Model pack: ", style=THEME["muted"])
            t.append(f"{opts['pack']}\n", style=f"bold {THEME['cyan']}")
        t.append("  Start coding with: ", style=THEME["muted"])
        t.append(f"superqode --harness {output}\n", style=THEME["cyan"])
        self._show_command_output(log, t)

